    public function update_user_inactive_in_ghl()
    {   
        $this->loadModel('SpaLiveV1.SysUsers');
        $Ghl = new GhlController();

        $uid = get('uid', '');
        if($uid == '') {
            $this->message('Invalid user identifier.');
            return;
        }

        $user = $this->SysUsers->find()->where(['SysUsers.uid' => $uid])->first();
        
        if (!empty($user)){
            $array_data = array(
                'email' => $user['email'],
                'name' => $user['name'],
                'lname' => $user['lname'],
                'phone' => $user['phone'],
                'costo' => 0,
                'course' => 'Inactive'
            );

            if(!env('IS_DEV', false))
            {   //print_r('seguimos --'); 
                $Ghl->updateOpportunity($array_data);
            }
        }        
    }

    public function analytics(){
        $this->loadModel('SpaLiveV1.DataAnalytics');
        $google_id = get('google_id', '');

        if(empty($google_id)){
            $this->message('Empty google id');
            return;
        }

        $ent = $this->DataAnalytics->find()->where(['DataAnalytics.google_id' => $google_id])->first();

        if(empty($ent)){
            $array_save = [
                'google_id' => $google_id,
                'phone' => '',
                'register_reserve' => 0,
                'register_discount' => 0,
                'register_pay_later' => 0,
                'use_qr' => 0,
                'use_button_android' => 0,
                'use_button_ios' => 0,
                'created' => date('Y-m-d H:i:s'),
                'deleted' => 0
            ];
            $c_entity = $this->DataAnalytics->newEntity($array_save);
            $this->DataAnalytics->save($c_entity);
            $this->success();
        }else{
            $this->message('Client already exists');
            $this->success();
        }
    }

    public function send_notification_from_admin(){
        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->notify_devices('WEIGHT_LOSS_CONFIRM_DELIVERY',array(get('user_id', 0)),true,true,true,array(),'',array(),true);
        $this->success();
    }

    public function send_notification_application(){
        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        if(get('status', '') == 'REJECTED'){
            $this->notify_devices('REJECT_APPLICATION_OS',array(get('user_id', 0)),true,true,true,array(),'',array(),true);
        }else if(get('status', '') == 'DONE'){
            $this->notify_devices('APPROVED_APPLICATION_OS',array(get('user_id', 0)),true,true,true,array(),'',array(),true);
        }

        $this->success();
    }

