    private function validateSubscriptionPayment() {
        $str_now = "2022-10-31";
        $str_subscription_date = "2021-07-31";
        $str_last_payment_date = "2022-09-30";
        $subscription_status = 'ACTIVE'; //HOLD

        $date_formatter = new \DateTime("-1 month");
        $monthago = $date_formatter->format("Y-m-d");
        
        $forcepay = false;

        $currentDate = date('Y-m-d', strtotime($str_now));
        $currentDateDay = date('d', strtotime($str_now));
        $currentMonthLastDate = date('Y-m-t', strtotime($str_now));
        $isTodayLastDay = $currentDate == $currentMonthLastDate ? true : false;

        $subscriptionDate = date('Y-m-d', strtotime($str_subscription_date));
        $subscriptionDateDay = date('d', strtotime($str_subscription_date));
        $subscriptionLastDate = date('Y-m-t', strtotime($str_subscription_date));
        $isSubscriptionLastDay = $subscriptionDate == $subscriptionLastDate ? true : false;

        if (!empty($str_last_payment_date)) {    
            $lastPaymentDate = date('Y-m-d', strtotime($str_last_payment_date));
            $lastPaymentDateDay = date('d', strtotime($str_last_payment_date));
            $lastPaymentLastDate = date('Y-m-t', strtotime($str_last_payment_date));
            $isPaymentLastDay = $lastPaymentDate == $lastPaymentLastDate ? true : false;
        }

        if (empty($str_last_payment_date)) {
            $diff_days = strtotime($str_now) - strtotime($str_subscription_date); 
        } else {
            $diff_days = strtotime($str_now) - strtotime($str_last_payment_date); 
        }

        $diff_days = $diff_days / 60 / 60 / 24;
        echo 'diff days: ' . $diff_days . '<br>';
        if ($subscription_status == 'ACTIVE') {
            if (!empty($str_last_payment_date)) {   
                if ($lastPaymentDateDay == $subscriptionDateDay || ($isPaymentLastDay && $subscriptionDateDay > $lastPaymentDateDay)) {
                    if ($isTodayLastDay && ($subscriptionDateDay > $currentDateDay) && $diff_days >= 28) return true;
                    if ($subscriptionDateDay == $currentDateDay && $diff_days >= 28) return true;
                } else {
                    if ($isTodayLastDay && ($lastPaymentDateDay > $currentDateDay) && $diff_days >= 28) return true;
                    if ($lastPaymentDateDay == $currentDateDay && $diff_days >= 28) return true;
                }
            } else {
                if ($isTodayLastDay && ($subscriptionDateDay > $currentDateDay) && $diff_days >= 28) return true;
                if ($subscriptionDateDay == $currentDateDay && $diff_days >= 28) return true;
            }
        }
        if ($subscription_status == 'HOLD') {
            if ($diff_days >= 28) return true;
        }

        return false;

    }

    public function get_subscription_receipt() {
        
        $panel = get('l3n4p', '');
        if((empty($panel) || $panel != '609248af7ce858.91s69218')){
            $this->message('Invalid token.');
            return;
        }
        $uid = get('uid','');
        if (empty($uid)) {
            $this->message('Invalid payment identifier.');
            return;
        }


        $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
        $sp = $this->DataSubscriptionPayments->find()->select(['User.name','User.lname','User.street','User.city','User.zip','User.suite','State.abv','DataSubscription.subscription_type','DataSubscriptionPayments.total','DataSubscriptionPayments.subscription_id','DataSubscriptionPayments.created'])->join([
            'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'DataSubscriptionPayments.user_id = User.id'],
            'DataSubscription' => ['table' => 'data_subscriptions', 'type' => 'INNER', 'conditions' => 'DataSubscription.id = DataSubscriptionPayments.subscription_id'],
            'State' => ['table' => 'cat_states', 'type' => 'INNER', 'conditions' => 'DataSubscriptionPayments.user_id = User.id'],
        ])->where(['DataSubscriptionPayments.uid' => $uid, '(DATE_FORMAT(DataSubscriptionPayments.created, "%Y%m%d12") = "' . get('created','') . '")' ])->first();

        if (empty($sp)) {
            return;
        }
        
        $address = $sp['User']['street'].(isset($sp['User']['suite']) && !empty($sp['User']['suite']) ? ', '.$sp['User']['suite'] : '') .', '.$sp['User']['city'].', '.$sp['State']['abv'].' '.$sp['User']['zip'];

        
        $this->rcpt_subscriptions($sp['DataSubscription']['subscription_type'],$sp->total,$address,$sp['User']['name'] . ' ' . $sp['User']['lname'],$sp->subscription_id,$sp->created->i18nFormat('MM/dd/yyyy hh:mm a'));
        exit;

    }

