    public function refund_subscription_payment() {

        $panel = get('l3n4p', '');
        $token = get('token',"");

        if(!empty($token) && $panel == '6092482f7ce858.911692182323'){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $id_sp = get('id', ''); 
        $unsubscribe = get('unsubscribe', 0);
        try {
            $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
            $sp = $this->DataSubscriptionPayments->find()
                  ->where(['DataSubscriptionPayments.id' => $id_sp])->first();
            $amount = $sp->total;      
            $chargeIntent = $sp->charge_id;
            $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key')); 
            
            $refundCi = $stripe->charges->retrieve(
                $chargeIntent,
                []
            );        
            $re = \Stripe\Refund::create([
                'amount' => $amount,
                'payment_intent' => $refundCi->payment_intent,
            ]);
    
            if ($re) {
                if ($re->status == 'succeeded'){                        
                    $sp->status = 'REFUNDED';
                    $this->DataSubscriptionPayments->save($sp);

                    if ($unsubscribe == 1 ){
                        $this->loadModel('SpaLiveV1.DataSubscriptions');
                        $s = $this->DataSubscriptions->find()
                        ->where(['DataSubscriptions.id' => $sp->subscription_id])->first();
                        $s->status = 'CANCELLED';
                        $this->DataSubscriptions->save($s);
                    }
                    $this->success();
                }
            }
        } catch (\Stripe\Exception\InvalidRequestException $th) {
            $this->success(false);
            $this->set('mesagges', $th->getMessage());
            //echo $th;
        }        
    }

    public function refund_subscription_payment_service() {

        $panel = get('l3n4p', '');
        $token = get('token',"");
        
        if(!empty($token) && $panel == '6092482f7ce858.911692182323'){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $id_sp = get('id', ''); 
        $unsubscribe = get('unsubscribe', 0);
        $service_type = get('service_type', 0);
        $service_name = get('service_name', 0);

        try {
            $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
            $this->loadModel('SpaLiveV1.DataSubscriptionPaymentsRefunds');
            $sp = $this->DataSubscriptionPayments->find()
                  ->where(['DataSubscriptionPayments.id' => $id_sp])->first();

            if (empty($sp)) {
                $this->message('Invalid subscriptiojn.');
                return;
            }

            $spr = $this->DataSubscriptionPaymentsRefunds->find()
                  ->where(['DataSubscriptionPaymentsRefunds.subscription_paymet_id' => $id_sp, 'DataSubscriptionPaymentsRefunds.service' =>  $service_name,'DataSubscriptionPaymentsRefunds.deleted' => 0])->first();

            if (!empty($spr)) {
                $this->message('Service already refunded.');
                return;
            }

            $detail_data = json_decode($sp->payment_details,true);

            if (!isset($detail_data[$service_name]) || intval($detail_data[$service_name]) == 0) {
                $this->message('Error refunding service.');
                return;
            }

            $amnt = intval($detail_data[$service_name]);

            $amount = $sp->total;      
            $chargeIntent = $sp->charge_id;
            $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key')); 
            
            $refundCi = $stripe->charges->retrieve(
                $chargeIntent,
                []
            );        
            $re = \Stripe\Refund::create([
                'amount' => $amnt,
                'payment_intent' => $refundCi->payment_intent,
            ]);
    
            if ($re) {
                if ($re->status == 'succeeded'){                        

                    $array_save = array(
                        'subscription_paymet_id' => $id_sp,
                        'amount' => $amnt,
                        'service' => $service_name,
                        'deleted' => 0,
                        'created' => date('Y-m-d H:i:s'),
                    );

                    $c_entity = $this->DataSubscriptionPaymentsRefunds->newEntity($array_save);
                    if(!$c_entity->hasErrors()) {
                        $this->DataSubscriptionPaymentsRefunds->save($c_entity); 
                    } 

                    if ($unsubscribe == 1 ){
                        $this->loadModel('SpaLiveV1.DataSubscriptions');
                        $s = $this->DataSubscriptions->find()
                        ->where(['DataSubscriptions.id' => $sp->subscription_id])->first();

                        $_detail_data = json_decode($s->payment_details,true);

                        if (isset($_detail_data[$service_name])) {
                            
                            if ($s->main_service == $service_name)  {
                                if (empty($s->addons_services)) {
                                    $s->status = 'CANCELLED';
                                } else {
                                    $add_s = $s->addons_services;

                                    $addons_arr = explode(",", $add_s);
                                    $__bk = $addons_arr[0];

                                    array_shift($addons_arr);
                                    $add_s = implode(",", $addons_arr);

                                    $s->addons_services = $add_s;
                                    $s->main_service = $__bk;

                                    $unsub_total = intval($_detail_data[$__bk]);

                                    $s->total = $s->total - $unsub_total;

                                    $_detail_data[$__bk] = $_detail_data[$service_name];
                                }
                            } else {
                                $add_s = $s->addons_services;

                                $_narr = explode(",", $add_s);
                                $_narr = array_filter($_narr, function($p) use ($service_name) {
                                    return $p !== $service_name;
                                });

                                $add_s = implode(",", $_narr);

                                $s->addons_services = $add_s;

                                $unsub_total = intval($_detail_data[$service_name]);
                                $s->total = $s->total - $unsub_total;

                            }
                            
                            if(count($_detail_data) > 0){
                                unset($_detail_data[$service_name]);
                            }
                            $s->payment_details = json_encode($_detail_data);
                            $save =$this->DataSubscriptions->save($s);
                        }
                        
                    }

                    $this->success();
                }
            }
        } catch (\Stripe\Exception\InvalidRequestException $th) {
            $this->success(false);
            $this->set('mesagges', $th->getMessage());
            //echo $th;
        }        
    }

