    public function bulk_notification_patient() {
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        
        $type = get('type','');
        $body = get('body','');
        $is_sms = get('is_sms',0);
        $is_email = get('is_email',0);
        $now = date('Y-m-d H:i:s');
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataModelPatient');
        $users_array = array();
        $ent_user = array();
        $email_string = "";
        $email_array = array();

        $ent_user = $this->DataModelPatient->find()->where(['DataModelPatient.deleted' => 0, 'DataModelPatient.email !=' => ''])->all();

        foreach ($ent_user as $row) {
            $users_array[] = $row['id'];
        }

        if ($is_sms == 1) {
            foreach($ent_user as $ele) {

                $phone = preg_replace('/\D+/', '', $ele->phone);
                if(strlen($phone) == 11){
                    $phone = substr($phone, 1);
                    $phone_number = '+1' . $phone;

                    try {           
                        $sid    = env('TWILIO_ACCOUNT_SID'); 
                        $token  = env('TWILIO_AUTH_TOKEN'); 
                        $twilio = new Client($sid, $token); 
                            
                        $message = $twilio->messages 
                                    ->create($phone_number, // to 
                                            array(  
                                                "messagingServiceSid" => "MG65978a5932f4ba9dd465e05d7b22195e",      
                                                "body" => $body 
                                            ) 
                                    );
                        } catch (TwilioException $e) {
                        }
                    pr($phone_number);
                } else if(strlen($phone) == 10){
                    $phone_number = '+1' . $phone;

                    try {           
                        $sid    = env('TWILIO_ACCOUNT_SID'); 
                        $token  = env('TWILIO_AUTH_TOKEN'); 
                        $twilio = new Client($sid, $token); 
                            
                        $message = $twilio->messages 
                                    ->create($phone_number, // to 
                                            array(  
                                                "messagingServiceSid" => "MG65978a5932f4ba9dd465e05d7b22195e",      
                                                "body" => $body 
                                            ) 
                                    );
                        } catch (TwilioException $e) {
                        }
                }
            }
        }

    }

    public function bulk_notification_training() {

        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        
        $type = get('type','');
        $body = get('body','');
        $is_sms = get('is_sms',0);
        $is_email = get('is_email',0);
        $training_id = get('training_id',0);
        $now = date('Y-m-d H:i:s');
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataModelPatient');
        $users_array = array();
        $ent_user = array();
        $email_string = "";
        $email_array = array();

        $ent_user = $this->SysUsers->find()->join([
            'DataTrainings' => ['table' => 'data_trainings', 'type' => 'INNER', 'conditions' => 'DataTrainings.user_id = SysUsers.id'],
            'CatTrainings' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainings.id = DataTrainings.training_id'],
            ])
        ->where(['CatTrainings.id' => $training_id, 'DataTrainings.deleted ' => 0, 'SysUsers.deleted' => 0])->all();
        
        foreach ($ent_user as $row) {
            $users_array[] = $row['id'];
        }

        if ($is_email == 1) {

            if(empty($email_string)){
                $str_str_users = implode(",",$users_array);
            
                $str_query = "
                    SELECT 
                        GROUP_CONCAT(SU.email) emails
                    FROM sys_users SU
                    WHERE SU.deleted = 0 AND SU.id > 1 AND SU.active = 1 AND SU.steps NOT IN ('CODEVERIFICATION','STATENOTAVAILABLE','HOWITWORKS','TRACERS','DENIED','WAITINGSCHOOLAPPROVAL') AND FIND_IN_SET(SU.id,'{$str_str_users}')";
    
                $ent_query = $this->SysUsers->getConnection()->execute($str_query)->fetchAll('assoc');
                
                if (!empty($ent_query)) {
                    $email_string = $ent_query[0]['emails'];
                }
            }

            $data = array(
                'from'    => 'MySpaLive <info@mg.myspalive.com>',
                'to'    => 'MySpaLive <info@mg.myspalive.com>',
                'bcc'      => $email_string,
                'subject' => "New message from MySpaLive",
                'html'    => $this->getEmailFormat($body),
            );

            $mailgunKey = $this->getMailgunKey();

            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);

            $result = curl_exec($curl);
            curl_close($curl);

            $this->loadModel('SpaLiveV1.CatTrainings');

            $ent_training = $this->CatTrainings->find()->where(['CatTrainings.id' => $training_id, 'CatTrainings.deleted ' => 0])->first();
            if(!empty($ent_training)){
                $ent_training->email_sent_date = date("Y-m-d H:i:s");
                $this->CatTrainings->save($ent_training);
            }

        } else if ($is_sms == 1) {
            $this->notify_devices($body,$users_array,false,false,false,array(),'',array(),true);
            $this->loadModel('SpaLiveV1.CatTrainings');
            $ent_training = $this->CatTrainings->find()->where(['CatTrainings.id' => $training_id, 'CatTrainings.deleted ' => 0])->first();
            if(!empty($ent_training)){
                $ent_training->sms_sent_date = date("Y-m-d H:i:s");
                $this->CatTrainings->save($ent_training);
            }
        }
    }

