     public function payCIComissionsOnPurchase($purchase_uid = "") {
            
        $this->loadModel('SpaLiveV1.DataPurchases');
        $this->loadModel('SpaLiveV1.DataPayment');

        if(empty($purchase_uid)){
            $this->message('purchase_uid empty.');
            return;
        }
        
        $ent_purchase = $this->DataPurchases->find()->select(['DataPurchases.uid','DataPurchases.id', 'DataPurchases.payment_intent','DataPurchases.user_id'])
        ->where(['DataPurchases.uid' => $purchase_uid,'DataPurchases.deleted' => 0])->first();
        if (empty($ent_purchase)) return;

        $ent_pay = $this->DataPayment->find()
        ->where(['DataPayment.uid' => $ent_purchase->uid, 'DataPayment.intent' => $ent_purchase->payment_intent, 'DataPayment.comission_generated' => 0,'DataPayment.is_visible' => 1, 'DataPayment.type' => 'PURCHASE'])->first();
    
        if (empty($ent_pay)) return;

        $ent_pay->comission_generated = 1;
        $this->DataPayment->save($ent_pay); 

        //*************************** pyramid

        $int_user_id = $ent_pay->id_from;

        $this->loadModel('SpaLiveV1.DataNetwork');
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataPurchases');
        $this->loadModel('SpaLiveV1.DataTreatment');

        $_where = ['DataNetwork.user_id' => $int_user_id];
        $ent_network = $this->DataNetwork->find()->where($_where)->first();
        
        $result = array();

        if (!empty($ent_network)) {

            $n_parent_id = $ent_network->parent_id;

            $m_count = 1;
            $should_continue = true;

            do {    
                
                $ent_cycle = $this->DataNetwork->find()->select(['DataNetwork.parent_id','User.id','User.short_uid','User.name','User.lname','User.email','User.type','User.state'])
                ->join([
                    'User' => ['table' => 'sys_users', 'type' => 'LEFT', 'conditions' => 'User.id = DataNetwork.user_id']
                ])
                ->where(['DataNetwork.user_id' => $n_parent_id, 'User.deleted' => 0, 'User.login_status' => 'READY'])->first();

                if (!empty($ent_cycle)) {

                    //$now = date('Y-m-d H:i:s');

                    /*

                    $__fields = ['DataTreatment.id', 'DataTreatment.created'];
                    $__fields['last_treatment'] = "(DATEDIFF('{$now}', DataTreatment.schedule_date))";


                    $__where = ['DataTreatment.deleted' => 0];
                    
                    $__where['DataTreatment.status'] = "DONE";
                    $__where['DataTreatment.payment <>'] = "";
                    $__where['User.id'] = $ci_user_id;
                    
                    $ent_ci_treatment = $this->DataTreatment->find()->select($__fields)
                    ->join([
                        'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTreatment.assistance_id'],
                    ])
                    ->where($__where)->last();

                    */

                    // CHECK PURCHASES

                    /*
                    $_fields = ['DataPurchases.id', 'DataPurchases.created'];
                    $_fields['last_purchase'] = "(DATEDIFF('{$now}', DataPurchases.created))";
                    $ent_ci_purchase = $this->DataPurchases->find()->select($_fields)
                    ->where(['DataPurchases.user_id' => $ci_user_id, 'DataPurchases.payment <>' => ''])->last();

                    */

                    


                    // if (!empty($ent_ci_purchase) && !empty($ent_ci_treatment)) {

                        // if (!empty($ci_user_ent)) {
                        // if ($ent_ci_purchase['last_purchase'] < 60 && $ent_ci_treatment['last_treatment'] < 60 && !empty($ci_user_ent) && !$pending_subscriptions) {


                    if (!empty($ent_cycle)) {

                            $result[] = array(
                                'level' => $m_count,
                                'user_id' => $ent_cycle['User']['id'],
                                'email' => $ent_cycle['User']['email'],
                                'type' => $ent_cycle['User']['type'],
                                'state' => $ent_cycle['User']['state'],
                            );

                            $m_count++;

                    }

                    
                    // }

                    
                    if ($m_count > 3) {
                        $should_continue = false;    
                    }

                    $n_parent_id = $ent_cycle->parent_id;


                } else {
                    $should_continue = false;
                }


            } while ($should_continue);
    
        } 

        $this->loadModel('SpaLiveV1.DataPurchases');
        $this->loadModel('SpaLiveV1.DataPurchasesDetail');

        $ent_purchases_detail = $this->DataPurchasesDetail->find()->select(['DataPurchasesDetail.price', 'DataPurchasesDetail.qty','Product.name','Product.category','Product.comission_a','Product.comission_b','Product.comission_c'])
        ->join([
            'Product' => ['table' => 'cat_products', 'type' => 'INNER', 'conditions' => 'Product.id = DataPurchasesDetail.product_id']
        ])->where(['DataPurchasesDetail.purchase_id' => $ent_purchase['id']])->order(['DataPurchasesDetail.id' => 'DESC'])->all();
        
        // Pyramid comission calc
        foreach($result as $ci_row) {

            $ci_user_id = $ci_row['user_id'];
            $ci_level = $ci_row['level'];
            $ci_type = $ci_row['type'];
            $ci_state = $ci_row['state'];
            
            $super_total_ci_comission = 0;

            foreach ($ent_purchases_detail as $row) {
                
                $ci_price = $row['price'];
                $quantity = $row['qty'];
                                    
                $mkey = 'comission_a';
                if ($ci_level == 2) {
                    $mkey = 'comission_b';
                } else if ($ci_level == 3) {
                    $mkey = 'comission_c';
                } else if ($ci_level == 4) {
                    $mkey = 'comission_d';
                }  

                $ci_comission = $row['Product'][$mkey];
                $total_comission = $quantity * $ci_comission;    
                $super_total_ci_comission += $total_comission;
                
            }

            // CHECK SUBSCRIPTIONS
            $this->loadModel('SpaLiveV1.CatAgreements');
            // $ci_user_ent = $this->SysUsers->find()->where(['SysUsers.id' => $ci_user_id, 'SysUsers.deleted' => 0, 'SysUsers.active' => 1])->first();
            $pending_subscriptions = false; // if true means dont have both subscriptions

            $ent_agreement = $this->CatAgreements->find()->select(['CatAgreements.uid','DataAgreement.id','DataAgreement.deleted', 'DataSubscriptions.status'])->join([
                    'DataAgreement' => ['table' => 'data_agreements', 'type' => 'INNER', 'conditions' => 'CatAgreements.uid = DataAgreement.agreement_uid AND DataAgreement.user_id = ' . $ci_user_id. ' AND DataAgreement.deleted = 0'],
                    'DataSubscriptions' => ['table' => 'data_subscriptions', 'type' => 'INNER', 'conditions' => 'DataSubscriptions.user_id='. $ci_user_id.' AND DataSubscriptions.deleted =  0 AND DataSubscriptions.subscription_type = "SUBSCRIPTIONMSL" AND DataSubscriptions.status = "ACTIVE"'],
                ])->where(
                [
                    'CatAgreements.state_id' => $ci_state,
                    'CatAgreements.user_type' => $ci_type == 'gfe+ci' ? 'injector' : $ci_type,
                    'CatAgreements.agreement_type' => 'SUBSCRIPTIONMSL',
                ]
            )->first();

            if (empty($ent_agreement)) {
                $pending_subscriptions = true;
            } 

            $ent_agreement = $this->CatAgreements->find()->select(['CatAgreements.uid','DataAgreement.id','DataAgreement.deleted', 'DataSubscriptions.status'])->join([
                    'DataAgreement' => ['table' => 'data_agreements', 'type' => 'INNER', 'conditions' => 'CatAgreements.uid = DataAgreement.agreement_uid AND DataAgreement.user_id = ' . $ci_user_id. ' AND DataAgreement.deleted = 0'],
                    'DataSubscriptions' => ['table' => 'data_subscriptions', 'type' => 'INNER', 'conditions' => 'DataSubscriptions.user_id = '. $ci_user_id.' AND DataSubscriptions.deleted =  0 AND DataSubscriptions.subscription_type = "SUBSCRIPTIONMD" AND DataSubscriptions.status = "ACTIVE"'],
                    ])->where(
                [
                    'CatAgreements.state_id' => $ci_state,
                    'CatAgreements.user_type' => $ci_type == 'gfe+ci' ? 'injector' : $ci_type,
                    'CatAgreements.agreement_type' => 'SUBSCRIPTIONMD',
                ]
            )->first();
                
            if (empty($ent_agreement)) {
                $pending_subscriptions = true;
            } 
            
            if ($super_total_ci_comission > 0 && !$pending_subscriptions){
                $this->createPaymentCommissionRegister('CI COMMISSION', $ent_pay->id_from, $ci_user_id, $purchase_uid, $ent_pay->intent, $ent_pay->payment, '', $super_total_ci_comission);
            } 
        }
    }

