    public function check_exist() {

        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->loadModel('SpaLiveV1.SysUsers');

        $email = get('email', '');
       
        if (empty($email)) {
            $this->message('Email address empty.');
            return;
        }

        $existUser = $this->SysUsers->find()->where(['SysUsers.email LIKE' => strtolower($email)])->first();

        if(!empty($existUser)) {
            if($existUser->type == 'patient'){
                if($existUser->deleted == 0){
                    if($existUser->state != USER_STATE){
                        $this->message('This patient is registered in another state. Please try a different one.');
                        $this->set('patient', 1);
                        $this->success();
                        return;
                    }

                    $this->loadModel('SpaLiveV1.DataPatientClinic');
                    $existRelat = $this->DataPatientClinic->find()
                        ->where(['DataPatientClinic.injector_id' => USER_ID, 'DataPatientClinic.user_id' => $existUser->createdby])->first();
                    if(!empty($existRelat)){
                        $this->message('is already your patient.');
                        $this->set('patient', 1);
                        $this->success();
                        return;
                    }else{
                        $user_info = [
                            'user_uid' => $existUser->uid,
                            'user_name' => $existUser->name . ( empty($existUser->mname) ? '' : ' '.$existUser->mname ) . ' ' . $existUser->lname,
                            'user_email' => $existUser->email,
                            'user_phone' => $existUser->phone,
                        ];

                        $this->set('user_info', $user_info);
                        $this->set('patient', 2);
                        $this->set('state 1', USER_STATE);
                        $this->set('state 2', $existUser->state);
                        $this->success();
                        return;
                    }
                } else{
                    $this->loadModel('SpaLiveV1.DataSubscriptionMethodPayments');
                    $entMethod = $this->DataSubscriptionMethodPayments->find()->where(['DataSubscriptionMethodPayments.user_id' => $existUser->id])->first();
                    if(!empty($entMethod)){
                        $this->message('The patient is not active.');
                        $this->set('patient', 1);
                        $this->success();
                        return;
                    }
                }
            } else if($existUser->type == 'injector'){
                if($existUser->id == USER_ID){
                    $user_info = [
                        'user_uid' => $existUser->uid,
                        'user_name' => $existUser->name . ( empty($existUser->mname) ? '' : ' '.$existUser->mname ) . ' ' . $existUser->lname,
                        'user_email' => $existUser->email,
                        'user_phone' => $existUser->phone,
                    ];

                    $this->set('user_info', $user_info);
                    $this->set('patient', 2);
                    $this->success();
                    return;
                }else{
                    $this->message('Email address already exists but it is not a patient.');
                    $this->set('patient', 1);
                    $this->success();
                    return;
                }
            }else{
                $this->message('Email address already exists but it is not a patient.');
                $this->set('patient', 1);
                $this->success();
                return;

            }
            
        }
        $this->set('patient', 3);
        $this->success();
        return;
    }
    
    private function update_network($email,$user_id) {


        $this->loadModel('SpaLiveV1.DataNetwork');
        $this->loadModel('SpaLiveV1.DataNetworkInvitations');

        $parent_id = 0;
        $level = 0;

        $existUser = $this->DataNetworkInvitations->find()->where(['DataNetworkInvitations.email LIKE' => strtolower($email)])->first();

        if(!empty($existUser)){
            $parent_id = $existUser->parent_id;

            $networkLevel = $this->DataNetwork->find()->where(['DataNetwork.user_id' => $parent_id])->first();
            if (!empty($networkLevel)) {
                $level = $networkLevel->level + 1;
            }

        }


        $array_save = array(
            'parent_id' => $parent_id,
            'user_id' => $user_id,
            'level' => $level,

        );

        $entity = $this->DataNetwork->newEntity($array_save);
        if(!$entity->hasErrors()) $this->DataNetwork->save($entity);

    }

