    public function register_agreement() {

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }


        $str_uid = get('agreement_uid','');
        $str_sign = get('sign','');
        $_userid = USER_ID;
        $_file_id = 0;

        $patient_uid = get('patient_uid','');
        if (!empty($patient_uid)) {
            $this->loadModel('SpaLiveV1.SysUsers');
            $ent_user = $this->SysUsers->find()->where(['SysUsers.uid' => $patient_uid])->first();
            if (!empty($ent_user)) {
                $_userid = $ent_user->id;
            }
        }

        if (empty($str_uid) || empty($str_sign)) {
            $this->message('Invalid params.');
            return;
        }

        if (isset($_FILES['file'])) {
            if (!isset($_FILES['file']['name'])) {
                $this->set('error_name',$_FILES['file']);
                return;
            }
    
            $str_name = $_FILES['file']['name'];
            $_file_id = $this->Files->upload([
                'name' => $str_name,
                'type' => $_FILES['file']['type'],
                'path' => $_FILES['file']['tmp_name'],
                'size' => $_FILES['file']['size'],
            ]);
    
            if($_file_id <= 0){
                $this->message('Error in save content file.');
                return;
            }
        }

        $this->loadModel('SpaLiveV1.Agreement');
        $ent_agreement = $this->Agreement->find()->where(
                ['Agreement.uid' => $str_uid,
                'Agreement.deleted' => 0]
            )->first();
        if (empty($ent_agreement)) {
            $this->message('Invalid agreement.');
            return;
        }
        // $agreement_id = $this->Agreement->uid_to_id(get('uid_patient', ''));

        // if ($agreement_id == 0) {
        //     $this->message('Invalid agreement.');
        //     return;
        // }
        
        $this->loadModel('SpaLiveV1.DataAgreement');

        $array_save = array(
            'uid' => Text::uuid(),
            'user_id' => $_userid,
            'sign' => $str_sign,
            'agreement_uid' => $str_uid,
            'file_id' => $_file_id,
            'content' => $ent_agreement->content,
            'created' => date('Y-m-d H:i:s'),
        );

        // revisar si ya existe un agreement firmado por el usuario y el tipo de agreement
        $user_agreement = $this->DataAgreement->find()->where(
            ['DataAgreement.user_id' => $_userid,
            'DataAgreement.agreement_uid' => $str_uid,
            'DataAgreement.deleted' => 0]
        )->first();

        if (!empty($user_agreement)) {
            
            $this->DataAgreement->updateAll(
                ['sign' => $str_sign, 'file_id' => $_file_id, 'created' => date('Y-m-d H:i:s')],
                ['id' => $user_agreement->id]
            );

            $update_step = get('update_patient_step', 0);
            if($update_step == 1){
                $this->loadModel('SpaLiveV1.SysUsers');
                if(USER_TYPE == 'patient'){
                    $this->SysUsers->updateAll(
                        ['steps' => 'GFEPAYMENT'], 
                        ['id' => USER_ID]
                    );
                } else if(USER_TYPE == 'examiner'){
                    $this->SysUsers->updateAll(
                        ['steps' => 'W9'],
                        ['id' => USER_ID]
                    );
                }
            }

            $this->set('agreement_id', $user_agreement->id);
            $this->success();
            return;
        }

        $entity = $this->DataAgreement->newEntity($array_save);
        if(!$entity->hasErrors()){
            if($this->DataAgreement->save($entity)){
                $this->set('agreement_id', $entity->id);
                $this->success();
            }
            $update_step = get('update_patient_step', 0);
            if($update_step == 1){
                $this->loadModel('SpaLiveV1.SysUsers');
                if(USER_TYPE == 'patient'){
                    if(USER_STEP != 'HOME'){
                        if(USER_STEP == 'TREATMENTINFO'){
                            $this->SysUsers->updateAll(
                                ['steps' => 'HOME'], 
                                ['id' => USER_ID]
                            );
                        } else {
                            $this->SysUsers->updateAll(
                                ['steps' => 'GFEPAYMENT'], 
                                ['id' => USER_ID]
                            );
                        }
                    }
                } else if(USER_TYPE == 'examiner'){
                    $this->SysUsers->updateAll(
                        ['steps' => 'W9'],
                        ['id' => USER_ID]
                    );
                }
            }
        }
    }

    private function get_user_agreements(){

        // $token = get('token', '');
        
        // if(!empty($token)){
        //     $user = $this->AppToken->validateToken($token, true);
        //     if($user === false){
        //         $this->message('Invalid token.');
        //         $this->set('session', false);
        //         return;
        //     }
        //     $this->set('session', true);
        // } else {
        //     $this->message('Invalid token.');
        //     $this->set('session', false);
        //     return;
        // }

        $this->loadModel('DataAgreements');
        $this->loadModel('DataTrainings');

        $ent = $this->DataAgreements->find()->select([
            'CatAgreement.agreement_type',
            'CatAgreement.agreement_title',
            'CatAgreement.issue_type',
            'CatAgreement.other_treatment_id',
            'SysTreatment.name_key',
            'SysTreatment.name',
            'State.name',
            'DataAgreements.created',
            'CatAgreement.uid',
            'DataAgreements.uid'
        ])
        ->join([
            'CatAgreement' => ['table' => 'cat_agreements', 'type' => 'INNER', 'conditions' => 'CatAgreement.uid = DataAgreements.agreement_uid'],
            'State' => ['table' => 'cat_states', 'type' => 'LEFT', 'conditions' => 'State.id = CatAgreement.state_id'],
            'SysTreatment' => ['table' => 'sys_treatments_ot', 'type' => 'LEFT', 'conditions' => 'SysTreatment.id = CatAgreement.other_treatment_id']
        ])
        ->where(['DataAgreements.user_id' => USER_ID,'CatAgreement.deleted' => 0,'CatAgreement.id >' => 24,'DataAgreements.deleted' => 0])->all();
        
        $connection = \Cake\Datasource\ConnectionManager::get('default');
        $all_treatments = $connection->execute(
            'SELECT name_key, name FROM sys_treatments_ot WHERE deleted = 0 AND active = 1'
        )->fetchAll('assoc');
        
        $text_array = 
            array(
                'REGISTRATION' => 'Registration Agreement',
                'EXAM' => 'Good Faith Exam',
                'TREAMENT' => 'Treatment',
                'NEUROTOXINS' => 'Neurotoxins Consent',
                'FILLERS' => 'Fillers Consent',
                'SUBSCRIPTION' => 'Subscription',
                'TERMSANDCONDITIONS' => 'Terms and conditions',
                'SUBSCRIPTIONMD' => 'Medical Director Subscription',
                'SUBSCRIPTIONMSL' => 'MySpaLive Subscription'
            );

        
        $result = array();
        foreach ($ent as $row) {
            $issue_type = $row['CatAgreement']['issue_type'] ?? '';
            $agreement_type = $row['CatAgreement']['agreement_type'] ?? '';
            $treatment_name = '';
            $display_name = '';
            
            // Solo aplicar lógica de tratamiento para acuerdos que realmente lo necesiten
            $needs_treatment_logic = false;
            
            // Verificar si es un acuerdo que necesita lógica de tratamiento
            if ($agreement_type === 'OTHER_TREATMENTS' || 
                (!empty($row['CatAgreement']['other_treatment_id']) && 
                 (in_array($issue_type, ['MSL', 'MD']) || 
                  strpos($agreement_type, 'SUBSCRIPTION') !== false))) {
                $needs_treatment_logic = true;
            }
            
            if ($needs_treatment_logic) {
                $detected_type = $issue_type;
                if (empty($detected_type)) {
                    if (strpos($agreement_type, 'SUBSCRIPTIONMD') !== false ||
                        strpos($row['CatAgreement']['agreement_title'], 'Medical Director') !== false) {
                        $detected_type = 'MD';
                    } elseif (strpos($agreement_type, 'SUBSCRIPTIONMSL') !== false ||
                               strpos($row['CatAgreement']['agreement_title'], 'MySpaLive') !== false) {
                        $detected_type = 'MSL';
                    }
                }
                
                $treatment = null;
                // Solo usar el tratamiento de la base de datos si hay other_treatment_id
                if (!empty($row['CatAgreement']['other_treatment_id'])) {
                    if (!empty($row['SysTreatment']['name'])) {
                        $treatment = $row['SysTreatment']['name'];
                    } elseif (!empty($row['SysTreatment']['name_key'])) {
                        $treatment = ucwords(strtolower(str_replace('_', ' ', $row['SysTreatment']['name_key'])));
                    }
                }
                
                // Solo buscar tratamiento en el título si no se encontró en la BD y hay other_treatment_id
                if (empty($treatment) && !empty($row['CatAgreement']['other_treatment_id'])) {
                    $title_clean = $row['CatAgreement']['agreement_title'];
                    $title_clean = str_replace(['MySpaLive Subscription ', 'Medical Director Subscription ', ' Subscription'], '', $title_clean);
                    $title_clean = str_replace([' For IV Therapy'], '', $title_clean);
                    $title_clean = strtolower(trim($title_clean));
                    
                    foreach ($all_treatments as $treatment_item) {
                        $treatment_name_lower = strtolower($treatment_item['name'] ?? '');
                        $treatment_key_lower = strtolower(str_replace('_', ' ', $treatment_item['name_key'] ?? ''));
                        
                        if (strpos($title_clean, $treatment_name_lower) !== false || 
                            strpos($title_clean, $treatment_key_lower) !== false) {
                            $treatment = !empty($treatment_item['name']) ? $treatment_item['name'] : 
                                        ucwords(str_replace('_', ' ', $treatment_item['name_key']));
                            break;
                        }
                    }
                }
                
                if (!empty($detected_type)) {
                    if (!empty($treatment)) {
                        $display_name = $treatment . ' ' . $detected_type . ' agreement';
                    } else {
                        // Solo usar tratamiento por defecto si realmente es necesario
                        $default_treatment = 'Basic neurotoxins';
                        foreach ($all_treatments as $treatment_item) {
                            $treatment_name = strtolower($treatment_item['name'] ?? '');
                            if (strpos($treatment_name, 'neurotoxins') !== false) {
                                $default_treatment = $treatment_item['name'];
                                break;
                            }
                        }
                        if ($default_treatment === 'Basic neurotoxins' && !empty($all_treatments)) {
                            $default_treatment = $all_treatments[0]['name'] ?? 'Basic neurotoxins';
                        }
                        $display_name = $default_treatment . ' ' . $detected_type . ' agreement';
                    }
                }
            }
            
            if (empty($display_name)) {
                $display_name = isset($text_array[$row['CatAgreement']['agreement_title']]) ? 
                    $text_array[$row['CatAgreement']['agreement_title']] : 
                    $row['CatAgreement']['agreement_title'];
            }
            
            $result[] = array(
                'state' => $row['State']['name'],
                'created' => $row['created'],
                'type' => $display_name,
                'uid' => $row['uid'],
            );
        }

        $protocols = $this->_getCommonDocumentsForUser(USER_ID, USER_TYPE);

        $this->set('my_documents', array('protocols' => $protocols,'user_agreements' => $result));
    }

    private function _getCommonDocumentsForUser($userId, $userType)
    {
        $isInjector = ($userType === 'injector');
        $isPatient = ($userType === 'patient');
        
        $hasLevel1Access = $isInjector ? $this->_userHasLevelTraining($userId, 'LEVEL 1') : false;
        $hasLevel2Access = $isInjector ? $this->_userHasLevelTraining($userId, 'LEVEL 2') : false;
        $hasLevel3Access = $isInjector ? $this->_userHasLevelTraining($userId, 'LEVEL 3') : false;
        
        $subscribedLevels = $this->_getUserSubscribedLevelsFromSubscriptions($userId);
        $userTreatmentIds = $this->_getUserSubscribedTreatmentIds($userId);
        
        $this->loadModel('DataCommonDocuments');
        $documents = $this->DataCommonDocuments->find()
            ->select(['id', 'name', 'url', 'level', 'user_type', 'treatment_permissions'])
            ->where([
                'deleted' => 0,
                'OR' => [
                    ['user_type' => $userType],
                    ['user_type' => 'all']
                ]
            ])
            ->enableHydration(false)
            ->toArray();

        $filteredDocuments = [];
        $subscribedLevelsSet = array_flip($subscribedLevels);
        
        foreach ($documents as $doc) {
            $hasAccess = false;
            
            if ($isPatient) {
                $docLevel = $doc['level'] ?? '';
                
                if (in_array($docLevel, ['LEVEL 1', 'LEVEL 2', 'LEVEL 3'])) {
                    $hasAccess = false;
                }
                else if (empty($docLevel) || $docLevel === 'all') {
                    $hasAccess = true;
                }
                else if ($docLevel === 'LEVEL IV') {
                    $hasAccess = isset($subscribedLevelsSet[$docLevel]);
                }
                else if (isset($subscribedLevelsSet[$docLevel])) {
                    $hasAccess = true;
                }
                else {
                    $hasAccess = true;
                }
                
            } else if ($isInjector) {
                $hasLevelAccess = false;
                $hasTreatmentAccess = false;

                if (isset($doc['level']) && !empty($doc['level'])) {
                    if ($doc['level'] === 'all') {
                        $hasLevelAccess = true;
                    }
                    else if ($doc['level'] === 'LEVEL 1') {
                        $hasLevelAccess = $hasLevel1Access;
                    }
                    else if ($doc['level'] === 'LEVEL 2') {
                        $hasLevelAccess = $hasLevel2Access;
                    }
                    else if ($doc['level'] === 'LEVEL 3') {
                        $hasLevelAccess = $hasLevel3Access;
                    }
                    else if (isset($subscribedLevelsSet[$doc['level']])) {
                        $hasLevelAccess = true;
                    }
                }
                else if (empty($doc['level']) || $doc['level'] === null) {
                    $hasLevelAccess = true;
                }

                if (!empty($doc['treatment_permissions'])) {
                    $treatmentPermissions = json_decode($doc['treatment_permissions'], true);
                    if (is_array($treatmentPermissions) && !empty($treatmentPermissions)) {
                        foreach ($treatmentPermissions as $treatmentId => $enabled) {
                            if ($enabled === true && in_array((int)$treatmentId, $userTreatmentIds)) {
                                $hasTreatmentAccess = true;
                                break;
                            }
                        }
                    }
                }

                if ($doc['level'] === 'LEVEL IV' && !empty($doc['treatment_permissions'])) {
                    $hasAccess = $hasLevelAccess || $hasTreatmentAccess;
                } else {
                    if (!empty($doc['treatment_permissions'])) {
                        $hasAccess = $hasLevelAccess && $hasTreatmentAccess;
                    } else {
                        $hasAccess = $hasLevelAccess;
                    }
                }
            }

            // Permitir acceso si el documento es para todos los tipos de usuario
            if (!$hasAccess && isset($doc['user_type']) && $doc['user_type'] === 'all') {
                $hasAccess = true;
            }
            
            if ($hasAccess) {
                $filteredDocuments[] = [
                    'title' => $doc['name'],
                    'url' => $this->_transformDocumentUrl($doc['url'])
                ];
            }
        }

        return $filteredDocuments;
    }
    
    /**
     * Transform URL from myspalive.com to blog.myspalive.com
     * Only transforms if URL contains "https://myspalive.com"
     * 
     * @param string $url Original URL
     * @return string Transformed URL or original URL if no match
     */
    private function _transformDocumentUrl($url)
    {
        if (strpos($url, 'https://myspalive.com') !== false) {
            return str_replace('https://myspalive.com', 'https://blog.myspalive.com', $url);
        }
        return $url;
    }
    
    private function _userHasLevelTraining($userId, $level)
    {
        $this->loadModel('SpaLiveV1.DataTrainings');
        
        $levelVariants = [];
        switch ($level) {
            case 'LEVEL 1':
                $levelVariants = [
                    'CatTraining.level' => 'LEVEL 1',
                    ['CatTraining.title LIKE' => '%LEVEL 1%'],
                    ['CatTraining.title LIKE' => '%Level 1%'],
                    ['CatTraining.title LIKE' => '%Nivel 1%']
                ];
                break;
            case 'LEVEL 2':
                $levelVariants = [
                    'CatTraining.level' => 'LEVEL 2',
                    ['CatTraining.title LIKE' => '%LEVEL 2%'],
                    ['CatTraining.title LIKE' => '%Level 2%'],
                    ['CatTraining.title LIKE' => '%Nivel 2%']
                ];
                break;
            case 'LEVEL 3':
                $levelVariants = [
                    ['CatTraining.level' => 'LEVEL 3 MEDICAL'],
                    ['CatTraining.title LIKE' => '%LEVEL 3%'],
                    ['CatTraining.title LIKE' => '%Level 3%'],
                    ['CatTraining.title LIKE' => '%Nivel 3%']
                ];
                break;
            default:
                return false;
        }
        
        $training = $this->DataTrainings->find()
            ->join([
                'CatTraining' => [
                    'table' => 'cat_trainings',
                    'type' => 'INNER',
                    'conditions' => 'CatTraining.id = DataTrainings.training_id'
                ]
            ])
            ->where([
                'DataTrainings.user_id' => $userId,
                'DataTrainings.deleted' => 0,
                'DataTrainings.attended' => 1,
                'CatTraining.deleted' => 0,
                'OR' => $levelVariants
            ])
            ->first();
            
        return !empty($training);
    }
    
    private function _getUserSubscribedTreatmentIds($userId)
    {
        $this->loadModel('DataSubscriptions');
        $subscriptions = $this->DataSubscriptions->find()
            ->select(['main_service', 'addons_services'])
            ->where(['user_id' => $userId])
            ->enableHydration(false)
            ->toArray();
        
        $treatmentNames = [];
        foreach ($subscriptions as $sub) {
            if (!empty($sub['main_service'])) {
                $treatmentNames[] = $sub['main_service'];
            }
            if (!empty($sub['addons_services'])) {
                $addons = explode(',', $sub['addons_services']);
                foreach ($addons as $addon) {
                    $treatmentNames[] = trim($addon);
                }
            }
        }
        
        if (empty($treatmentNames)) {
            return [];
        }
        
        return $this->_mapTreatmentNamesToIds($treatmentNames);
    }
    
    private function _mapTreatmentNamesToIds($treatmentNames)
    {
        if (empty($treatmentNames)) {
            return [];
        }
        
        $this->loadModel('SpaLiveV1.SysTreatmentsOt');
        
        $orConditions = [];
        foreach ($treatmentNames as $name) {
            $orConditions[] = ['name LIKE' => '%' . $name . '%'];
        }
        
        $treatments = $this->SysTreatmentsOt->find()
            ->select(['id'])
            ->where([
                'OR' => $orConditions,
                'deleted' => 0
            ])
            ->enableHydration(false)
            ->toArray();
        
        $treatmentIds = [];
        foreach ($treatments as $treatment) {
            $treatmentIds[] = (int)$treatment['id'];
        }
        
        return array_unique($treatmentIds);
    }
    
    private function _getUserSubscribedLevelsFromSubscriptions($userId)
    {
        $this->loadModel('DataSubscriptions');
        $subscriptions = $this->DataSubscriptions->find()
            ->select(['main_service', 'addons_services'])
            ->where(['user_id' => $userId])
            ->enableHydration(false)
            ->toArray();    
        $treatmentNames = [];
        foreach ($subscriptions as $sub) {
            if (!empty($sub['main_service'])) {
                $treatmentNames[] = $sub['main_service'];
            }
            if (!empty($sub['addons_services'])) {
                $addons = explode(',', $sub['addons_services']);
                foreach ($addons as $addon) {
                    $treatmentNames[] = trim($addon);
                }
            }
        }
        if (empty($treatmentNames)) {
            return [];
        }
        return $this->_mapServiceNamesToLevels($treatmentNames);
    }
    private function _mapServiceNamesToLevels($serviceNames)
    {
        $serviceToLevelMap = [
            'NEUROTOXINS' => ['LEVEL 1', 'LEVEL 2'],
            'FILLERS' => ['LEVEL 2'],
            'DERMAPLANING' => ['LEVEL 1', 'LEVEL 2'],
            'MICRONEEDLING' => ['LEVEL 1', 'LEVEL 2'],
            'CHEMICAL_PEELS' => ['LEVEL 1', 'LEVEL 2'],
            'LASH_ENHACEMENT' => ['LEVEL 1', 'LEVEL 2'],
            'IV THERAPY' => ['LEVEL IV']
        ];
        
        $allowedLevels = [];
        foreach ($serviceNames as $serviceName) {
            if (isset($serviceToLevelMap[$serviceName])) {
                $allowedLevels = array_merge($allowedLevels, $serviceToLevelMap[$serviceName]);
            }
        }

        return array_unique($allowedLevels);
    }

