          ]);

       
    
        $this->createPaymentRegister('GFE', $user_id, 0, $transfer_group, $session->payment_intent, $this->get_amount($consultation_id), $total_amount, $save_discount_credits, $prepaid);
        
        $this->set('uid', $transfer_group);
