    private function check_publicdata_detals($dlnumber, $dlstate, $id,$record, $ed, $db) {
        
        $post_data = array(
            'dlnumber' => $dlnumber, //Guardhub
            'dlstate' => $dlstate,
            'id' => $id,
            'rec' => $record,
            'db' => $db,
            'ed' => $ed,
            'disp' => 'XML'
        );

        $curl = curl_init();
        curl_setopt($curl, CURLOPT_URL, "https://login.publicdata.com/pddetails.php?disp=XML");
        curl_setopt($curl, CURLOPT_POST, true);
        curl_setopt($curl, CURLOPT_POSTFIELDS, $post_data);
        curl_setopt($curl, CURLOPT_RETURNTRANSFER, true);
        //Send CURL Request
        $result = curl_exec($curl);
        $err = curl_error($curl);
        curl_close($curl);

        if ($err) {
            return array();
        }
        //No data found From API
        if (empty($result)) {
            return array();
        }
        
        
        $xml = simplexml_load_string($result, "SimpleXMLElement", LIBXML_NOCDATA);
        $arr_result = array();
        if (isset($xml->dataset->dataitem)) {
            $dataitem = $xml->dataset->dataitem;
