                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

       $tt = $this->total;
        /*
        $treatments = get('treatments','');
        if (!empty($treatments)) {
            $arr_treatments = explode(",", $treatments); 
            $tt = $this->total;
            if (count($arr_treatments) > 4) {
