    public function create_checkout_session_training_advanced() {

         $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        

        $this->loadModel('SpaLiveV1.SysUsers');
     

        $ent_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
        
        if (empty($ent_user)) {
            $this->message('user not found');
            return;
        }


        $uid = 'AT' . $ent_user->uid;
        $total_amount = $this->validateCode(get('promo_code',''),$this->training_advanced,'TRAINING');
             
        if ($total_amount < 100) $total_amount = 100;

        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        
        $oldCustomer = $stripe->customers->all([
            "email" => $ent_user['email'],
            "limit" => 1,
        ]);

        if (count($oldCustomer) == 0) {
            $customer = $stripe->customers->create([
                'description' => $ent_user['name'] . ' ' . $ent_user['lname'],
                'email' => $ent_user['email'],
            ]);
        } else $customer = $oldCustomer->data[0];


        $session = \Stripe\Checkout\Session::create([
            'payment_method_types' => ['card'],
            'payment_intent_data' => ['transfer_group' => $uid, 'metadata' => ['type' => 'purchase', 'uid' => $uid]],
            'line_items' => [[
              'price_data' => [
                'currency' => 'usd',
                'product_data' => [
                  'name' => 'MySpaLive',
                ],
                'unit_amount' => $total_amount,
              ],
              'quantity' => 1,
            ]],
            'customer' => $customer['id'],
            'metadata' => ['type' => 'purchase', 'uid' => $uid],
            'mode' => 'payment',
            'success_url' => $this->URL_WEB . 'injector/trainings/LEVEL2',
            'cancel_url' => $this->URL_WEB,
          ]);

      

        $this->createPaymentRegister('PURCHASE', $ent_user->id, 0, $uid, $session->payment_intent, $this->training_advanced, $total_amount);

        // CREATE PURCHASE

        $purchase_array_save = array(
            'uid' => $uid,
            'user_id' => $ent_user->id,
            'status' => 'NEW',
            'name' => $ent_user->name . ' ' . $ent_user->lname,
            'address' => $ent_user->street,
            'suite' => $ent_user->suite,
            'city' => $ent_user->city,
            'state' => $ent_user->state,
            'zip' => $ent_user->zip,
            'tracking' => '',
            'payment_intent' => $session->payment_intent,
            'delivery_company' => '',
            'created' => date('Y-m-d H:i:s'),
            'shipping_date' => date('Y-m-d'),
            'shipping_cost' => 0,
            'amount' => $total_amount,
        );


        $this->loadModel('SpaLiveV1.DataPurchasesDetail');
        $this->loadModel('SpaLiveV1.DataPurchases');

        $c_entity = $this->DataPurchases->newEntity($purchase_array_save);
        if(!$c_entity->hasErrors()) {
            if ($this->DataPurchases->save($c_entity)) {
                $this->set('uid', $uid);

                $detail_array_save = array(
                    'product_id' => 44,
                    'purchase_id' => $c_entity->id,
                    'price' => $total_amount,
                    'qty' => 1,
