    public function send_payment_treatment_patient(){
        $this->loadModel('SpaLiveV1.DataTreatment');

        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $treatment_uid = get('uid', '');
        if(empty($treatment_uid)){
            $this->message('treatment_uid empty.');
            return;
        }

        $ent_treatment = $this->DataTreatment->find()->select(['DataTreatment.id', 'DataTreatment.payment_intent','DataTreatment.amount','DataTreatment.patient_id', 'DataTreatment.assistance_id', 'User.name', 'User.lname'])
        ->join([
            'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTreatment.assistance_id'],
        ])
        ->where(['DataTreatment.uid' => $treatment_uid])->first();
        
        if (empty($ent_treatment)) {
            $this->message('purchase not found');
            return;
        }

        $tip = get('tip', 0);
        $tip_type = get('tip_type','');
        $promo_code = get('promo_code','');

        $total_amount = $this->validateCode(get('promo_code',''),$ent_treatment->amount,'TREATMENT', $ent_treatment);
        
        if ($total_amount < 100) $total_amount = 100;

        if($tip > 0){
            if($tip_type == 'PERCENTAGE'){
                $tip = ($tip / 100) * $total_amount;
            }else if($tip_type == 'CUSTOM'){
                $tip = $tip * 100;
            }
        }

        $this->DataTreatment->updateAll(
            [
                'request_payment' => 1,
                'tip' => $tip,
                'promo_code' => $promo_code,
            ],
            ['id' => $ent_treatment->id]
        );

        $this->notify_devices('NOTIFI_PAYMENT_TREATMENT',array($ent_treatment->patient_id),true);

        $this->set('total', $total_amount + $tip);
        $this->success();
    }

