    public function auto_approve($user_id){

        $this->loadModel('SpaLiveV1.SysUsers');
        $ent_user = $this->SysUsers->find()->select(['SysUsers.id','SysUsers.uid','SysUsers.login_status','SysUsers.name','SysUsers.lname','SysUsers.mname','SysUsers.type','SysUsers.payment_intent', 'SysUsers.tracers','SysUsers.dob','SysUsers.tracers', 'SysUsers.email'])
        ->where(['SysUsers.id' => $user_id])->first();


        if ($ent_user->type == 'injector') {

            $email = $ent_user->email;
            $user_id = $ent_user->id;
            $user_uid = $ent_user->uid;


            $this->loadModel('SpaLiveV1.DataNetwork');
            $this->loadModel('SpaLiveV1.DataNetworkInvitations');
            $this->DataNetwork->addBehavior('SpaLiveV1.MyTree');

            // adding in pyramid

            $ent_find_usr = $this->DataNetwork->find()->where(['DataNetwork.user_id' => $user_id])->first();

            if (empty($ent_find_usr)) {

                $existUser = $this->DataNetworkInvitations->find()->where(['DataNetworkInvitations.email LIKE' => strtolower($email)])->first();
                if(!empty($existUser)){
                    $parent_id = $existUser->parent_id;

                    //$this->createPaymentRegister('CI_COMMISSION', $parent_id, $user_id, $user_uid, $ent->payment_intent, 7500, 7500);

                    $networkLevel = $this->DataNetwork->find()->where(['DataNetwork.user_id' => $parent_id])->first();
                    if (!empty($networkLevel)) {
                        $level = $networkLevel->level + 1;

                        $array_save = array(
                            'parent_id' => $parent_id,
                            'user_id' => $user_id,
                            'level' => $level,
                        );

                        $entity = $this->DataNetwork->newEntity($array_save);
                        if(!$entity->hasErrors()) { 
                            
                            $ent_find = $this->DataNetwork->find()->where(['DataNetwork.parent_id' => $parent_id])->first();
                            if (empty($ent_find)) {
                                $str_qq = 'UPDATE data_network SET levels_below = levels_below + 1 WHERE user_id = ' . $parent_id;
                                $this->DataNetwork->getConnection()->execute($str_qq);
                                $n_f_id_p = $parent_id;
                                $shd = false;
                                do {
                                    $ent_fff = $this->DataNetwork->find()->where(['DataNetwork.parent_id' => $n_f_id_p])->first();

                                    if(!empty($ent_fff)) {
                                        $n_f_id_p = $ent_fff->user_id;
                                        $ent_fff->levels_below = $ent_fff->levels_below + 1;
                                        $this->DataNetwork->save($ent_fff);
                                    }
                                    else
                                        $shd = true;
                                } while (!$shd);

                            }

                            $this->DataNetwork->save($entity);
                            $this->DataNetwork->recover_tree();
                        }
                    }

                } else {


                    $ent_next = $this->DataNetwork->find()->join([
                        'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataNetwork.user_id']
                    ])
                    ->where(['DataNetwork.levels_below <' => 3,'User.type' => 'injector','User.login_status' => 'READY', 'User.active' => 1, 'User.deleted' => 0])->order(['DataNetwork.user_id' => 'ASC'])->first();
                    if (!empty($ent_next)) {
                        
                        $n_f_id = $ent_next->user_id;
                        $n_f_level = $ent_next->level;
                        $shd = false;
                        do {
                            $ent_ff = $this->DataNetwork->find()->join([
                                'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataNetwork.user_id']
                            ])->where(['DataNetwork.parent_id' => $n_f_id,'User.type' => 'injector','User.login_status' => 'READY', 'User.active' => 1, 'User.deleted' => 0])->order(['DataNetwork.user_id' => 'ASC'])->first();

                            if(!empty($ent_ff)) {
                                $n_f_id = $ent_ff->user_id;
                                $n_f_level = $ent_ff->level;
                                $ent_ff->levels_below = $ent_ff->levels_below + 1;
                                $this->DataNetwork->save($ent_ff);
                            }
                            else
                                $shd = true;
                        } while (!$shd);
                            
                            $array_save = array(
                                'parent_id' => $n_f_id,
                                'user_id' => $user_id,
                                'level' => $n_f_level + 1,
                            );

                        $entity = $this->DataNetwork->newEntity($array_save);
                        if(!$entity->hasErrors()) { 
                            $this->DataNetwork->save($entity);

                            $ent_next->levels_below = $ent_next->levels_below + 1;
                            $this->DataNetwork->save($ent_next);
                            $this->DataNetwork->recover_tree();
                        }
                    }
                    
                }
            }
        }

        $ent_user->login_status = 'W9';
        $ent_user->last_status_change = date('Y-m-d H:i:s');
        
        $this->SysUsers->save($ent_user);
        
        
        $message_key = 'USER_APPROVED_INJECTOR';

        $this->loadModel('SpaLiveV1.CatNotifications');
        $ent_notification = $this->CatNotifications->find()->where(['CatNotifications.title' => $message_key])->first();
         
        if (!empty($ent_notification)) {
            $conf_subject = $ent_notification['subject'];
            $conf_body = $ent_notification['body'];
            $conf_body_push = $ent_notification['body_push'];

            $data = array(
                'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'to'    => $ent_user->email,
                'subject' => $conf_subject,
                'html'    => $conf_body,
            );

            $mailgunKey = $this->getMailgunKey();

            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);

            $result = curl_exec($curl);

            curl_close($curl);
        }


        // DEFAULT TREATMENTS

        //DataTreatmentsPrice
        /*
        List Jeuveau first  ( default to 11 per)
        List Botox second (default to 12 per)
        List Xeomin last. ( default to 11 per)
        */

        $this->loadModel('SpaLiveV1.DataTreatmentsPrice');
        $this->loadModel('SpaLiveV1.DataScheduleModel');

        $this->DataTreatmentsPrice->updateAll(
            ['deleted'   => 1], ['user_id' => $user_id]
        );

        $arr_prices = array();

        $arr_prices[] = array(
            'user_id' => $user_id,
            'treatment_id' => 4, //Juveau
            'price' => 1100, 
            'deleted' => 0,
            'created' => $user_id
        );


        $arr_prices[] = array(
            'user_id' => $user_id,
            'treatment_id' => 1, //Xeomin
            'price' => 1100, 
            'deleted' => 0,
            'created' => $user_id
        );

        $arr_prices[] = array(
            'user_id' => $user_id,
            'treatment_id' => 2, // Botox
            'price' => 1200, 
            'deleted' => 0,
            'created' => $user_id
        );

    

        foreach ($arr_prices as $row) {
            $cq_entity = $this->DataTreatmentsPrice->newEntity($row);
            if(!$cq_entity->hasErrors()){
                $this->DataTreatmentsPrice->save($cq_entity);
            }
        }

        $array_save_m = array(
            'injector_id' => $user_id,
            'days' => 'MONDAY,TUESDAY,WEDNESDAY,THURSDAY,FRIDAY',
            'time_start' => 8,
            'time_end' => 20,
            'model' => 'injector'
        );

        $m_entity = $this->DataScheduleModel->newEntity($array_save_m);
        if(!$m_entity->hasErrors()) {
            $this->DataScheduleModel->save($m_entity);    
            
        }

        $this->success();

    }

