    public function summarySubscriptions(){
        //PAYMENT METHODS
        $this->loadModel('SpaLiveV1.DataSubscriptionMethodPayments');
        $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
        $this->loadModel('SpaLiveV1.DataSubscriptions');

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $entSubs = $this->DataSubscriptions->find()->where(['DataSubscriptions.user_id' => USER_ID, 'DataSubscriptions.status IN' => array('ACTIVE', 'HOLD'), 'DataSubscriptions.deleted' => 0])->all();
        
        if(!empty($entSubs)){
            $array_result = array();
            $array_result2 = array();
            foreach($entSubs as $sub){
                
                $nextPay = '';
                $entPayment =  $this->DataSubscriptionPayments->find()->where(['DataSubscriptionPayments.subscription_id' => $sub->id])->order(['DataSubscriptionPayments.id' => 'DESC'])->first();
                $this->loadModel('SpaLiveV1.DataSubscriptionCancelled');
                $entCancelled = $this->DataSubscriptionCancelled
                    ->find()
                    ->where([
                        'DataSubscriptionCancelled.subscription_id' => $sub->id,
                        'DataSubscriptionCancelled.deleted' => 0 
                    ])
                    ->order(['DataSubscriptionCancelled.id' => 'DESC'])
                    ->first();
                $tmp_date = null;            
                if(!empty($entPayment)){
                    $tmp_date = $entPayment->created->i18nFormat('dd-MM-yyyy');
                }else{
                    $tmp_date = $sub->created->i18nFormat('dd-MM-yyyy');
                }

                $subs_day = $sub->created->i18nFormat('dd');
                $last_day = date('t', strtotime($tmp_date));
                $day_pay = date('d', strtotime($tmp_date));
                $month_pay = date('m', strtotime($tmp_date));
                $year = date('Y', strtotime($tmp_date));
                $month_next = $month_pay < 12 ? $month_pay + 1 : 1;
                $next_year = $month_next == 1 ? $year + 1 : $year;
                $month_next_last_day = date('t', strtotime($next_year . '-' . $month_next . '-01'));

                if($day_pay <= $month_next_last_day){
                    $nextPay = $month_next . '-' . $day_pay . '-' . $next_year;
                }else{;
                    $nextPay = $month_next . '-' . $month_next_last_day . '-' . $next_year;
                }

                if(!empty($entPayment) && $day_pay != $subs_day && $subs_day > 28 && $last_day == $day_pay){
                    if($subs_day <= $month_next_last_day){
                        $nextPay = $month_next . '-' . $subs_day . '-' . $next_year;
                    }else{
                        $nextPay = $month_next . '-' . $month_next_last_day . '-' . $next_year;
                    }
                }
                $array_subs = array(
                    'id' => $sub->id,
                    'subtotal' => $sub->subtotal,
                    'total' => $sub->total,
                    'status' => $sub->status,
                    'created' => date('m-d-Y', strtotime($sub->created->i18nFormat('dd-MM-yyyy'))),
                    'type' => $sub->subscription_type == 'SUBSCRIPTIONMD' || $sub->subscription_type == 'SUBSCRIPTIONMD+IVT' ? 'Medical Director subscription' : 'MySpaLive subscription',
                    'nextPay' => $nextPay,
                );
                if(!empty($entCancelled)){
                    $array_subs['cancelled'] = true;
                    $array_subs['cancelled_date'] = date('m/d/Y', strtotime($entCancelled->date_payment->i18nFormat('dd-MM-yyyy')));                   
                }
                array_push($array_result, $array_subs);
            }
            $have_trainings = false;

            $this->loadModel('SpaLiveV1.DataTrainings');

            $now = date('Y-m-d H:i:s');

            $ent_data_training = $this->DataTrainings->find()->join([
                'CatTrainigs' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainigs.id = DataTrainings.training_id'],
            ])->where(
                [
                    'CatTrainigs.level' => 'LEVEL 1',
                    'DataTrainings.user_id' => USER_ID,
                    'DataTrainings.deleted' => 0, 
                    '(DATE_FORMAT(CatTrainigs.scheduled, "%Y-%m-%d 09:00:00") < "' . $now . '")',
                    'CatTrainigs.deleted' => 0
                ]
            )->first();
            if (!empty($ent_data_training)){
                $have_trainings = true;
            }

            if(count($array_result) == 0){
                if($have_trainings){
                    $array_result2 = array(
                        array(
                            'title' => 'Medical Director subscription',
                            'type' => 'SUBSCRIPTIONMD',
                            'total' => $this->total_subscriptionmd 
                        ),
                        array(
                            'title' => 'MySpaLive subscription',
                            'type' => 'SUBSCRIPTIONMSL',
                            'total' => $this->total_subscriptionmsl 
                        )
                    );
                }else{
                    $array_result2 = array();
                }
            }else if(count($array_result) == 1){
                if($array_result[0]['type'] == 'Medical Director subscription'){
                    array_push($array_result2, array(
                        'title' => 'MySpaLive subscription',
                        'type' => 'SUBSCRIPTIONMSL',
                        'total' => $this->total_subscriptionmsl 
                    ));
                }else{
                    if(!$have_trainings){
                        array_push($array_result2, array(
                            'title' => 'Medical Director subscription',
                            'type' => 'SUBSCRIPTIONMD',
                            'total' => $this->total_subscriptionmd,
                        ));
                    }
                }
            }
            $this->set('subscriptions', $array_result);
            $this->set('subscriptionsoff', []);
        }

        $methods_array = array();
        $preferred_method = '';
        $entMethod = $this->DataSubscriptionMethodPayments->find()->where(['DataSubscriptionMethodPayments.user_id' => USER_ID, 'DataSubscriptionMethodPayments.deleted' => 0])->first();
        if (!empty($entMethod)) {
            $preferred_method = $entMethod->payment_id;
        }

        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));
        
        $oldCustomer = $stripe->customers->all([
            "email" => USER_EMAIL,
            "limit" => 1,
        ]);

        if (count($oldCustomer) > 0) {
           $customer = $oldCustomer->data[0];  

           $payment_methods = $stripe->customers->allPaymentMethods(
                $customer->id,
                ['type' => 'card']
            );
            
            if (empty($entMethod) && count($payment_methods) > 0) {

                 $array_save = array(
                    'user_id' => USER_ID,
                    'payment_id' => $payment_methods->data[0]->id,
                    'preferred' => 1,
                    'error' => 0,
                    'created' => date('Y-m-d H:i:s')
                );
                $preferred_method = $payment_methods->data[0]->id;
                $c_entity = $this->DataSubscriptionMethodPayments->newEntity($array_save);
                if(!$c_entity->hasErrors()) $this->DataSubscriptionMethodPayments->save($c_entity);
            }

            $preferred_ = false;
            foreach($payment_methods as $method) {
                $preferred = $method->id == $preferred_method ? 1 : 0;
                if($preferred == 1) $preferred_ = true;
                $methods_array[] = array(
                    'id' => $method->id,
                    'name' => strtoupper($method->card->brand) . ' ' . 'XXXX' . $method->card->last4,
                    'preferred' => $preferred,
                    'error' => $preferred == 1 && !empty($entMethod) ? $entMethod->error : 0
                ); 
            } 
            
            if (!$preferred_ && count($payment_methods) > 0) {

                $entMethod->payment_id = $payment_methods->data[0]->id;
                $entMethod->error = 0;
                $entMethod->created = date('Y-m-d H:i:s');
                $entMethod->deleted = 0;
                $entMethod->preferred = 1;
                $this->DataSubscriptionMethodPayments->save($entMethod);

                $methods_array[0]['preferred'] = 1;
            }

            if(!empty($entMethod) && count($payment_methods) <= 0){
                $this->loadModel('SpaLiveV1.DataSubscriptions');
                $ent_subscription = $this->DataSubscriptions->find()->where([
                    'DataSubscriptions.subscription_type IN' => array('SUBSCRIPTIONMSL','SUBSCRIPTIONMD'),
                    'DataSubscriptions.user_id' => USER_ID,
                    'DataSubscriptions.status' => 'ACTIVE',
                    'DataSubscriptions.deleted' => 0
                ])->all();
                /*if(count($ent_subscription) > 0){
                    foreach($ent_subscription as $subscription){
                        $this->DataSubscriptions->updateAll(
                            ['status' => 'HOLD'], 
                            ['id' => $subscription->id]
                        );
                    }
                }*/
            }
        } 
        
        array_multisort(array_column($methods_array,'preferred'), SORT_DESC, $methods_array);
        
        $this->set('methods', $methods_array);

        $this->success();
    }

    public function create_payment_method_setup() {

       $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        \Stripe\Stripe::setApiKey(Configure::read('App.stripe_secret_key'));
        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));    

        $stripe_user_email = $user['email'];
        $stripe_user_name = $user['name'];
 
        $oldCustomer = $stripe->customers->all([
            "email" => $stripe_user_email,
            "limit" => 1,
        ]);

        if (count($oldCustomer) == 0) {
            $customer = $stripe->customers->create([
                'description' => $stripe_user_name,
                'email' => $stripe_user_email,
            ]);
        } else $customer = $oldCustomer->data[0];

        $intent = \Stripe\SetupIntent::create([
          'customer' => $customer['id'],
        ]);

        $client_secret = $intent->client_secret;
        
        $this->set('secret', $client_secret);

        $this->success();
    }

    public function create_payment_method_check(){

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        \Stripe\Stripe::setApiKey(Configure::read('App.stripe_secret_key'));
        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        $stripe_user_email = $user['email'];
        $stripe_user_name = $user['name'];
        $userType = str_replace('+', '-', USER_TYPE);

        $oldCustomer = $stripe->customers->all([
            "email" => $stripe_user_email,
            "limit" => 1,
        ]);

        if (count($oldCustomer) == 0) {
            $customer = $stripe->customers->create([
                'description' => $stripe_user_name,
                'email' => $stripe_user_email,
            ]);
        } else $customer = $oldCustomer->data[0];

        $session = \Stripe\Checkout\Session::create([
            'payment_method_types' => ['card'],
            'mode' => 'setup',
            'customer' => $customer['id'],
            'success_url' => $this->URL_WEB . $userType . '/account',
            'cancel_url' => $this->URL_WEB . $userType . '/account',
        ]);
        
        $this->set('url', $session->url);
        $this->set('id', $session->id);
        $this->success();
    }

    public function update_payment_method() {
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $payment_method_id = get('id','');

        if (empty($payment_method_id)) {
            $this->message('Invalid payment method.');
            return;
        }
        
        $this->loadModel('SpaLiveV1.DataSubscriptionMethodPayments');

        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        $stripe_pm = $stripe->paymentMethods->retrieve(
          $payment_method_id,
          []
        );

        $oldCustomer = $stripe->customers->all([
            "email" => USER_EMAIL,
            "limit" => 1,
        ]);

        if ($stripe_pm->customer != $oldCustomer->data[0]->id) {
            $this->message('Invalid payment method.');
            return;
        }

        $entMethod = $this->DataSubscriptionMethodPayments->find()->where(['DataSubscriptionMethodPayments.user_id' => USER_ID, 'DataSubscriptionMethodPayments.deleted' => 0])->first();
        if (!empty($entMethod)) {
            $entMethod->payment_id = $payment_method_id;
            $entMethod->error = 0;
            $entMethod->created = date('Y-m-d H:i:s');
            $entMethod->deleted = 0;
            $entMethod->preferred = 1;
            $this->DataSubscriptionMethodPayments->save($entMethod);

            $this->success();
        } else {
            $array_save = array(
                'user_id' => USER_ID,
                'payment_id' => $payment_method_id,
                'preferred' => 1,
                'error' => 0,
                'created' => date('Y-m-d H:i:s')
            );

            $c_entity = $this->DataSubscriptionMethodPayments->newEntity($array_save);
            if(!$c_entity->hasErrors()) {
                if ($this->DataSubscriptionMethodPayments->save($c_entity)) {
                    $this->success();
                }
            }
        }
    
    }

    public function delete_payment_method() {

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $payment_method_id = get('id','');

        if (empty($payment_method_id)) {
            $this->message('Invalid payment method.');
            return;
        }
        
        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        $stripe_pm = $stripe->paymentMethods->retrieve(
            $payment_method_id,
            []
        );

        $oldCustomer = $stripe->customers->all([
            "email" => USER_EMAIL,
            "limit" => 1,
        ]);

        if ($stripe_pm->customer != $oldCustomer->data[0]->id) {
            $this->message('Invalid payment method.');
            return;
        }

        $stripe->paymentMethods->detach(
            $payment_method_id,
                []
        );            

        $this->success();
    }

    public function getPaymentSubscription(){
        $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
        $this->loadModel('SpaLiveV1.DataSubscriptions');

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $subscription_id = get('subscription_id', 0);

        $entPayment =  $this->DataSubscriptionPayments->find()->where(['DataSubscriptionPayments.subscription_id' => $subscription_id,'DataSubscriptionPayments.deleted' => 0])->order(['DataSubscriptionPayments.id' => 'DESC'])->all();


        if(!empty($entPayment)){
            $array_result = array();

            foreach($entPayment as $item){
                array_push($array_result, array(
                    'id' => $item->id,
                    'user_id' => $item->user_id,
                    'subscription_id' => $item->subscription_id,
                    'total' => $item->total,
                    'payment_id' => $item->payment_id,
                    'charge_id' => $item->charge_id,
                    'receipt_id' => $item->receipt_id,
                    'created' => date('m-d-Y', strtotime($item->created->i18nFormat('dd-MM-yyyy'))),
                ));
            }
            $this->set('payments', $array_result);
        }

        $entSubs = $this->DataSubscriptions->find()->where(['DataSubscriptions.id' => $subscription_id])->first();

        if(!empty($entSubs)){
            $nextPay = '';
            $entPayment =  $this->DataSubscriptionPayments->find()->where(['DataSubscriptionPayments.subscription_id' => $entSubs->id])->order(['DataSubscriptionPayments.id' => 'DESC'])->first();
            if(!empty($entPayment)){
                $date = date('m-d-Y', strtotime($entPayment->created->i18nFormat('dd-MM-yyyy')."+ 1 month"));
                $nextPay = $date;
            }else{
                $date = date('m-d-Y', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy')."+ 1 month"));
                $nextPay = $date;
            }
            $data = array(
                'id' => $subscription_id,
                'title' => $entSubs->subscription_type == 'SUBSCRIPTIONMD' ? 'Medical Director subscription' : 'MySpaLive Subscription',
                'subtotal' => $entSubs->subtotal,
                'total' => $entSubs->total,
                'nextPay' => $nextPay,
                'created' => date('m-d-Y', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy'))),
            );
            $this->set('data', $data);
        }

        $this->loadModel('SpaLiveV1.DataSubscriptionCancelled');
        $entCancelled = $this->DataSubscriptionCancelled
            ->find()
            ->where([
               'DataSubscriptionCancelled.subscription_id' => $subscription_id,
               'DataSubscriptionCancelled.deleted' => 0 
            ])
            ->order(['DataSubscriptionCancelled.id' => 'DESC'])
            ->first();
        if(!empty($entCancelled)){
            $this->set('cancelled', true);
            $this->set('cancelled_date', date('m-d-Y', strtotime($entCancelled->date_payment->i18nFormat('dd-MM-yyyy'))));   
        }
        $this->success();
    }

    public function deleteSubscription(){ 
        $this->loadModel('SpaLiveV1.DataSubscriptions');
        $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
        $this->loadModel('SpaLiveV1.DataSubscriptionCancelled');
        $this->loadModel('SpaLiveV1.DataAgreements');

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $subscription_id = get('subscription_id', 0);
        $reason = get('reason', '');
        $services_unsubscribe = get('services_unsubscribe', '');
        $type = get('type', 0);

        $datas = $this->DataSubscriptionCancelled->find()->where(['DataSubscriptionCancelled.subscription_id' => $subscription_id, 'DataSubscriptionCancelled.deleted' => 0])->first();
        if(!empty($datas)){
            $this->message('Your cancellation has been scheduled succesfully.');
            $this->success();
            return;
        }
        
        $entSubs = $this->DataSubscriptions->find()->where(['DataSubscriptions.id' => $subscription_id,])->first();

        if(!empty($entSubs)){
            $nextPay = '';
            $entPayment =  $this->DataSubscriptionPayments->find()->where(['DataSubscriptionPayments.subscription_id' => $subscription_id])->order(['DataSubscriptionPayments.id' => 'DESC'])->first();
            $endPay = '';
            $today = date('Y-m-d H:i:s'); 
            if(!empty($entPayment)){
                if($type == 1){
                    $date = date('Y-m-d H:i:s', strtotime($entPayment->created->i18nFormat('dd-MM-yyyy')."+ 1 month"));
                    $nextPay = $date;
                    $endPay = date('Y-m-d H:i:s', strtotime($entPayment->created->i18nFormat('dd-MM-yyyy')));
                }else{
                    $date = date('Y-m-d H:i:s', strtotime($entPayment->created->i18nFormat('dd-MM-yyyy')."+ 2 month"));
                    $nextPay = $date;
                    $endPay = date('Y-m-d H:i:s', strtotime($entPayment->created->i18nFormat('dd-MM-yyyy')));
                }
            }else{
                if($type == 1){
                    $date = date('Y-m-d H:i:s', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy')."+ 1 month"));
                    $nextPay = $date;
                    $endPay = date('Y-m-d H:i:s', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy')));
                }else{
                    $date = date('Y-m-d H:i:s', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy')."+ 2 month"));
                    $nextPay = $date;
                    $endPay = date('Y-m-d H:i:s', strtotime($entSubs->created->i18nFormat('dd-MM-yyyy')));
                }
            }
            $entsubcancel = array(
                'subscription_id' => $subscription_id,
                'date_cancelled' => $today, //$endPay,
                'date_payment' => $nextPay,
                'created' => $today,
                'deleted' => 0,
                'modified' => $today,
                'reason' => $reason,
                'services_unsubscribe' => $services_unsubscribe,
            );
            $array_str_subscriptions = [
                'SUBSCRIPTIONMSL' => 'MySpaLive Subscription','SUBSCRIPTIONMD' => 'Medical Director Subscription'
            ];
            $c_entity = $this->DataSubscriptionCancelled->newEntity($entsubcancel);
            if(!$c_entity->hasErrors()) {                
                $this->DataSubscriptionCancelled->save($c_entity);
                $this->success();
                if(isset($array_str_subscriptions[$entSubs->subscription_type])){
                    $st = $array_str_subscriptions[$entSubs->subscription_type];
                }else{
                    $st = 'MySpaLive Subscription '. $entSubs->subscription_type;
                }                 
                $this->sendUnsubscriptionEmail('EMAIL_SUBSCRIPTION_CANCELLATION_REQUEST', USER_EMAIL, $st);                                
            }
        }
    }

    private function requestSubscriptions() {

        $this->loadModel('SpaLiveV1.SysUsers');

        $allow_treatments = true;
        $show_subscriptions = false;
        $have_trainings = false;

        $this->loadModel('SpaLiveV1.CatLabels');

        $this->loadModel('SpaLiveV1.DataTrainings');

        $now = date('Y-m-d H:i:s');

        $ent_data_training = $this->DataTrainings->find()->join([
            'CatTrainigs' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainigs.id = DataTrainings.training_id'],
        ])->where(
            [
                'CatTrainigs.level' => 'LEVEL 1',
                'DataTrainings.user_id' => USER_ID,
                'DataTrainings.deleted' => 0, 
                '(DATE_FORMAT(CatTrainigs.scheduled, "%Y-%m-%d 09:00:00") < "' . $now . '")',
                'CatTrainigs.deleted' => 0
            ]
        )->first();
        if (!empty($ent_data_training)){
            $have_trainings = true;
        }

        
        $ent_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();

        $ent_agreement = $this->CatAgreements->find()->select(['CatAgreements.uid','DataAgreement.id','DataAgreement.deleted', 'DataSubscriptions.status'])->join([
                'DataAgreement' => ['table' => 'data_agreements', 'type' => 'LEFT', 'conditions' => 'CatAgreements.uid = DataAgreement.agreement_uid AND DataAgreement.user_id = ' . USER_ID. ' AND DataAgreement.deleted = 0'],
                'DataSubscriptions' => ['table' => 'data_subscriptions', 'type' => 'LEFT', 'conditions' => 'DataSubscriptions.user_id='. USER_ID.' AND DataSubscriptions.deleted =  0 AND DataSubscriptions.subscription_type = "SUBSCRIPTIONMSL" AND DataSubscriptions.status IN ("ACTIVE", "HOLD") '],
            ])->where(
            [
                'CatAgreements.state_id' => $ent_user->state,
                'CatAgreements.user_type' => $ent_user->type == 'gfe+ci' ? 'injector' : $ent_user->type,
                'CatAgreements.agreement_type' => 'SUBSCRIPTIONMSL',
                'CatAgreements.deleted' => 0
            ]
        )->first();



        if (!empty($ent_agreement) && empty($ent_agreement['DataAgreement']['id'])) {
            $str_text = '';
            $ent_labels = $this->CatLabels->find()->where(['CatLabels.key_field' => 'ci_subscribe_msl_copy','CatLabels.deleted' => 0])->first();
            if (!empty($ent_labels)) {
                $str_text = $ent_labels->value;
                // if ($have_trainings) $str_text .= ' Use our promo code 50OFFSPA';
            }
            if($have_trainings){
                $this->set('request_subscription_msl', array('display' => true, 'price' => $this->total_subscriptionmsl, 'uid' => $ent_agreement['uid'],'type' => 'SUBSCRIPTIONMSL', 'label' => $str_text, 'status' => '', 'hide' => false));
            }else{
                $this->set('request_subscription_msl', array('display' => true, 'price' => $this->total_subscriptionmsl, 'uid' => $ent_agreement['uid'],'type' => 'SUBSCRIPTIONMSL', 'label' => $str_text, 'status' => '' , 'hide' => true));
            }
            $allow_treatments = false;
            $show_subscriptions = true;
            
        } else {
            $str_status_msl = !empty($ent_agreement['DataSubscriptions']['status']) ? $ent_agreement['DataSubscriptions']['status']  : "" ;
            if($str_status_msl == 'HOLD'){
                $allow_treatments = false;
            }
            $this->set('request_subscription_msl', array('display' => false, 'price' => $this->total_subscriptionmsl, 'uid' => '','type' => 'SUBSCRIPTIONMSL', 'status' => $str_status_msl, 'hide' => false));
        }

       

        $ent_agreement = $this->CatAgreements->find()->select(['CatAgreements.uid','DataAgreement.id','DataAgreement.deleted', 'DataSubscriptions.status'])->join([
                'DataAgreement' => ['table' => 'data_agreements', 'type' => 'LEFT', 'conditions' => 'CatAgreements.uid = DataAgreement.agreement_uid AND DataAgreement.user_id = ' . USER_ID. ' AND DataAgreement.deleted = 0'],
                'DataSubscriptions' => ['table' => 'data_subscriptions', 'type' => 'LEFT', 'conditions' => 'DataSubscriptions.user_id='. USER_ID.' AND DataSubscriptions.deleted =  0 AND DataSubscriptions.subscription_type = "SUBSCRIPTIONMD" '],
                ])->where(
            [
                'CatAgreements.state_id' => $ent_user->state,
                'CatAgreements.user_type' => $ent_user->type == 'gfe+ci' ? 'injector' : $ent_user->type,
                'CatAgreements.agreement_type' => 'SUBSCRIPTIONMD',
                'CatAgreements.deleted' => 0
            ]
        )->first();

        
        if (!empty($ent_agreement) && empty($ent_agreement['DataAgreement']['id'])) {
            $str_text = '';
            $ent_labels = $this->CatLabels->find()->where(['CatLabels.key_field' => 'ci_subscribe_md_copy','CatLabels.deleted' => 0])->first();
            if (!empty($ent_labels)) {
                $str_text = $ent_labels->value;
            }
            if($have_trainings){
                $this->set('request_subscription_md', array('display' => true, 'price' => $this->total_subscriptionmd, 'uid' => $ent_agreement['uid'],'type' => 'SUBSCRIPTIONMD', 'label' => $str_text, 'status' => '', 'hide' => false));
            }
            else{
                $this->set('request_subscription_md', array('display' => true, 'price' => $this->total_subscriptionmd, 'uid' => $ent_agreement['uid'],'type' => 'SUBSCRIPTIONMD', 'label' => $str_text, 'status' => '', 'hide' => true));
            }
            $allow_treatments = false;
            $show_subscriptions = true;

        } else {
            $str_status_md = !empty($ent_agreement['DataSubscriptions']['status']) ? $ent_agreement['DataSubscriptions']['status']  : "" ;
            if($str_status_md == 'HOLD'){
                $allow_treatments = false;
            }
            $this->set('request_subscription_md', array('display' => false, 'price' => $this->total_subscriptionmd, 'uid' => '','type' => 'SUBSCRIPTIONMD', 'status' => $str_status_md, 'hide' => false));
        }

        if (!$this->checkTrainings()) {
            $show_subscriptions = false;
            $allow_treatments = false;
        }


        $this->set('allow_treatments', $allow_treatments);
        $this->set('show_subscriptions', $show_subscriptions);
    }

    public function requestTreatmentSuccess(){
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $uid = get('uid', '');

        if($uid == ''){
            $this->message('Invalid Uid');
            return;
        }

        $this->loadModel('SpaLiveV1.DataTreatment');

        if(USER_TYPE == 'injector'){
            $fields = ['DataTreatment.uid','DataTreatment.schedule_date','DataTreatment.amount', 'DataTreatment.patient_id','DataTreatment.assistance_id','DataTreatment.tip','DataTreatment.promo_code','User.name','User.lname', 'Total.total'];
            $_where = ['DataTreatment.uid' => $uid];

            $certTreatment = $this->DataTreatment->find()->select($fields)
            ->join([
                'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTreatment.patient_id'],
                'Total' => ['table' => 'data_payment', 'type' => 'INNER', 'conditions' => 'Total.uid = DataTreatment.uid AND Total.receipt = DataTreatment.receipt_url'],
            ])->where($_where)->first();

            if(!empty($certTreatment)){

                $total_amount = $this->validateCode(get('promo_code',''),$certTreatment->amount,'TREATMENT',$certTreatment);

                $array_result = array(
                    'uid' => $certTreatment->uid,
                    'amount' => $total_amount,
                    'tip' => $certTreatment->tip,
                    'patient' => $certTreatment['User']['name'] . ' ' . $certTreatment['User']['lname'],
                    'total' => $certTreatment['Total']['total']
                );
                $this->set('data', $array_result);
                $this->success();
            }
        } else if(USER_TYPE == 'patient'){
            $fields = ['DataTreatment.uid','DataTreatment.schedule_date','DataTreatment.amount','DataTreatment.assistance_id','DataTreatment.patient_id','DataTreatment.tip','DataTreatment.promo_code','User.name','User.lname'];
            $_where = ['DataTreatment.uid' => $uid];

            $certTreatment = $this->DataTreatment->find()->select($fields)
            ->join([
                'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTreatment.assistance_id'],
            ])->where($_where)->first();

            if(!empty($certTreatment)){

                $total_amount = $this->validateCode(get('promo_code',''),$certTreatment->amount,'TREATMENT', $certTreatment);

                $array_result = array(
                    'uid' => $certTreatment->uid,
                    'amount' => $total_amount,
                    'tip' => $certTreatment->tip,
                    'injector' => $certTreatment['User']['name'] . ' ' . $certTreatment['User']['lname']   
                );

                $this->set('data', $array_result);
                $this->success();
            }
        }
    }

