    public function cat_treatments(){

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            $this->set('session', true);
        } 


        $this->loadModel('SpaLiveV1.CatTreatments');
         $ent_treatments = $this->CatTreatments->find()->where(['CatTreatments.deleted' => 0])->order(['CatTreatments.type_trmt','CatTreatments.id'])->all();
        if(!empty($ent_treatments)){

            $result = array();
            foreach ($ent_treatments as $row) {
                $result[] = array(
                    'id' => $row['id'],
                    'parent_id' => $row['parent_id'],
                    'name' => $row['name'],
                    'details' => $row['details'],
                    'haschild' => $row['haschild'],
                    'name_spanish' => $row['name'] == 'Botox & other neurotoxins' ? 'Botox y otras neurotoxinas' : $row['name'],
                    'selected' => false,
                );
                
            }
        }


        
        if (defined('USER_TYPE')) {
            switch (USER_TYPE) {
                case 'patient':
                    $str_query_ = "
                        SELECT GROUP_CONCAT(DISTINCT CT.name) treatments
                        FROM data_consultation_plan DCP
                        JOIN data_consultation DC ON DC.id = DCP.consultation_id
                        JOIN data_certificates DCE ON DCE.consultation_id = DC.id
                        JOIN cat_treatments CT ON CT.id = DCP.treatment_id
                        WHERE 
                        
                        DCP.proceed = 1
                        AND NOW() < DCE.date_expiration
                        AND DC.patient_id = " . USER_ID;
                    


                    $result_query = $this->CatTreatments->getConnection()->execute($str_query_)->fetchAll('assoc');
                    $str_treatments = '';
                    foreach($result_query as $row) {
                        $str_treatments = $row['treatments'];
                    }
                    
                    $this->set('treatments', isset($str_treatments) ? $str_treatments : '');

                    // Change ids in result to string
                    foreach ($result as $key => $row) {
                        $result[$key]['id'] = strval($row['id']);
                    }

                    $ent_treatments_pat = $this->CatTreatments
                    ->find()
                    ->join([
                        'DataConsultationPlan' => ['table' => 'data_consultation_plan', 'type' => 'INNER', 'conditions' => 'DataConsultationPlan.treatment_id = CatTreatments.id'],
                        'DataConsultation' => ['table' => 'data_consultation', 'type' => 'INNER', 'conditions' => 'DataConsultation.id = DataConsultationPlan.consultation_id'],
                    ])
                    ->where([
                        'CatTreatments.deleted' => 0,
                        'DataConsultation.deleted' => 0,
                        'DataConsultation.patient_id' => USER_ID,
                    ])
                    ->order(['CatTreatments.type_trmt','CatTreatments.id'])
                    ->group(['CatTreatments.id'])
                    ->all();
                    if(count($ent_treatments_pat) != 0){
                        $this->loadModel('SpaLiveV1.DataTreatment');
                        $ent_treatment = $this->DataTreatment
                        ->find()
                        ->where(['DataTreatment.deleted' => 0, 'DataTreatment.patient_id' => USER_ID])
                        ->order(['DataTreatment.id' => 'DESC'])
                        ->first();

                        if(!empty($ent_treatment)){
                            $str_treatments = $ent_treatment->treatments;
                            
                            $arr_treat = explode(',', $str_treatments);
                            $this->loadModel('SpaLiveV1.CatTreatmentsCi');
                            $ent_treatment = $this->CatTreatmentsCi
                            ->find()
                            ->where(['CatTreatmentsCi.deleted' => 0, 'CatTreatmentsCi.id IN' => $arr_treat])
                            ->all();

                            $arr_ids = array();
                            foreach ($ent_treatment as $row) {
                                $arr_ids[] = $row->treatment_id;
                            }
                            //$this->set('arr_ids', implode(',', $arr_ids));

                            $ent_treatments = $this->CatTreatments
                            ->find()
                            ->where(['CatTreatments.deleted' => 0, 'CatTreatments.id IN' => $arr_ids])
                            ->order(['CatTreatments.type_trmt','CatTreatments.id'])
                            ->all();
                        }
                    }
                        //$this->set('treatments', $ent_treatments);return;
                        $combinedIds = [];
                        $containsFill = false;
                        $containsNeu = false;

                        // Recorrer el arreglo
                        foreach ($ent_treatments as $treatment) {
                            // Verificar si el id está en la lista
                            if (in_array($treatment['id'], [92, 93])) {
                                // Agregar el id a la lista combinada
                                $combinedIds[] = $treatment['id'];
                        
                                // Marcar que ambos IDs están presentes
                                if (in_array(92, $combinedIds)) {
                                    $containsNeu = true;
                                }
                                if (in_array(93, $combinedIds)) {
                                    $containsFill = true;
                                }
                            }
                        }

                        if ($containsNeu && $containsFill) {
                            foreach ($result as $key => $row) {
                                if ($row['id'] == 1) {
                                    unset($result[$key]);
                                }
                                if (in_array($row['id'], $combinedIds)) {
                                    // Eliminar el elemento de la lista
                                    unset($result[$key]);
                                }
                            }
                        } else if ($containsNeu && !$containsFill) {
                            break;
                        } else if (!$containsNeu && $containsFill) {
                            foreach ($result as $key => $row) {
                                if ($row['id'] == 1) {
                                    unset($result[$key]);
                                }
                                if (in_array($row['id'], $combinedIds)) {
                                    // Eliminar el elemento de la lista
                                    unset($result[$key]);
                                }
                            }
                            // Crear el nuevo elemento
                            $newElement = [
                                'id' => implode(',', $combinedIds),
                                'parent_id' => 0,
                                'name' => 'Fillers',
                                'details' => 0,
                                'haschild' => 0,
                                'name_spanish' => 'Rellenos',
                                'selected' => false,
                            ];
                            array_unshift($result, $newElement);
                            break;
                        }


                        // Crear el nuevo elemento sin índices
                        $newElement = [
                            'id' => implode(',', $combinedIds),
                            'parent_id' => 0,
                            'name' => 'Neurotoxins & Fillers',
                            'details' => 0,
                            'haschild' => 0,
                            'name_spanish' => 'Neurotoxinas y Rellenos',
                            'selected' => false,
                        ];

                        // Agregar el nuevo elemento al inicio del arreglo
                        array_unshift($result, $newElement);
                    break;
                case 'examiner' || 'gfe+ci':
                    $this->loadModel('SpaLiveV1.DataConsultation');
                    $cons_arr = $this->DataConsultation->find()->select(['DataConsultation.id', 'DataConsultation.treatments'])
                    ->where(['DataConsultation.assistance_id' => USER_ID, 'DataConsultation.deleted' => 0, 'DataConsultation.uid' => get('consultation_uid', '')])
                    ->order(['DataConsultation.id' => 'DESC'])->first();

                    if (!empty($cons_arr)) {
                        $treatments = explode(',', $cons_arr['treatments']);
                        
                        foreach ($result as $key => $value) {
                            $str_id = strval($value['id']);
                            if (in_array($str_id, $treatments)) {
                                $result[$key]["selected"] = true;
                            }
                        }
                    }
                    break;

            }
        }
        $this->set('data', $result);
        
        $this->success();
    }

