    public function create_checkout_session_suscription() {
        

        $this->loadModel('SpaLiveV1.SysUsers');
        $uid = get('uid', '');
        if(empty($uid)){
            $this->message('uid empty.');
            return;
        }

        $ent_user = $this->SysUsers->find()->select(['SysUsers.id','SysUsers.uid', 'SysUsers.payment_intent','SysUsers.amount','SysUsers.email','SysUsers.name','SysUsers.lname'])
        ->where(['SysUsers.uid' => $uid])->first();
        
        if (empty($ent_user)) {
            $this->message('user not found');
            return;
        }

        $total_amount = $this->validateCode(get('promo_code',''),$this->register_total,'REGISTER');
        
        if ($total_amount < 100) $total_amount = 100;


        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        
        $oldCustomer = $stripe->customers->all([
            "email" => $ent_user['email'],
            "limit" => 1,
        ]);

        if (count($oldCustomer) == 0) {
            $customer = $stripe->customers->create([
                'description' => $ent_user['name'] . ' ' . $ent_user['lname'],
                'email' => $ent_user['email'],
            ]);
        } else $customer = $oldCustomer->data[0];


        $session = \Stripe\Checkout\Session::create([
            'success_url' => $this->URL_WEB . 'registerprocess/success/' . $uid,
            'cancel_url' => $this->URL_WEB . 'registerprocess/fail/' . $uid,
            'mode' => 'subscription',
            'line_items' => [[
              'price' => 'price_1LO61XD0WNkFIbmKTAOHh3m9',
              'quantity' => 1,
            ]],
            'customer' => $customer['id'],
            'metadata' => ['type' => 'subscription', 'uid' => $uid],
          ]);

        // $array_save = array(
        //     'id' => $ent_user->id,
        //     'payment_intent' => $session->payment_intent,
        // );
        $this->SysUsers->updateAll(
            ['payment_intent' => 'da3541w5das3-d4aw65d16a-ad35a4wd6'],
            ['id' => $ent_user->id]
        );

        $this->createPaymentRegister('CI REGISTER', $ent_user->id, 0, $uid, 'da3541w5das3-d4aw65d16a-ad35a4wd6', $this->register_total, $total_amount);

        // $c_entity = $this->SysUsers->newEntity($array_save);
        // if(!$c_entity->hasErrors()) {
        //     if ($this->SysUsers->save($c_entity)) {
                // $this->success();
        //     }
        // }    

        $this->set('id', $session->id);
        $this->set('total', $total_amount);
        $this->success();
    }

    private function requestInjectorSubscriptionAgreement() {

        $this->loadModel('SpaLiveV1.Agreement');
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.CatAgreements');


        $ent_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
        
        $usertype = $ent_user->type == 'gfe+ci' ? 'injector' : $ent_user->type;
        $ent_agreement = $this->CatAgreements->find()->select(['CatAgreements.uid','DataAgreement.id','DataAgreement.deleted'])->join([
