    public function inventory_grid() {

        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->loadModel('SpaLiveV1.SysUsers');
                
        $now = date('Y-m-d H:i:s');

        $ServicesHelper = new ServicesHelper($user["user_id"]);

        $status_advanced = $ServicesHelper->service_status(
            "ADVANCED NEUROTOXINS"                
        );

        $this->loadModel('SpaLiveV1.DataPayment');
        $payment_advanced = $this->DataPayment->find()->where(['DataPayment.id_from' => USER_ID, 'DataPayment.id_to' => 0,'DataPayment.type' => "ADVANCED COURSE", 'DataPayment.service_uid' => '','DataPayment.payment <>' => '', 'DataPayment.is_visible' => 1])->first();
        $payment_medical = $this->DataPayment->find()->where(['DataPayment.id_from' => USER_ID, 'DataPayment.id_to' => 0,'DataPayment.type' => "ADVANCED TECHNIQUES MEDICAL", 'DataPayment.service_uid' => '','DataPayment.payment <>' => '', 'DataPayment.is_visible' => 1])->first();
        $payment_tuneup = $this->DataPayment->find()->where(['DataPayment.id_from' => USER_ID, 'DataPayment.id_to' => 0,'DataPayment.type' => "LEVEL 1-1 NEUROTOXINS", 'DataPayment.service_uid' => '','DataPayment.payment <>' => '', 'DataPayment.is_visible' => 1])->first();
        $payment_filler = $this->DataPayment->find()->where(['DataPayment.id_from' => USER_ID, 'DataPayment.id_to' => 0,'DataPayment.type' => "FILLERS COURSE", 'DataPayment.service_uid' => '','DataPayment.payment <>' => '', 'DataPayment.is_visible' => 1])->first();

        $shop_level_medical = empty($payment_advanced) ? false : true;

        $shop_level_3 = false;

        $filler_check = $this->SysUsers->find()->select(['SysUsers.filler_check'])->where(['SysUsers.id' => USER_ID])->first();

        if ($filler_check->filler_check == 1) {
            $shop_level_3 = true;
        }


        $reference = [
            // 'LASH_ENHACEMENT',
            'CHEMICAL_PEELS',
            'DERMAPLANING',
            'MICRONEEDLING',
            'PEEL',
            // 'FILLERS'
        ];
        $main_conditions = [];
        foreach ($reference as $ref) {
            $main_conditions[] = "DS.main_service LIKE '%" . addslashes($ref) . "%'";
        }
        $addon_conditions = [];
        foreach ($reference as $ref) {
            $addon_conditions[] = "FIND_IN_SET('" . addslashes($ref) . "', REPLACE(DS.addons_services, ', ', ','))";
        }
        $all_conditions = implode(" OR ", array_merge($main_conditions, $addon_conditions));


        $fields = [];
