    public function cat_concierge(){

        $this->loadModel('SpaLiveV1.DataConcierge');
        $ent_treatments = $this->DataConcierge->find()->where(['DataConcierge.deleted' => 0, 'DataConcierge.enabled' => 1])->all();
        if(!empty($ent_treatments)){
            $result = array();
            foreach ($ent_treatments as $row) {
                $result[] = array(
                    'id' => $row['id'],
                    'name' => $row['name'],
                    'desc' => $row['desc'],
                    'email' => $row['email'],
                    'lat' => doubleval($row['lat']),
                    'lon' => doubleval($row['lon']),
                );
                
            }
        }

        $this->set('data', $result);
        $this->success();
    }

    public function set_consultation_scheduled() {

        $this->loadModel('SpaLiveV1.DataConsultation');
        
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $consultation_uid = get('consultation_uid','');

        $this->loadModel('SpaLiveV1.SysUsers');


        $ent_consultation = $this->DataConsultation->find()->where(['DataConsultation.uid' => $consultation_uid])->first();
        if (empty($ent_consultation)) {
            $this->message('Consultation not found.');
            return;
        }

        $this->success();

        $ent_patient = $this->SysUsers->find()->where(['SysUsers.id' => $ent_consultation->patient_id, 'SysUsers.is_test' => 0])->first();
        if(!empty($ent_patient)){
            $constants = [
                '[CNT/PatName]' => trim($ent_patient->name),
                '[CNT/PatLastName]' => trim($ent_patient->lname),
                '[CNT/PatPhone]' => preg_replace('~.*(\d{3})[^\d]{0,7}(\d{3})[^\d]{0,7}(\d{4}).*~', '($1)$2-$3', $ent_patient->phone),
            ];
            $this->set('notif_param', $constants);
            $dataNoti = array(
                'consultation_uid' => $consultation_uid,
                'patient_name' => $ent_patient->name . ' ' . $ent_patient->lname,
                'meeting_number' => $ent_consultation['meeting'],
                'meeting_pass' => $ent_consultation['meeting_pass']
            );

            

            $this->notify_devices('NEW_PATIENT_WAITING_ROOM',array($ent_consultation->assistance_id), true, true, true, $dataNoti,'', $constants, true);

        }

    }

    public function start_consultation_actual(){
        $this->loadModel('SpaLiveV1.DataConsultation'); 
        $this->loadModel('SpaLiveV1.DataConsultationAnswers');
        
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        
        // if (API_KEY == '2fe548d5ae881ccfbe2be3f6237d7952') {
        //     $this->message('Video calls on Android phones are currently undergoing maintenance. Please join via our web app using the following URL: https://app.myspalive.com/');
        //     return;
        // }

        $consultation_uid = get('consultation_uid','');
        if (empty($consultation_uid)) {
            $consultation_uid = Text::uuid();
            $string_answers = get('answers','');
            $arr_answers = json_decode($string_answers,true);   
            
            if (empty($arr_answers)) {
                $this->message('Answers empty.');
                return;
            }
 
            $string_treatments = get('treatments','');
            if (empty($string_treatments)) {
                $this->message('Treatments empty.');
                return;
            }

            $schedule_by = 0;
            $schedule_date = get('schedule_date','');
            if (!empty($schedule_date)) {
                $schedule_by = USER_ID;
            }
            
            if (empty($schedule_date)) 
                $schedule_date = date('Y-m-d H:i:s');


            $createdby = USER_ID;
            $patient_id = USER_ID;
            
            $this->loadModel('SpaLiveV1.SysUsers');
            if ($user['user_role'] == 'clinic' /* || $user['user_role'] == 'injector' || $user['user_role'] == 'gfe+ci'*/) {

                $_patient_id = $this->SysUsers->uid_to_id(get('patient_uid', ''));
                // $this->message($_patient_id);
                if($_patient_id <= 0) {
                    $this->message('The patient does not exist.');
                    return;
                }
                $patient_id = $_patient_id;
            }

            if ($user['user_role'] == 'patient' || $user['user_role'] == 'clinic' || $user['user_role'] == 'injector' || $user['user_role'] == 'gfe+ci') {
                $available = $this->gfeAvailability($schedule_date);

                if ($available) {
                    if ($schedule_by > 0) {
                        $str_now = date('Y-m-d H:i:s');
                        $arr_conditions = [
                            'DataConsultation.status' => 'INIT',
                            'DataConsultation.schedule_by >' => 0,
                            'DataConsultation.patient_id' => $patient_id,
                            'DataConsultation.deleted' => 0,
                        ];
    
                        $arr_conditions[] = "TIMESTAMPDIFF(MINUTE, DataConsultation.schedule_date, '{$str_now}') <= 15";
                        $ent_consultation = $this->DataConsultation->find()
                            ->where($arr_conditions)
                            ->first();
                        
                        if (!empty($ent_consultation)) {
                            $this->success(false);
                            $this->set('has_scheduled_appointment', true);
                            $this->message('You already have a scheduled appointment.');
                            return false;
                        }
                    }
                } else {
                    $this->success(false);
                    $this->message("Our good faith examiners are available Monday-Saturday from 8 a.m - 8 p.m. If you have reached us outside of our business hours, holidays, etc., please feel free to schedule your exam for a specific date and time or reach back out to us during business hours OR (reconnect with us during business hours) Thank you!");
                    $this->set('not_available', true);
                    return false;
                }
            }

             $array_save = array(
                'uid' => $consultation_uid,
                'patient_id' => $patient_id,
                'assistance_id' => 0,
                'treatments' => $string_treatments,
                'payment' => '',
                'meeting' => '',
                'meeting_pass' => '',
                'schedule_date' => $schedule_date,
                'status' => "INIT",
                'schedule_by' => $schedule_by,
                'deleted' => 0,
                'participants' => 0,
                'createdby' => $createdby,
                'clinic_patient_id' => $patient_id,
                'payment_method' => get('payment_method',''),
                'language' => get('language','ENGLISH'),
                // 'name' => $name,
                // 'email' => $email,
                // 'password' => hash_hmac('sha256', $passwd, Security::getSalt()),
                // 'type' => $userType,
                // 'active' => 1,
                // 'confirm' => 1,
                // 'confirm_code' => 0,
                // 'deleted' => 0,
                // 'createdby' => 0,
                // 'modifiedby' => 0,

            );

            $r = $this->generateMeeting($schedule_date);

            if ($r) {
                $array_save['meeting'] = $r['id'];
                $array_save['meeting_pass'] = $r['password'];
                $array_save['join_url'] = $r['join_url'];

            } else {
                return;
            }

            $c_entity = $this->DataConsultation->newEntity($array_save);
            if(!$c_entity->hasErrors()) {
                if ($this->DataConsultation->save($c_entity)) {
                    foreach ($arr_answers as $row) {
                        $arr_save_q = array(
                            'uid' => Text::uuid(),
                            'consultation_id' => $c_entity->id,
                            'question_id' => $row['id'],
                            'response' => $row['response'],
                            'details' => $row['details'],
                            'deleted' => 0
                        );

                        

                        $cq_entity = $this->DataConsultationAnswers->newEntity($arr_save_q);
                        if(!$cq_entity->hasErrors()){
                            $this->DataConsultationAnswers->save($cq_entity);
                        }
                    }
                    
                    $this->success();    
                    

                    //$str_quer = "UPDATE data_consultation SET `status` = 'CANCEL' WHERE patient_id = " . USER_ID . " AND (status = 'ONLINE' OR status = 'INIT') AND schedule_by = 0";
                    // $this->set('schedule_date', $str_quer); return;
                    // $this->DataConsultation->getConnection()->execute($str_quer);

                    // SELECT COUNT(id) FROM data_consultation  WHERE status = \"INIT\"  AND assistance_id = 0  AND schedule_by = 0 AND SU.state = {$examiner_state} 


                    if($user['user_role'] == 'clinic'){
                        $this->loadModel('SpaLiveV1.DataPatientConsult');
                        $saveConsPat = [
                            'consult_id' => $c_entity->id,
                            'patient_clin_id' => $patient_id
                        ];
                        $ent_cons_pat = $this->DataPatientConsult->newEntity($saveConsPat);
                        if(!$ent_cons_pat->hasErrors()) {
                            $this->DataPatientConsult->save($ent_cons_pat);
                            $this->set('uid', $consultation_uid);
                            if ($schedule_by > 0) {
                                $this->set('schedule_date', get('schedule_date',''));
                            }
                        }
                    }

                    $this->set('uid', $consultation_uid);
                    $this->loadModel('SpaLiveV1.SysUsers');
                    $arrUsers = $this->SysUsers->find()->where(['SysUsers.type IN' => array('examiner','gfe+ci'), 'SysUsers.deleted' => 0, 'SysUsers.state' => $user['user_state'], 'SysUsers.login_status' => 'READY','SysUsers.active' => 1])->all();

                    if (Count($arrUsers) > 0) {
                         $arr_ids = array();
                        foreach ($arrUsers as $row) {
                            if ($row['id'] == USER_ID) continue;
                            if ($row['id'] == 18837) continue;
                            if ($row['id'] == 9982) continue; //Kristy Carroll
                            $arr_ids[] = $row['id'];
                        }
                        
                        $arr_ids[] = 9982; // Kristy Carroll
                        $ent_patient = $this->SysUsers->find()->where(['SysUsers.id' => $patient_id, 'SysUsers.is_test' => 0])->first();
                        if(!empty($ent_patient)){
                            $constants = [
                                '[CNT/PatName]' => trim($ent_patient->name),
                                '[CNT/PatLastName]' => trim($ent_patient->lname),
                                '[CNT/PatPhone]' => preg_replace('~.*(\d{3})[^\d]{0,7}(\d{3})[^\d]{0,7}(\d{4}).*~', '($1)$2-$3', $ent_patient->phone),
                            ];
                            $this->set('notif_param', $constants);
                            $dataNoti = array(
                                'consultation_uid' => $consultation_uid,
                                'patient_name' => $ent_patient->name . ' ' . $ent_patient->lname,
                                'meeting_number' => $array_save['meeting'],
                                'meeting_pass' => $array_save['meeting_pass']
                            );
                            if($schedule_by == 0){
                                $this->notify_devices('NEW_PATIENT_WAITING_ROOM',$arr_ids, true, true, true, $dataNoti,'', $constants, true);
                            }else{
                                $dataNoti = array(
                                    'uid' => $consultation_uid,
                                    'action' => 'open_schedule_room'
                                );
                                $this->notify_devices('SCHEDULED_CONSULTATION',$arr_ids, true, true, true, $dataNoti,'', $constants, true);
                            }
                        }
                        
                        $constants_not = [
                            '[CNT/ScheduleDate]' => date("m-d-Y h:i A", strtotime($schedule_date)),
                        ];
                        $this->notify_devices('SCHEDULED_CONSULTATION_CREATEDBY',array($schedule_by), false, true, true, array(),'', $constants_not, false);

                        //change medical director to marie
                        $this->loadModel('SpaLiveV1.SysUserAdmin');
                        $md_id = $this->SysUserAdmin->getAssignedDoctorInjector($ent_patient->id);
                        $pat  = $this->SysUsers->find()->where(['SysUsers.id' => $ent_patient->id])->first();
                        if (!empty($pat)) {
                            $this->SysUsers->updateAll(
                                ['md_id' => $md_id], ['SysUsers.id' => $ent_patient->id]
                            );
                        }
                    } else{
                        $this->message('No examiners available.');
                        $this->success(false);
                    }
                }
            }

        } else {
            // Schedule
            $this->loadModel('SpaLiveV1.SysUsers');

            $consultation_id = $this->DataConsultation->uid_to_id($consultation_uid);
            if (!$consultation_id) {
                $this->message('consultation_uid not found.');
                return;
            }

            $schedule_date = get('schedule_date','');
            if (empty($schedule_date)) {
                $this->message('Invalid schedule date..');
                return;
            }

             $array_save = array(
                'id' => $consultation_id,
                'schedule_date' => $schedule_date,
                'schedule_by' => USER_ID,
                'status' => 'INIT',
                'participants' => 0,
                'is_waiting' => 0,
                'language' => get('language','ENGLISH'),
            );

            $c_entity = $this->DataConsultation->newEntity($array_save);
            if(!$c_entity->hasErrors()) {
                if ($this->DataConsultation->save($c_entity)) {
                    $this->success();

                    $arrUsers = $this->SysUsers->find()->where(['SysUsers.type IN' => array('examiner','gfe+ci'), 'SysUsers.deleted' => 0, 'SysUsers.state' => $user['user_state'], 'SysUsers.login_status' => 'READY','SysUsers.active' => 1])->all();
                    if (!empty($arrUsers)) {
                        $arr_ids = array();
                        foreach ($arrUsers as $row) {
                            if ($row['id'] == USER_ID) continue;
                            if ($row['id'] == 9982) continue; //Kristy Carroll
                            $arr_ids[] = $row['id'];
                        }

                        $arr_ids[] = 9982; // Kristy Carroll

                        $patient_id = USER_ID;
                        $this->loadModel('SpaLiveV1.SysUsers');
                        if ($user['user_role'] == 'clinic' || $user['user_role'] == 'injector' || $user['user_role'] == 'gfe+ci') {
                            $_patient = $this->DataConsultation->find()->where(['DataConsultation.id' => $consultation_id])->first();
                            if(empty($_patient)) {
                                $this->message('The patient does not exist.');
                                return;
                            }
                            $patient_id = $_patient->patient_id;
                        }

                        $ent_patient = $this->SysUsers->find()->where(['SysUsers.id' => $patient_id])->first();
                        $constants = [
                            '[CNT/PatName]' => trim($ent_patient->name),
                            '[CNT/PatLastName]' => trim($ent_patient->lname),
                            '[CNT/PatPhone]' => preg_replace('~.*(\d{3})[^\d]{0,7}(\d{3})[^\d]{0,7}(\d{4}).*~', '($1)$2-$3', $ent_patient->phone),
                        ];
                        
                        $dataNoti = array(
                            'uid' => '',
                            'action' => 'open_schedule_room'
                        );
                        $this->notify_devices('SCHEDULED_CONSULTATION',$arr_ids, true, true, true, $dataNoti,'', $constants, true);
                    }

                    $constants_not = [
                            '[CNT/ScheduleDate]' => date("m-d-Y h:i A", strtotime($schedule_date)),
                        ];
                        $this->notify_devices('SCHEDULED_CONSULTATION_CREATEDBY',array(USER_ID), false, true, true, array(),'', $constants_not, false);
                    //change medical director to marie
                    $this->loadModel('SpaLiveV1.SysUserAdmin');
                    $md_id = $this->SysUserAdmin->getAssignedDoctorInjector($ent_patient->id);
                    $pat  = $this->SysUsers->find()->where(['SysUsers.id' => $ent_patient->id])->first();
                    if (!empty($pat)) {
                        $this->SysUsers->updateAll(
                            ['md_id' => $md_id], ['SysUsers.id' => $ent_patient->id]
                        );
                    }
                }
            }
        }
        //$this->set('q ', $data_questions);
    }

    public function start_consultation(){
        $this->loadModel('SpaLiveV1.DataConsultation'); 
        $this->loadModel('SpaLiveV1.DataPayment'); 
        $this->loadModel('SpaLiveV1.DataConsultationAnswers');
        
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        $ot_exam_id = 0;
        // if (API_KEY == '2fe548d5ae881ccfbe2be3f6237d7952') {
        //     $this->message('Go to app.myspalive.com to start get your GFE');
        //     return;
        // }
        $string_treatments = get('treatments','');
        if(empty($string_treatments)){
            $this->loadModel('SpaLiveV1.DataTreatment');

            $fields = ['DataTreatment.id', 'DataTreatment.uid', 'DataTreatment.status'];
            $fields['treatments_string'] = "(SELECT GROUP_CONCAT(CONCAT(CTC.name,' (',CT.name, ')') SEPARATOR ', ') 
                                        FROM cat_treatments_ci CT 
                                        JOIN cat_treatments_category CTC ON CTC.id = CT.category_treatment_id 
                                        WHERE FIND_IN_SET(CT.id,DataTreatment.treatments) LIMIT 1)";
            
            $ent_treatment = $this->DataTreatment->find()->select($fields)->where(['DataTreatment.patient_id' => USER_ID, 'DataTreatment.deleted' => 0])->last();

            if(empty($ent_treatment)){
                $string_treatments = '92,93';
            }else{
                $Treatments = new TreatmentsController();
                $separate_treatments = $Treatments->separate_treatments($ent_treatment->treatments_string);

                if(!empty($separate_treatments["neurotoxins"]) || !empty($separate_treatments["fillers"])){
                    $string_treatments = '92,93';
                }else if(!empty($separate_treatments["iv_therapy"])){
                    $string_treatments = '35';
                }
            }
        }

        if($string_treatments == 'neuro_filler'){
            $call_type = '92,93';
        }else if($string_treatments == 'iv_therapy'){
            $call_type = '35';
        }else if($string_treatments == 'neuro_iv'){
            $call_type = '92,93,35';
       }else if($string_treatments == 'other_treatments'){
            $type = get('type','');
            $name_key = get('name_key','');
            

            if (!empty($type) && $type == 'OTHER_TREATMENTS' && !empty($name_key)) {
                $this->loadModel('SpaLiveV1.SysTreatmentsOt');
                $other_treatment = $this->SysTreatmentsOt->find()
                ->select(['CT.id','CT.qualiphy_exam_id'])
                ->join([
                    'CT' => ['table' => 'cat_treatments', 'type' => 'INNER', 'conditions' => 'SysTreatmentsOt.id = CT.other_treatment_id AND CT.deleted = 0'],
                ])
                ->where(['SysTreatmentsOt.deleted' => 0, 'SysTreatmentsOt.active' => 1, 'SysTreatmentsOt.name_key' => $name_key])
                ->first();

                if (!empty($other_treatment)) {
                    $call_type = $other_treatment['CT']['id'];
                    $ot_exam_id = $other_treatment['CT']['qualiphy_exam_id'];
                } else {
                    $this->message('Treatment not found');
                    return;
                }
            }
        }
        else{
            $string_treatments = 'neuro_filler';
            $call_type = '92,93';
        }

        $consultation_uid = get('consultation_uid','');
        if (empty($consultation_uid)) {
            $consultation_uid = Text::uuid();

            $schedule_by = 0;
            $schedule_date = get('schedule_date','');
            if (!empty($schedule_date)) {
                $schedule_by = USER_ID;
            }
            
            if (empty($schedule_date)) 
                $schedule_date = date('Y-m-d H:i:s');

            $createdby = USER_ID;
            $patient_id = USER_ID;
            
            $this->loadModel('SpaLiveV1.SysUsers');

            $available = $this->gfeAvailability($schedule_date);

            if (!$available) {
                $this->success(false);
                $this->message("Our good faith examiners are available Monday-Saturday from 8 a.m - 8 p.m. If you have reached us outside of our business hours, holidays, etc., please feel free to schedule your exam for a specific date and time or reach back out to us during business hours OR (reconnect with us during business hours) Thank you!");
                $this->set('not_available', true);
                return false;
            }

            $ent_payment = $this->DataPayment->find()
                                ->where(['DataPayment.id_from' => $patient_id, 'DataPayment.id_to' => 0,'DataPayment.type' => 'GFE', 
                                        'DataPayment.service_uid' => '','DataPayment.payment <>' => '','DataPayment.prepaid' => 1,
                                        'DataPayment.comission_payed' => 1])->first();
            
            if(empty($ent_payment)){
                $this->message('You need to pay for the GFE.');
                return;
            }

            $consultation = $this->DataConsultation->find()->where(['DataConsultation.patient_id' => $patient_id, 'DataConsultation.deleted' => 0, 
                                                                    'DataConsultation.status' => 'INIT', 'DataConsultation.join_url <>' => ''])->first();

            if(!empty($consultation)){

                $posicion = strpos($consultation->join_url, 'zoom.us');

                if ($posicion === false){
                    $this->set('meeting_url', $consultation->join_url);
                    $this->set('uid', $consultation->uid);
                    $this->success();
                    return;
                }
            }

            $array_save = array(
                'uid' => $consultation_uid,
                'patient_id' => $patient_id,
                'assistance_id' => 0,
                'treatments' => $call_type,
                'payment' => '',
                'meeting' => '',
                'meeting_pass' => '',
                'schedule_date' => $schedule_date,
                'status' => "INIT",
                'schedule_by' => $schedule_by,
                'deleted' => 0,
                'participants' => 0,
                'createdby' => $createdby,
                'clinic_patient_id' => $patient_id,
                'payment_method' => get('payment_method',''),
                'language' => get('language','ENGLISH'),
                'state' => USER_STATE,
            );

            $qualiphy = new QualiphyController;

            $r = $qualiphy->generate_meeting(array('consultation_uid' => $consultation_uid, 'user_uid' => USER_UID, 'type' => $string_treatments), $string_treatments, $ot_exam_id);

            if($r['http_code'] == 200){
                $array_save['meeting'] = $r['patient_exams'][0]['patient_exam_id'];
                $array_save['meeting_pass'] = $r['meeting_uuid'];
                $array_save['join_url'] = $r['meeting_url'];

            } else {
                $this->message($r['http_code']);
                $this->message($r['error_message']);
                return;
            }

            $c_entity = $this->DataConsultation->newEntity($array_save);
            if(!$c_entity->hasErrors()) {
                if ($this->DataConsultation->save($c_entity)) {

                    $this->set('meeting_url', $r['meeting_url']);
                    $this->set('uid', $consultation_uid);
                    $this->success();
                }
            }

        } else {
            // Schedule
            $this->loadModel('SpaLiveV1.SysUsers');

            $consultation_id = $this->DataConsultation->uid_to_id($consultation_uid);
            if (!$consultation_id) {
                $this->message('consultation_uid not found.');
                return;
            }

            $schedule_date = get('schedule_date','');
            if (empty($schedule_date)) {
                $this->message('Invalid schedule date..');
                return;
            }

            $array_save = array(
                'id' => $consultation_id,
                'schedule_date' => $schedule_date,
                'schedule_by' => USER_ID,
                'status' => 'INIT',
                'participants' => 0,
                'is_waiting' => 0,
                'language' => get('language','ENGLISH'),
            );

            $c_entity = $this->DataConsultation->newEntity($array_save);
            if(!$c_entity->hasErrors()) {
                if ($this->DataConsultation->save($c_entity)) {
                    $this->success();
                }
            }
        }
    }

