    public function confirm_appointment() {
        
        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->loadModel('SpaLiveV1.DataTreatment');
        $this->loadModel('SpaLiveV1.DataPatientClinic');


        $treatment_uid = get('uid', '');
        if(empty($treatment_uid)){
            $this->message('uid empty.');
            return;
        }

        $ent_treatments = $this->DataTreatment->find()->where(['DataTreatment.uid' => $treatment_uid])->first();
        if(empty($ent_treatments)){
            $this->message('Treatment not found');
            return;
        }

         $array_save = array(
            'id' => $ent_treatments->id,
            'status' => 'CONFIRM',
        );
        
        $c_entity = $this->DataTreatment->newEntity($array_save);
        if(!$c_entity->hasErrors()) {
            if ($this->DataTreatment->save($c_entity)) {
                $this->success();
                $this->notify_devices('TREATMENT_CONFIRMED',array($ent_treatments->patient_id),true,true,true, array(), '',array(),true);
                
                $ent_datapatient = $this->DataPatientClinic->find()->select(['SysUsers.uid','SysUsers.short_uid','SysUsers.name','SysUsers.lname'])
                ->join(['SysUsers' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'DataPatientClinic.user_id = SysUsers.id'],])
                ->where(['SysUsers.deleted' => 0, 'DataPatientClinic.injector_id' => USER_ID,'DataPatientClinic.deleted' => 0,'DataPatientClinic.user_id' => $ent_treatments->patient_id])->first();
                if($ent_treatments->type_uber == 0){
                    $patient = $this->SysUsers->find()->where(['SysUsers.id' => $ent_treatments->patient_id])->first();
                    $Main = new MainController();
                    $this->loadModel('SpaLiveV1.CatNotifications');
                    $ent_notification = $this->CatNotifications->find()->where(['CatNotifications.title' => "APPOINTMENT_PREPARATION"])->first();
                    $to = $patient['email'];
                    if (!empty($ent_notification)) {
                        $subject = $ent_notification['subject'];
                        $msg_mail = $ent_notification['body'];
                        
                        $constants = [
                            '[Patient]' => $patient['name'] ." " . $patient['lname'],
                            
                        ];
                        foreach($constants as $key => $value){
                                $msg_mail = str_replace($key, $value, $msg_mail);
                        }
                        
                        $this->send_email_after_register($to, $subject, $msg_mail);
                    }
                }
                if (empty($ent_datapatient)) {
                    $arrLinkPat = [
                        'uid' => $this->DataPatientClinic->new_uid(),
                        'injector_id' => USER_ID, 
                        'user_id' => $ent_treatments->patient_id,
                    ];
                    try{
                        $entLink = $this->DataPatientClinic->newEntity($arrLinkPat);
                        if(!$entLink->hasErrors()){
                            $this->DataPatientClinic->save($entLink);
                            $this->success(); 
                        }
                    }catch (\PDOException $e){
                        $this->message('is already your patient.');
                    }
                }


            }
        }
    }

