    private function generateZakToken($zoom_token,$u_email){
        if ($zoom_token) {

            $zoom_user = $this->get_zoom_user($zoom_token,$u_email);

            $curl = curl_init();

            curl_setopt_array($curl, array(
              CURLOPT_URL => "https://api.zoom.us/v2/users/".$zoom_user["id"]."/token?type=zak",
              CURLOPT_RETURNTRANSFER => true,
              CURLOPT_ENCODING => "",
              CURLOPT_MAXREDIRS => 10,
              CURLOPT_TIMEOUT => 30,
              CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
              CURLOPT_CUSTOMREQUEST => "GET",
              CURLOPT_HTTPHEADER => array(
                "authorization: Bearer " . $zoom_token,
                "content-type: application/json"
              ),
            ));

            $response = curl_exec($curl);
            $err = curl_error($curl);

            curl_close($curl);
           
            if ($err) {
                return false;
            }

            $res = json_decode($response,true);

            return $res["token"];
        }

        return false;
    }

    private function get_zoom_user($zoom_token,$u_email){
        $curl = curl_init();

        curl_setopt_array($curl, array(
            CURLOPT_URL => "https://api.zoom.us/v2/users/".$u_email,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_ENCODING => "",
            CURLOPT_MAXREDIRS => 10,
            CURLOPT_TIMEOUT => 30,
            CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
            CURLOPT_CUSTOMREQUEST => "GET",
            CURLOPT_HTTPHEADER => array(
            "authorization: Bearer " . $zoom_token,
            "content-type: application/json"
            ),
        ));

        $response = curl_exec($curl);
        $err = curl_error($curl);

        curl_close($curl);
        
        if ($err) {
            return false;
        }

        $res = json_decode($response,true);

        return $res;
    }

    private function generateZoomUser($zoom_token) {
        
        if ($zoom_token) {
            $user_seetings = '{
               "action":"custCreate",
               "user_info":{
                  "email":"' . str_replace('ymail.com', 'yahoo.com', USER_EMAIL) . '",
                  "type":1,
                  "first_name":"' . USER_NAME . '",
                  "last_name":""
               }
            }';

            $curl = curl_init();

            curl_setopt_array($curl, array(
              CURLOPT_URL => "https://api.zoom.us/v2/users/",
              CURLOPT_RETURNTRANSFER => true,
              CURLOPT_ENCODING => "",
              CURLOPT_MAXREDIRS => 10,
              CURLOPT_TIMEOUT => 30,
              CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
              CURLOPT_CUSTOMREQUEST => "POST",
              CURLOPT_POSTFIELDS => $user_seetings,
              CURLOPT_HTTPHEADER => array(
                "authorization: Bearer " . $zoom_token,
                "content-type: application/json"
              ),
            ));

            $response = curl_exec($curl);
            $response = json_decode($response,true);
            $err = curl_error($curl);
            curl_close($curl);
            if(!isset($response['id'])){
                if(isset($response['code'])){
                    if($response['code'] != "1005"){
                        $this->log(__LINE__ . ' ' . json_encode($response));
                        $this->set('zoom_error_code',$response['code']);
                        $this->set('zoom_error_message',$response['message']);
                        return false;
                    }
                }
            }
           
            if ($err) {
                return false;
            }
            return str_replace('ymail.com', 'yahoo.com', USER_EMAIL);
        }

        return false;
    }

