                    (SELECT GROUP_CONCAT(DISTINCT CT.name) FROM cat_treatments CT WHERE FIND_IN_SET(CT.id,DC.treatments)) treatments
                FROM data_consultation DC
                JOIN sys_users U ON U.id = DC.patient_id
                JOIN cat_states CS ON CS.id = U.state
                WHERE DC.deleted = 0' . $_where . '
                AND (
                    ((DC.assistance_id = 0 AND DC.schedule_by = 0 AND status = "INIT")
                    OR (assistance_id = '.$user['user_id'].' AND schedule_by > 0 AND status = "INIT" AND is_waiting = 1))
                    AND (DC.reserve_examiner_id = ' . USER_ID . ' OR DC.reserve_examiner_id = 0)
                )
                AND TIMESTAMPDIFF(second, DC.modified, \'' . $c_date . '\') < 15 ' . $_where_states;
            } else {
                 $str_query = 'SELECT 
                    DC.id, DC.uid, DC.meeting, DC.meeting_pass,CONCAT(U.`name`,\' \',U.lname) patient, U.type, CONCAT(U.name," ",U.lname) pname ,CS.name state, DC.schedule_date, DC.treatments, DC.assistance_id,DC.language,
                    (SELECT GROUP_CONCAT(DISTINCT CT.name) FROM cat_treatments CT WHERE FIND_IN_SET(CT.id,DC.treatments)) treatments
                FROM data_consultation DC
                JOIN sys_users U ON U.id = DC.patient_id
                JOIN cat_states CS ON CS.id = U.state
                WHERE DC.deleted = 0 AND TIMESTAMPDIFF(MINUTE,DC.schedule_date,\'' . $c_date .'\') <= 15 AND DC.schedule_by != 0' . $_where . ' AND DC.status = "INIT" AND DC.assistance_id = 0 ' . $_where_states;
                ;

                //DC.schedule_date > NOW() AND
            }

