                $sdkKey = env('ZOOM_SDK_KEY','');
                $sdkSecret = env('ZOOM_SDK_SECRET','');
                $payload = [
                    'sdkKey' => $sdkKey,
                    'mn'=> trim($row['meeting']), //meet number
                    'role' =>  0,
                    'iat' =>  $iat,
                    'exp' =>  $exp,
                    'appKey' =>  $sdkKey,
                    'tokenExp' =>  $exp
                ];

                $treatments = str_replace(",", ", ", trim($row['treatments']));

                if ($treatments == "Botox & other neurotoxins, Fillers") {
                    $treatments = "Neurotoxins & Fillers";
                }

                $jwt = JWT::encode($payload, $sdkSecret, 'HS256');
                $result[] = array(
                    'uid' => $row['uid'],
                    'meeting_pass' => trim($row['meeting_pass']),
                    'meeting' => trim($row['meeting']),
                    'jwt' => !empty($jwt) ? $jwt : '',
                    'patient' => $patient,
                    'assistance' => isset($row['assistance']) ? "Dr. " . $row['assistance'] : "",
                    'assistance_id' => $row['assistance_id'],
                    'state' => !empty($row['state']) ? $row['state'] : "",
                    'schedule_date' => $dd[0],
                    'schedule_time' => isset($dd[1]) ? $dd[1] : '',
                    'treatments' => $treatments,
                    'language' => trim($row['language']),
                    'text_disclaimer' => "*By Texas law, you have to have a visual appointment with the patient before providing the Good Faith Exam certificate."
                );
                
            }
        }

        if($returnList == true){
            return $result;
        }else{
            $this->set('data', $result);
            $this->success();
        }
    }

