    public function load_injector_settings() {
        $this->loadModel('SpaLiveV1.DataScheduleDaysOff');
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $model = empty(get('model','')) ? 'injector' : get('model','');
        if($model != 'injector' && $model != 'examiner'){
            $this->message('Invalid user model.');    
            return;
        }

        // if (USER_TYPE != "injector") {
        //     $this->message('Invalid user type.');    
        //     return;
        // }
        $this->loadModel('SpaLiveV1.SysUsers');
        $e_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();

        $array_response = array();

        $array_response['radius'] = $e_user->radius;

        $this->loadModel('SpaLiveV1.DataScheduleModel');
        $lm_entity = $this->DataScheduleModel->find()->where(['DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.deleted' => 0, 'DataScheduleModel.days LIKE' => '%,%', 'DataScheduleModel.model' => $model])->first();

        if (empty($lm_entity)) {
            $str_days = "";
            $int_start = 9;
            $int_end = 15;
        } else {
            $str_days = $lm_entity->days;
            $int_start = $lm_entity->time_start;
            $int_end = $lm_entity->time_end;
        }

        $array_response['days'] = $str_days;
        $array_response['time_start'] = $int_start;
        $array_response['time_end'] = $int_end;

        $skd_days = $this->DataScheduleModel->find()->select(['DataScheduleModel.id', 'DataScheduleModel.days', 'DataScheduleModel.time_end', 'DataScheduleModel.time_start'])
        ->where(['DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.deleted' => 0, 'DataScheduleModel.days NOT LIKE' => '%,%', 'DataScheduleModel.model' => $model])->toArray();

        $array_response['days_settings'] = [];
        if(!empty($skd_days)){
            $array_response['days_settings'] = $skd_days;
        }else if(!empty($lm_entity)){
            $days = explode(',', $lm_entity->days);
            foreach($days as $item){
                if(!empty($item)){
                    $array_response['days_settings'][] = [
                        'days' => $item,
                        'time_start' => $lm_entity->time_start,
                        'time_end' => $lm_entity->time_end
                    ];
                }
            }
        }

        $days_off = $this->DataScheduleDaysOff->find()->select(['DataScheduleDaysOff.date_off'])
            ->where(['DataScheduleDaysOff.user_id' => USER_ID, 'DataScheduleDaysOff.deleted' => 0])->toArray();
        $array_response['days_off'] = (!empty($days_off) ? Hash::extract($days_off, '{n}.date_off') : []);

        $str_services = "";

        $this->loadModel('SpaLiveV1.DataTreatmentsPrice');
        $p_entity = $this->DataTreatmentsPrice->find()->join([
            'CTCI' => ['table' => 'cat_treatments_ci', 'type' => 'INNER', 'conditions' => 'DataTreatmentsPrice.treatment_id = CTCI.id AND CTCI.deleted = 0']
        ])
        ->where(['DataTreatmentsPrice.user_id' => USER_ID, 'DataTreatmentsPrice.deleted' => 0])->all();

        if (!empty($p_entity)) {
            $arr_pro = array();
            foreach ($p_entity as $row) {
                $arr_pro[] = $row->treatment_id . ',' . $row->price;
            }

            $str_services = implode("|", $arr_pro);

        }

        $array_response['services'] = $str_services;

        $this->set('data', $array_response);
        $this->set('request_stripe', $this->checkStripeACcount());

        $this->success(); 
     // radius: 
     // days: MONDARY,FRIDAY
     // start: 10
     // end: 15
     // services: id,price|id,price
    }

    public function confirm_purchase() {

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }


        // if (USER_TYPE != "injector") {
        //     $this->message('Invalid user type.');    
        //     return;
        // }

        $str_products = get('products','');
        $str_details = get('details','');
        if (empty($str_products)) {
            $this->message('Invalid products');
            return;
        }

        $arr_products = explode("|", $str_products);
        

        if (empty($arr_products)) {
            $this->message('Invalid products.');
            return;
        }

        $arr_details = explode("||", $str_details);
        $arr_pro_details = array();

        if (count($arr_details) > 0) {
            foreach ($arr_details as $det) {
                $arr_det = explode("::", $det);
                if (count($arr_det) > 1 ) {
                    $arr_pro_details[$arr_det[0]] = $arr_det[1];
                }
            }
        }

        $this->loadModel('SpaLiveV1.DataPurchases');
        $this->loadModel('SpaLiveV1.CatProducts');
        $this->loadModel('SpaLiveV1.DataEliteClub');

        $elite_discount = false;
        $total_elite = 0;
        $total_discount_elite = 0;
        $discount_text = '';
        $code_elite = '';
        $elite = $this->DataEliteClub->find()->where(['user_id' => USER_ID, 'active' => 1, 'deleted' => 0])->first();
        if(!empty($elite)){
            $elite_discount = true;
        }

        $arr_cat = array(
                'FILLERS' => false,
                'MATERIALS' => false,
                'NEUROTOXINS' => false,
                'MISCELLANEOUS' => false,
                'NEUROTOXIN PACKAGES' => false,
                'FILLER PACKAGES' => false,
                'IV VIALS' => false,
            );

        $erros = [];
        $arr_products_save = array();
        $grand_total = 0;
        $neurotoxinsQty= 0;
        $is_training = false;
        $arr_cart = array();
        foreach ($arr_products as $row) {

            $arr_product = explode(',', $row);
            $ent_cprod = $this->CatProducts->find()->where(['CatProducts.id' => $arr_product[0]])->first();

            if (!empty($ent_cprod)) {

                if($arr_product[0]==44||$arr_product[0]==45||$arr_product[0]==103||$arr_product[0]==178||$arr_product[0]==184||$arr_product[0]==185){
                    $is_training = true;
                }
                
                $quanti = $arr_product[1];
                if ($quanti == 0) continue;
                if($ent_cprod->purchase_limit > 0 && $quanti > $ent_cprod->purchase_limit){$erros[] = "\nyou only can buy " . $ent_cprod->purchase_limit . " of ".$ent_cprod->name;}
                $array_save = array(
                    'product_id' => $ent_cprod->id,
                    'price' => $ent_cprod->unit_price,
                    'qty' => $quanti,
                    'product_detail_question' => $ent_cprod->details_text,
                    'product_detail' => isset($arr_pro_details[$ent_cprod->id]) ? $arr_pro_details[$ent_cprod->id] : '',
                );

                $arr_cart[] = array(
                    'name_product' => $ent_cprod->name,
                    'qty' => $quanti,
                    'total' => $ent_cprod->unit_price * $quanti,
                );

                if ($ent_cprod->category == "MISCELLANEOUS") {
                    if ($ent_cprod->add_shipping == 1) { $arr_cat[$ent_cprod->category] = true; }
                } else 
                    $arr_cat[$ent_cprod->category] = true;

                if($ent_cprod->category == "NEUROTOXINS" || $ent_cprod->category == 'NEUROTOXIN PACKAGES') $neurotoxinsQty += $quanti;

                $arr_products_save[] = $array_save;
                
                if($elite_discount){
                    if(($ent_cprod->category == "NEUROTOXINS" || $ent_cprod->category == 'NEUROTOXIN PACKAGES' || $ent_cprod->category == 'FILLERS' || $ent_cprod->category == 'IV VIALS') && ($ent_cprod->product_id != 59 && $ent_cprod->product_id != 1)){
                        $this->loadModel('SpaLiveV1.DataCodeEc');
                        $ent_promo = $this->DataCodeEc->find()->last();
                        if(!empty($ent_promo)){
                            $total_elite += ($ent_cprod->unit_price * $arr_product[1]) - (($ent_cprod->unit_price * $arr_product[1]) * ($ent_promo->discount / 100));
                            $total_discount_elite += ($ent_cprod->unit_price * $arr_product[1]) * ($ent_promo->discount / 100);
                            $discount_text = '-' . $ent_promo->discount . '% Elite Club Discount applied';
                            $code_elite = $ent_promo->code;
                        }else{
                            $grand_total += $ent_cprod->unit_price * $arr_product[1];
                        }
                    }else{
                        $grand_total += $ent_cprod->unit_price * $arr_product[1];
                    }
                }else{
                    $grand_total += $ent_cprod->unit_price * $arr_product[1];
                }

            }

        }

        if(sizeof($erros) > 0){
            $this->message($erros);
            return;
        }
        //        

        $shipping_cost = 0;
        /*
         if (($arr_cat['NEUROTOXINS'] || $arr_cat['FILLERS'] || $arr_cat['NEUROTOXIN PACKAGES'] || $arr_cat['FILLER PACKAGES']) && ($arr_cat['MATERIALS'] || $arr_cat['MISCELLANEOUS']) ) {
            $shipping_cost = $this->shipping_cost_both;
        } else if ($arr_cat['NEUROTOXINS'] || $arr_cat['FILLERS'] || $arr_cat['NEUROTOXIN PACKAGES'] || $arr_cat['FILLER PACKAGES']) {
            $shipping_cost = $this->shipping_cost_inj;
        } else if($arr_cat['IV VIALS'] && $arr_cat['MATERIALS']) {
            $shipping_cost = $this->shipping_cost_vial;
        } else if ($arr_cat['MATERIALS']) {
            $shipping_cost = $this->shipping_cost_mat;
        } else if ($arr_cat['MISCELLANEOUS']) {
            $shipping_cost = $this->shipping_cost_mat;
        } else if ($arr_cat['IV VIALS']) {
            $shipping_cost = $this->shipping_cost_vial;
        }
        */

        if(($arr_cat['NEUROTOXINS'] || $arr_cat['FILLERS'] || $arr_cat['NEUROTOXIN PACKAGES'] || $arr_cat['FILLER PACKAGES']) && 
            ($arr_cat['MATERIALS'] || $arr_cat['MISCELLANEOUS']) && $arr_cat['IV VIALS']) {
            $shipping_cost = $this->ship_cost_neuro + $this->ship_cost_vial;
        } else if (($arr_cat['MATERIALS'] || $arr_cat['MISCELLANEOUS']) && 
            $arr_cat['IV VIALS']) {
            $shipping_cost = $this->ship_cost_mat + $this->ship_cost_vial;
        } else if(($arr_cat['NEUROTOXINS'] || $arr_cat['FILLERS'] || $arr_cat['NEUROTOXIN PACKAGES'] || $arr_cat['FILLER PACKAGES']) && 
            ($arr_cat['MATERIALS'] || $arr_cat['MISCELLANEOUS'])) {
            $shipping_cost = $this->ship_cost_neuro;
        } else if ($arr_cat['MATERIALS'] || $arr_cat['MISCELLANEOUS']) {
            $shipping_cost = $this->ship_cost_mat;
        } else if ($arr_cat['IV VIALS']) {
            $shipping_cost = $this->ship_cost_vial;
        } else {
            $shipping_cost = $this->ship_cost_neuro;
        }

        if($neurotoxinsQty >= 5){
            $shipping_cost = $shipping_cost - $this->shipping_cost_inj;
        }

        if($is_training&&count($arr_products)<=1){
            $shipping_cost = 0;
        }

        $purchase_uid = Text::uuid();
        $array_save = array(
            'uid' => $purchase_uid,
            'user_id' => USER_ID,
            'status' => 'NEW',
            'name' => get('name',''),
            'address' => get('address',''),
            'suite' => get('suite',''),
            'city' => get('city',''),
            'state' => get('state',''),
            'zip' => get('zip',0),
            'tracking' => '',
            'delivery_company' => '',
            'created' => date('Y-m-d H:i:s'),
            'shipping_date' => date('Y-m-d'),
            'shipping_cost' => $shipping_cost,
            'amount' => $grand_total,
        );

        $c_entity = $this->DataPurchases->newEntity($array_save);
        if(!$c_entity->hasErrors()) {
            if ($this->DataPurchases->save($c_entity)) {
                $this->set('uid', $purchase_uid);
                
                foreach ($arr_products_save as $a_sav) {
                    $a_sav['purchase_id'] = $c_entity->id;

                    $this->loadModel('SpaLiveV1.DataPurchasesDetail');
                    $csave_entity = $this->DataPurchasesDetail->newEntity($a_sav);
                    if(!$csave_entity->hasErrors()) {
                        $this->DataPurchasesDetail->save($csave_entity);
                    }
                }

                if (USER_TYPE == 'clinic') {
                    $this->checkClinicCredits();
                }

                if($elite_discount){
                    $grand_total = $total_elite + $grand_total;
                    $stripe_fee = round(($grand_total + $shipping_cost) * 0.0315);
    
                    $this->set('grand_total', $grand_total + $shipping_cost + $stripe_fee);
                    $this->set('stripe_fee', $stripe_fee);
                    $this->set('shipping_cost', intval($shipping_cost));
                    $this->set('discount_text', $discount_text);
                    $this->set('discount_amount', intval($total_discount_elite));
                    $this->set('code_discount', $code_elite);
                    $this->set('cart', $arr_cart);
                    $this->success();
                }else{
                    $stripe_fee = round(($grand_total + $shipping_cost) * 0.0315);
    
                    $this->set('grand_total', $grand_total + $shipping_cost + $stripe_fee);
                    $this->set('stripe_fee', $stripe_fee);
                    $this->set('shipping_cost', intval($shipping_cost));
                    $this->set('cart', $arr_cart);
                    $this->success();
                }


            }
        }

    }

    public function send_message_contact(){

        
        $message = get('message', '');
        $nameCnt = get('name', '');
        $lnameCnt = get('lname', '');
        $emailCnt = get('email', '');
        $numberCnt = get('phone_number', '');


        if (empty($message) && (empty($emailCnt) || empty($emailCnt))) return;
        
        $html_content = "";
        
        $subject = 'New Message';
        $html_content = 'Contact form.
        <br><br>
        You have received this message from myspalive.com' . 
        '<br><br>' .
        '<b>Contact information</b>' .
        '<div style="margin: 12px 16px 12px 24px;">' .
            '<p>Name: ' . $nameCnt . ' ' . $lnameCnt .
            '<p>Phone number: ' . $numberCnt .
            '<p>Email: ' . $emailCnt .
        '</div>' .
        '<br><br>' .
        '<div style="margin: 12px 16px 12px 24px;">' . $message . '</div>';
        

        $data=array(
                'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'to'      => 'ashlan@myspalive.com,cassandra@myspalive.com',
                // 'to'      => 'khanzab@gmail.com',
                'subject' => 'New message from contact form - MySpaLive',
                'html'    => $html_content,
            );

        $mailgunKey = $this->getMailgunKey();

        $curl = curl_init();
        curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
        curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
        curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
