    public function remove_license(){

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->loadModel('SpaLiveV1.SysLicence');

        if ($user['user_role'] == 'gfe+ci' || $user['user_role'] == 'examiner')  {
            $license_count = $this->SysLicence->find()->select(['SysLicence.id'])->where(['SysLicence.user_id' => USER_ID,'SysLicence.deleted' => 0])->count();
            if ($license_count <= 1) {
                $this->message('You must have at least 1 license, add a new license before remove this one.');
                return;    
            }    
        }
        
        $licenceItem = $this->SysLicence->find()->select(['SysLicence.id'])->where(['SysLicence.user_id' => USER_ID,'SysLicence.id' => get('license_id')])->first();

        if (!empty($licenceItem)) {
            $licenceItem->deleted = 1;
            $this->SysLicence->save($licenceItem);
            $this->success();
        }

    }

