    public function notify_devices($message, $arr_users, $notify_push = false, $notify_email = false, $shouldSave = true, $data = array(),$body_extra = '', $constants = array(), $notify_sms = false, $force_hour = false, $treatment_uid='', $bulk = false) {

        $is_dev = env('IS_DEV', false);
        $av_result = $force_hour == true ? true : $this->gfeAvailability();
        // if (!$av_result) return;
         
        $this->loadModel('SpaLiveV1.CatNotifications');
        if ($message == 'TREATMENT_AVAILABLE') {
            $ent_notifications = $this->CatNotifications->find()->where(['CatNotifications.title' => $message])->all();

            $random_index = array_rand($ent_notifications->toArray());

            $ent_notification = $ent_notifications->toArray()[$random_index];

        } else {
            $message_emoti = $this->remove_emoji($message);
            $message_emoti = preg_replace('/[^(\x20-\x7F)]*/','', $message_emoti);
            $message_emoti = iconv("UTF-8", "ISO-8859-1//TRANSLIT", $message_emoti);            
            
            $ent_notification = $this->CatNotifications->find()->where(['CatNotifications.title' => $message_emoti])->first();
        }
        $message_detail = '';
        $notification_type = '';
        $path_file = '';

        if (!empty($ent_notification)) {
            $msg_mail = $ent_notification['body'];
            $msg_push = $ent_notification['body_push'];
            foreach($constants as $key => $value){
                $msg_mail = str_replace($key, $value, $msg_mail);
                $msg_push = str_replace($key, $value, $msg_push);
            }

            $conf_subject = $ent_notification['subject'];
            //remplazar caracteres especiales             //Your Weight Loss Program is On the Way! &#128666; &#10024;
            if($message == 'WEIGHT_LOSS_CONFIRM_DELIVERY' || $message == 'SHIPPING_PRODUCT' ){
                $html_decimal_code = '&#128666;';                // Convert HTML Decimal Code to Unicode character
                $unicode_character = html_entity_decode($html_decimal_code, ENT_COMPAT, 'UTF-8');
                $html_decimal_code = '&#10024;';                // Convert HTML Decimal Code to Unicode character
                $unicode_character2 = html_entity_decode($html_decimal_code, ENT_COMPAT, 'UTF-8');                
                $conf_subject = 'Your Weight Loss Program is On the Way! '.$unicode_character.' '.$unicode_character2 ;
            }
            $conf_body = $msg_mail;
            $conf_body_push = $msg_push; 
            $conf_body .= '<br><br>' . $body_extra;
            $path_file = $ent_notification['path_file'];
        } else {
            $conf_subject = 'MySpaLive Notification';
            $conf_body = $message;
            $conf_body_push = $message; 
        }
        
        
        if ($notify_email && $av_result) {

            $notification_type = 'EMAIL';

            $this->loadModel('SpaLiveV1.SysUsers');
            $str_str_users = implode(",",$arr_users);
            
            
            $str_query = "
                SELECT 
                    GROUP_CONCAT(SU.email) emails
                FROM sys_users SU LEFT JOIN data_notifications_settings NS ON NS.user_id = SU.id       
                WHERE SU.deleted = 0 AND (SU.login_status = \"READY\" OR SU.login_status = \"CHANGEPASSWORD\" OR SU.login_status = \"PAYMENT\") AND FIND_IN_SET(SU.id,'{$str_str_users}') AND (NS.allow_email = 1 OR NS.allow_email IS NULL)";


            $ent_query = $this->SysUsers->getConnection()->execute($str_query)->fetchAll('assoc');
            
            if (!empty($ent_query)) {
                $ems = $ent_query[0]['emails'];  
                $this->send_new_email($conf_body,$ems,$conf_subject,$path_file);
            }
            
        
        }

        if ($notify_push && $av_result) {
            
            $notification_type = 'PUSH';
         
            $this->loadModel('SpaLiveV1.ApiDevices');
            $this->loadModel('SpaLiveV1.DataNotificationsSettings');    
            
            $this->loadModel('SpaLiveV1.SysUsers');
            $str_str_users = implode(",",$arr_users);

            $str_query = "SELECT 
                AD.id, NS.allow_push   
            FROM api_devices AD LEFT JOIN data_notifications_settings NS ON NS.user_id = AD.user_id       
            WHERE (NS.allow_push = 1 OR NS.allow_push IS NULL) AND AD.application_id = 1 AND FIND_IN_SET(AD.user_id,'{$str_str_users}')";
            
            $ent_devices = $this->ApiDevices->getConnection()->execute($str_query)->fetchAll('assoc');      
            $arr_devices = array();
            
            foreach ($ent_devices as $row) {
                if($row['allow_push'] == 1 || $row['allow_push'] == null){
                    $arr_devices[] = $row['id'];
                }
            } 

            $this->loadModel('SpaLiveV1.DataNotification');
            if (!defined('USER_ID')) define('USER_ID', 0);
            $arrSave = array(
                'type' => 'NOTIFICATION',
                'message' => $conf_body_push,
                'json_users' => json_encode($arr_users),
                'json_data' => json_encode($data),
                'user_id' => USER_ID,
            );
            $ent_noti = $this->DataNotification->newEntity($arrSave);
            if(!$ent_noti->hasErrors()){
                $this->DataNotification->save($ent_noti);
            }
            
            $this->send($conf_body_push,$data,$arr_devices);

        }

        /*if ($shouldSave) {

             foreach ($arr_users as $user_id) {
                
                $array_save = array(
                    'type' => 'NOTIFICATION',
                    'id_from' => 0,
