    public function send_new_email($html_content,$email,$subject = "New alert from MySpaLive", $file = '') {

           $data = array(
                'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'to'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'bcc'      => $email,
                'subject' => $subject,
                'html'    => $html_content,
            );

            if(!empty($file)){
                $filename = APP . $file;
                $data['attachment[1]'] = curl_file_create($filename, 'application/pdf', 'file.pdf');
            }

            $mailgunKey = $this->getMailgunKey();

            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);
            curl_setopt($curl, CURLOPT_HEADER, true);
            curl_setopt($curl, CURLOPT_HTTPHEADER, ["Content-Type:multipart/form-data"]);

            $result = curl_exec($curl);

            curl_close($curl);

    }

    public function invite_injector() {

        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        if (USER_TYPE != "injector" && USER_TYPE != "gfe+ci") {
            $this->message('Invalid user.');
            return;
        }

        $str_email = get('email','');
        if(empty($str_email)) {
            $this->message('Empty email.');
            return;
        }

        if (!filter_var($str_email, FILTER_VALIDATE_EMAIL)) {
            $this->message('Invalid email format.');
            return;
        }


        $this->loadModel('SpaLiveV1.DataNetworkInvitations');
        $this->loadModel('SpaLiveV1.SysUsers');

        $existUser = $this->DataNetworkInvitations->find()->where(['DataNetworkInvitations.email LIKE' => strtolower($str_email)])->first();

        if(!empty($existUser)){
            $this->message('This email has already been invited.');
            return;
        }

        $existUser2 = $this->SysUsers->find()->where(['SysUsers.email LIKE' => strtolower($str_email), 'SysUsers.deleted' => 0])->first();

        if(!empty($existUser2)){
            $this->message('This email has already been registered.');
            return;
        }


        $this->loadModel("SpaLiveV1.CatNotifications");
        $ent_notification = $this->CatNotifications->find()->where(['CatNotifications.title' => 'CI_TO_CI_INVITE'])->first();
        if (!empty($ent_notification)) {

            $msg_mail = $ent_notification['body'];

            $e_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
 
            $constants = [
                '[CNT/CIName]' => $e_user['name'],
                '[CNT/CILastName]' => $e_user['lname'],
            ];
            foreach($constants as $key => $value){
                $msg_mail = str_replace($key, $value, $msg_mail);
            }


            $html_content = '<img src="' . $this->URL_PANEL . 'img/logo.png" width="100px"/>' . $msg_mail;

            $data=array(
                'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'to'      => $str_email,
                'subject' => 'New message from MySpaLive',
                'html'    => $html_content,
            );

            $mailgunKey = $this->getMailgunKey();

            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);

            $result = curl_exec($curl);
            curl_close($curl);
        }
        
        $this->loadModel("SpaLiveV1.DataNetworkInvitations");

        $array_save = array(
            'email' => $str_email,
            'parent_id' => USER_ID,
        );

        $c_entity = $this->DataNetworkInvitations->newEntity($array_save);
        if(!$c_entity->hasErrors()) {
            $this->DataNetworkInvitations->save($c_entity);    
        }

        $this->success();

    }

    public function upload_user_photo(){
        
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }


        if (!isset($_FILES['file'])) {
            $this->set('error_file',$_FILES);
            return;
        }

        if (!isset($_FILES['file']['name'])) {
            $this->set('error_name',$_FILES['file']);
            return;
        }

        $str_name = $_FILES['file']['name'];
        $_file_id = $this->Files->upload([
            'name' => $str_name,
            'type' => $_FILES['file']['type'],
            'path' => $_FILES['file']['tmp_name'],
            'size' => $_FILES['file']['size'],
        ]);

        if($_file_id <= 0){
            $this->message('Error in save content file.');
            return;
        }

        
        $array_save = array(
            'id' => USER_ID,
            'photo_id' => $_file_id,
        );

        $this->loadModel("SpaLiveV1.SysUsers");

        $c_entity = $this->SysUsers->newEntity($array_save);
        if(!$c_entity->hasErrors()) {
            if ($this->SysUsers->save($c_entity)) {
                $this->set('photo_id', $_file_id);
                $this->success();
            }
        }

    }

    public function save_bug(){
        $this->loadModel('SpaLiveV1.AppBug');
        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        

        $_name = trim($user['name'].' '.((isset($user['mname']) && !empty($user['mname']) ?$user['mname'] : '' )).' '.$user['lname']);
        $_email = $user['email'];
        $_role = $user['user_role'];
        $title       = get('title', '');
        $description = get('description', '');

        $errors = array();
        if(empty($title) || strlen($title) < 1){
            $errors[] = "You must add a title";
        }
        if(empty($description) || strlen($description) < 10){
            $errors[] = "Invalid description. Minimum 10 characters";
        }

        if(!empty($errors)){
            $msg = implode('\n', $errors);
            $this->message($msg);
            return;
        }


        $arraySave = array(
            'uid'         => $this->AppBug->new_uid(),
            'title'       => $title,
            'description' => $description,
            'op_system'   => get('op_system', ''),
            'ver_system'  => get('ver_system', ''),
            'file_id'     => 0,
            'createdby'   => USER_ID
        );

        if(isset($_FILES['file'])){
            if(isset($_FILES['file']['name'])) {
                $str_name = $_FILES['file']['name'];
                $_file_id = $this->Files->upload([
                    'name' => $str_name,
                    'type' => $_FILES['file']['type'],
                    'path' => $_FILES['file']['tmp_name'],
                    'size' => $_FILES['file']['size'],
                ]);

                if($_file_id > 0){
                    $arraySave['file_id'] = $_file_id;
                }      
            }    
        }

        $ent_bug = $this->AppBug->newEntity($arraySave);
        if(!$ent_bug->hasErrors()) {
            if ($this->AppBug->save($ent_bug)) {
                $this->success();

                $msg = '<h4>This is a User message from MySpaLive App.</h4><br><br>
                <b>Sent by: </b>' . $_role . ' - ' . $_name . ' (' . $_email . ')<br>
                <b>Title: </b>' . $title . '<br><br><b>Description: </b>' .  $description . '<br><br><br><u>You can see details in MySpaLive Admin Panel.</u>';

                $is_dev = env('IS_DEV', false);
                if($is_dev === false){
                    $this->send_new_email($msg,'dev@myspalive.com,myspa@myspalive.com','Technical question from ' . $_name);
                }
                else {
                    $this->send_new_email($msg,'francisco@advantedigital.com','Technical question from ' . $_name);
                }
            }
        }

    }

