    public function verify_background() {

        $this->loadModel('SpaLiveV1.SysUsers');
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $user_node = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
        if(empty($user_node)) {
            return;
        }

        $response_arr = json_decode($user_node->tracers, TRUE);
        $response_arr_sxo = array();
        $response_arr_sxo['numrecords'] = 0;
        
        if (!empty($user_node->tracers_sxo)) $response_arr_sxo = json_decode($user_node->tracers_sxo, TRUE);
        if (!empty($response_arr)) {

            if (isset($response_arr['numrecords'])) {
                if ($response_arr['numrecords'] == 0 && $response_arr_sxo['numrecords'] == 0) {
                    $this->set('login_status', $user_node->login_status);
                    $this->success();
                }
            }
        }
     
    }

