    public function check_gfe_service() {
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataModelPatient');
        $token = get('token', '');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $renew_flag = get('renew_gfe', 0);
        $ot_key_name = get('name_key', false);
        
        $this->loadModel('SpaLiveV1.DataPayment');
        // Verificacion para nuevo registro de paciente
        if(USER_TYPE == 'patient') {
            $this->set('crossed_price', '$79');
            $this->set('text_price',    'Online Medical Exam    $79.00');
            $this->set('text_discount', 'Special Discount         -$40.00');
            $this->set('text_total',       'New Price Just $39.00');
            //Verificar si esta registrado como patient model
            $ent_patient_model = $this->DataModelPatient->find()->where(['DataModelPatient.email' => USER_EMAIL, 'DataModelPatient.deleted' => 0])->first();
            
            if(!empty($ent_patient_model)){
                $this->set('patient_model_register', true);
            }else{
                $this->set('patient_model_register', false);
            }
            //-----------------------------------------------
            // Register flow type uber
            $this->loadModel('SpaLiveV1.DataTreatment');

            $ondemando_flow = false;

            $this->loadModel('SpaLiveV1.DataPatientOndemand');
            $ent_onde = $this->DataPatientOndemand->find()->where(['user_id' => USER_ID, 'deleted' => 0])->first();

            if(!empty($ent_onde)){
                $ondemando_flow = true;
            }

            $ent_payment = $this->DataPayment->find()
                ->where(['DataPayment.id_from' => USER_ID, 'DataPayment.id_to' => 0,'DataPayment.type' => 'GFE', 'DataPayment.service_uid' => '','DataPayment.payment <>' => '','DataPayment.prepaid' => 1, 'DataPayment.comission_payed' => 1])->first();

            $fields = ['DataTreatment.id', 'DataTreatment.uid', 'DataTreatment.status', 'DataTreatment.treatments'];
            $fields['treatments_string'] = "(SELECT GROUP_CONCAT(CONCAT(CTC.name,' (',CT.name, ')') SEPARATOR ', ') 
                                        FROM cat_treatments_ci CT 
                                        JOIN cat_treatments_category CTC ON CTC.id = CT.category_treatment_id 
                                        WHERE FIND_IN_SET(CT.id,DataTreatment.treatments) LIMIT 1)";
            $_where = ['DataTreatment.patient_id' => USER_ID, 'DataTreatment.deleted' => 0];
            $_having = [];

            $ttype = get('type','');
            if (!empty($ttype)) {
                $_having['treatments_string LIKE'] = '"%' . str_replace('_',' ',$ttype) . '%"';
            }
            $ent_treatment = $this->DataTreatment->find()->select($fields)->where($_where)->having($_having)->first();

            if(!empty($ent_treatment)){
                $this->set('treatment_uid', $ent_treatment->uid);
                $require_gfe = false;
                $Treatments = new TreatmentsController();
                $separate_treatments = $Treatments->separate_treatments($ent_treatment->treatments_string);

                if(!empty($separate_treatments["other_treatments"]) && !empty($ot_key_name)){

                        $this->loadModel('SpaLiveV1.SysTreatmentsOt');

                        $other_treatment = $this->SysTreatmentsOt->find()
                         ->select(['SysTreatmentsOt.require_gfe','CT.qualiphy_exam_id'])
                        ->join([
                            'CT' => ['table' => 'cat_treatments', 'type' => 'INNER', 'conditions' => 'SysTreatmentsOt.id = CT.other_treatment_id AND CT.deleted = 0'],
                        ])
                        ->where(['SysTreatmentsOt.deleted' => 0, 'SysTreatmentsOt.active' => 1, 'SysTreatmentsOt.name_key' => $ot_key_name])
                        ->first();

                        if ($other_treatment->require_gfe == 1 && $other_treatment['CT']['qualiphy_exam_id'] > 0) {
                            $require_gfe = true;
                        }

                 
                }else if(!empty($separate_treatments["neurotoxins"]) || !empty($separate_treatments["fillers"])){
                    $require_gfe = $this->getCertificateType('92,93', USER_ID, $renew_flag);
                }else if(!empty($separate_treatments["iv_therapy"])){
                    $require_gfe = USER_STATE == 10 && $this->getCertificateType('35', USER_ID, $renew_flag) ? true : false;   
                }else{
                    // parches para iv
                    $array_treat = explode(',', $ent_treatment->treatments);
                    foreach($array_treat as $key => $value){
                        if($value == 0){
                            $require_gfe = USER_STATE == 10 && $this->getCertificateType('35', USER_ID, $renew_flag) ? true : false;
                        }
                    }
                }

                if($require_gfe){
                    $request_payment = empty($ent_payment) ? true : false;
                }else{
                    $request_payment = false;
                }

                $av_result = $this->gfeAvailability();

                $this->set('end_message', '');
                $this->set('skip_button', false);
                $this->set('has_iv_exam', USER_STATE != 10 ? false : true);
                $this->set('require_gfe', $require_gfe);
                $this->set('request_payment', $request_payment);
                $this->set('amount', empty($ent_payment) ? $this->get_amount() : $ent_payment->total);
                $this->set('available', $av_result);
                $this->set('available_message', "Thank you for signing up as a patient with MySpaLive! Our good faith examiners are available Monday-Saturday from 8 a.m - 8 p.m. If you have reached us outside of our business hours, holidays, etc., please feel free to schedule your exam for a specific date and time or reach back out to us during business hours OR (reconnect with us during business hours) Thank you!");
                $this->set('ondemando_flow', $ondemando_flow);
                $this->success();
                return;
            }

            $require_gfe = true;
            if($require_gfe){
                $request_payment = empty($ent_payment) ? true : false;
            }else{
                $request_payment = false;
            }

            $av_result = $this->gfeAvailability();

            $this->set('end_message', '');
            $this->set('skip_button', false);
            $this->set('has_iv_exam', false);
            $this->set('require_gfe', $require_gfe);
            $this->set('request_payment', $request_payment);
            $this->set('amount', empty($ent_payment) ? $this->get_amount() : $ent_payment->total);
            $this->set('available', $av_result);
            $this->set('available_message', "Thank you for signing up as a patient with MySpaLive! Our good faith examiners are available Monday-Saturday from 8 a.m - 8 p.m. If you have reached us outside of our business hours, holidays, etc., please feel free to schedule your exam for a specific date and time or reach back out to us during business hours OR (reconnect with us during business hours) Thank you!");
            
            $this->success();
            return;
        }
        //--------------------

        $user_id = USER_ID;
        $patient_uid = get('patient_uid','');
        if (!empty($patient_uid)) {
            $this->loadModel('SpaLiveV1.SysUsers');
            $ent_user = $this->SysUsers->find()->where(['SysUsers.uid' => $patient_uid])->first();
            if (!empty($ent_user)) {
                $user_id = $ent_user->id;
            }
        }

        $ent_payment = $this->DataPayment->find()
        ->where(['DataPayment.id_from' => $user_id, 'DataPayment.id_to' => 0,'DataPayment.type' => 'GFE', 'DataPayment.service_uid' => '','DataPayment.payment <>' => '','DataPayment.prepaid' => 1, 'DataPayment.comission_payed' => 1])->first();
        
        $av_result = $this->gfeAvailability();

        $require_gfe = true;

        $SummaryController = new SummaryController();

        $gfe_status = $SummaryController->gfeStatusForTreatment($user_id, 0);

        $require_gfe = $gfe_status == 'NOTSTARTED' || $gfe_status == 'DENIED';

        $request_payment = true;

        if($require_gfe){
            $request_payment = empty($ent_payment) ? true : false;
        }else{
            $request_payment = false;
        }

        $this->set('require_gfe', $require_gfe);
        $this->set('request_payment', $request_payment);
        $this->set('amount', empty($ent_payment) ? $this->get_amount() : $ent_payment->total);
        $this->set('available', $av_result);
        $this->set('available_message', "Thank you for signing up as a patient with MySpaLive! Our good faith examiners are available Monday-Saturday from 8 a.m - 8 p.m. If you have reached us outside of our business hours, holidays, etc., please feel free to schedule your exam for a specific date and time or reach back out to us during business hours OR (reconnect with us during business hours) Thank you!");
        
        $this->success();
    }

    public function getCertificateType($treatment, $user_id, $renew_flag = 0){
        $this->loadModel('SpaLiveV1.DataConsultation');
        $array_certificates = array();

        $ent_consultations = $this->DataConsultation->find()
        ->select([
            'DataConsultation.id', 
            'DataConsultation.uid', 
            'DataConsultation.status', 
            'DataConsultation.patient_id', 
            'DataConsultation.treatments', 
            'DataCertificates.date_expiration',
            'DataCertificates.certificate_url',
            'DataCertificates.uid'
        ])
        ->join([
            'DataCertificates'     => ['table' => 'data_certificates',      'type' => 'LEFT', 'conditions' => 'DataCertificates.consultation_id = DataConsultation.id'],
        ])->where([
            'DataConsultation.patient_id' => $user_id,
            'DataConsultation.treatments LIKE' => "%$treatment%",
            'DataConsultation.deleted' => 0
        ])->toArray();
        $result = true;
        foreach ($ent_consultations as $key => $row) {
            $status = $row->status;
            if($status == 'CERTIFICATE'){                
                $expired = $row['DataCertificates']['date_expiration'] < date('Y-m-d');
                $expires_soon = $row['DataCertificates']['date_expiration'] < date('Y-m-d', strtotime('+15 days'));
                if($expired){
                    continue;
                }else if($expires_soon && $renew_flag == 1){
                    continue;
                }else{
                    $result = false;
                    break;
                }
            } else if($status == 'INIT'){
                $result = false;
                break;
            }else{
                continue;
            }
        }

        return $result;
    }

    public function gfeAvailability($str_date = '') {

        if (empty($str_date)) {
            $hour = date('G'); // 0 to 23 hr 
            $minutes = date('i'); // 0 to 23 hr 
            $day = date('N'); // 0 to 23 hr 
        } else {
            $date_str = strtotime($str_date);
            $hour = date('G', $date_str);
            $minutes = date('i', $date_str);
            $day = date('N', $date_str);
        }

        $this->loadModel('SpaLiveV1.DataGfeAvailability');
        $ent_r = $this->DataGfeAvailability->find()->order(['DataGfeAvailability.id' => 'DESC'])->first();

        $av_result = true;
        if ($ent_r->available == 1 || !empty($str_date)) {
            if (strpos($ent_r->days, $day) === false) $av_result = false;
            $f_hour = $hour . $minutes; // now
            $s_hour = str_replace(':', '', $ent_r->start); //schedule start
            $e_hour = str_replace(':', '', $ent_r->end); //schedule end
            if ($f_hour < $s_hour || $f_hour > $e_hour) $av_result = false;
        } else {
            $av_result = false;
        }

        return $av_result;

    }

