        $obj_state = $this->CatStates->find()->select(['CatStates.name'])->where(['CatStates.id' => get('state',43)])->first();
                    
        $chain =  get('address','') . ' ' . get('city','') . ' ' . get('zip','') . ' ,' . $obj_state->name;

        $c_entity = $this->DataTreatment->newEntity($array_save);
       if(!$c_entity->hasErrors()) {
            if ($this->DataTreatment->save($c_entity)) {
                if($status == 'STOP'){
                    $Treatments = new TreatmentsController();
                    $Treatments->sendEmalStopRequest(USER_EMAIL, USER_NAME . ' ' . USER_LNAME, $notes, get('address','') . ', ' .get('city',''), date('m-d-Y H:i:s'), date('m-d-Y H:i:s', strtotime(get('schedule_date',''))), $treatment_uid);
                }
               $this->success();
            }
       }
       if($option_patient_model){
        $message_text="I want to be a patient model.";
       }else{
        if($injector_id === 0 ) 
            $message_text ="I need MySpaLive to recommend a provider." ;
        else
        $message_text ="I know my provider.";
       }
       $email = USER_EMAIL;
            if($email!=''){
