    public function school_application() {
        $this->loadModel('SpaLiveV1.DataSchoolRegister');


        $nameschool = get('nameschool', '');
        $rname = get('rname', '');
        $email = get('email', '');
        $schoolphone = get('schoolphone', '');
        $id_state = get('id_state', 43);
        if (empty($nameschool) || empty($rname) || empty($email) || empty($schoolphone) || empty($id_state)) {
            $this->message('Please fill all fields before submit.');
            return;
        }

        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            $this->message('Invalid email format.');
            return;
        }

        $ent_schoolregister = $this->DataSchoolRegister->new_entity([
            'uid'                   => Text::uuid(),
            'nameschool'            => $nameschool,
            'schoolweb'             => $rname,
            'rname'                 => get('rname', ''),
            'schoolphone'           => $schoolphone,
            'email'                 => $email,
            'address'               => get('address', ''),
            'city'                  => get('city', ''),
            'id_state'              => intval($id_state),
            'zip'                   => get('zip', ''),
            'certifications'        => get('certifications', ''),
            'additional_comments'   => get('additional_comments', ''),
        ]);


        if ($ent_schoolregister) $this->success();
    }

