    public function get_w9_bulk() {
        set_time_limit(0);
        ini_set('memory_limit','-1');

        $type = str_replace('-', '+', get('type', ''));
        $date_from = get('date_from', '');
        $date_to = get('date_to', '');
        $arr_types = ['clinic','examiner','injector','gfe+ci'];

        if (!$date_from|| !$date_to) {
            $this->message('You must specify a valid range of dates.');
            return;
        }

        if (!in_array($type, $arr_types)) {
            $this->message('Invalid type ' . $type);
            return;
        }

        $this->loadModel('SpaLiveV1.FileTray');

        $tray_uid = $this->FileTray->new_uid();
        $this->FileTray->new_entity([
            'uid'           => $tray_uid,
            'filename'      => 'W9Bulk-' . date('U') . '.pdf',
            // 'filename'      => 'W9Bulk-' . str_replace('-', '', $date_from) . '-' . str_replace('-', '', $date_to),
            'model'         => 'W9Bulk',
            'status'        => 'INIT',
            'params'        => json_encode([
                'model'     => 'W9Bulk',
                'type'      => $type,
                'date_from' => $date_from,
                'date_to'   => $date_to,
            ]),
            'mimetype'      => 'PDF',
        ]);

        $this->success();
        $this->set('tray_uid', $tray_uid);
        $this->set('command', (env('COMMAND_PATH', '') . ' filetray ' . $tray_uid . ' > /dev/null 2>&1 &'));

        shell_exec(env('COMMAND_PATH', '') . ' filetray ' . $tray_uid . ' > /dev/null 2>&1 &');
    }

    public function get_training_cert($return_path = false) {
        $this->loadModel('SpaLiveV1.CatTrainigs');


        $panel = get('l3n4p', '');
        $ftmpname="";
        if(empty($panel) || (!empty($panel) && $panel != '6092482f7ce858.91169218')){

            $token = get('token',"");

            if(!empty($token)){
                $user = $this->AppToken->validateToken($token, true);

                if($user === false){
                    $this->message('Invalid token.');
                    $this->set('session', false);
                    return;
                }
                $this->set('session', true);
            } else {
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
        }

        if (isset($user)) {

            $certItem = $this->CatTrainigs->find()->select(['User.name','User.mname','User.lname','CatTrainigs.scheduled','CatTrainigs.title','DataTrainigs.id','CatTrainigs.level'])
            ->join([
                'DataTrainigs' => ['table' => 'data_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainigs.id = DataTrainigs.training_id'],
                'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTrainigs.user_id']
            ])->where(['DataTrainigs.user_id' => USER_ID, 'DataTrainigs.id' => get('id', 0)])->first();

            if(empty($certItem)){
                $this->message('Training not found.');
                return;
            }

            $name = trim($user['name'].' '.((isset($user['mname']) && !empty($user['mname']) ?$user['mname'] : '' )).' '.$user['lname']);
            $ftmpname= $certItem['DataTrainigs']['id'];
        } else {

            if (get('cert_id', 0) > 0) {
                $certItem = $this->CatTrainigs->find()->where(['CatTrainigs.id' => get('cert_id', 0)])->first();
                $name = '';
            } else {

                $certItem = $this->CatTrainigs->find()->select(['User.name','User.mname','User.lname','CatTrainigs.scheduled','CatTrainigs.title','DataTrainigs.id','CatTrainigs.level'])
                ->join([
                    'DataTrainigs' => ['table' => 'data_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainigs.id = DataTrainigs.training_id'],
                    'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTrainigs.user_id']                    
                ])
                ->where(['User.uid' => get('user_uid', ''), 'DataTrainigs.id' => get('id', 0)])->first();
                if(empty($certItem)){
                    $this->message('Training not found.');
                    return;
                }
                $name = trim($certItem['User']['name'].' '.((isset($certItem['User']['mname']) && !empty($certItem['User']['mname']) ?$certItem['User']['mname'] : '' )).' '.$certItem['User']['lname']);
                $ftmpname= $certItem['DataTrainigs']['id'];
            }

            if(empty($certItem)){
                $this->message('Training not found.');
                return;
            }

            
        }

        $dates = $certItem['scheduled']->i18nFormat('MM/dd/yyyy');
        //iv therapy certificate
        
        if($certItem['level'] == 'LEVEL IV'){

            // $dates = date("m-d-Y", strtotime($user["created"]));
        
            $type_space = imagettfbbox(140, 0, './font/AlexBrush-Regular.ttf', $name);
            $text_width = abs($type_space[4] - $type_space[0]) + 10;
            
            $im   = imagecreatefrompng(TMP . "files/IV_Certificate_of_completion.png");
            $gray = imagecolorallocate($im, 30, 30, 30);
            $px   = (imagesx($im) - $text_width) / 2;
            imagettftext($im, 140, 0, (int)$px, 1250, $gray, './font/AlexBrush-Regular.ttf', $name);

            //imagettftext($im, 28, 0, 1430, 965, $gray, './font/Garet-Book.ttf', $dates);
            imagepng($im, TMP . "files/tmp_Train_Cert".$ftmpname.".png");
            imagedestroy($im);

            if (get('img',false)) {
                $fname = TMP . "files/tmp_Train_Cert".$ftmpname.".png";

                if (file_exists($fname)) {
                    $size = filesize(TMP . "files/tmp_Train_Cert".$ftmpname.".png");
                    if(get('return_path', true)){
                        return $fname;
                    }else{
                        header("Content-Type: image/png");
                        header("Content-Disposition: inline; filename=training_cert.png");
                        header("Content-Length: {$size}");
                        header('content-Transfer-Encoding:binary');
                        header('Accept-Ranges:bytes');
