        $cert_title = 'has successfully completed '.$certItem['title'].' on '.$dates;
        if (strlen($cert_title) > 70) {
            $tmp_title = wordwrap($cert_title, 70, "\n");
            $arr_strings = $arr_tttrr = explode("\n",$tmp_title);
            $cert_title = $arr_tttrr[0];
