    private function __child_invitees($level, $parent_id, $forSummary = false){
        $add_level = true;
        $network = $this->DataNetwork->find()->select(['SysUsers.id','DataNetwork.user_id','SysUsers.uid', 'SysUsers.name', 'SysUsers.mname', 'SysUsers.lname','SysUsers.active','SysUsers.email','SysUsers.short_uid'])
        ->join(['SysUsers' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'SysUsers.id = DataNetwork.user_id']])
        ->where([ 'DataNetwork.parent_id' => $parent_id, 'SysUsers.deleted' => 0, 'SysUsers.login_status' => 'READY'])->order(['SysUsers.active' => 'DESC'])->toArray();

        $result = [];
        if($level > 3){
            return $result;
        }

        foreach($network as $item){
            $need_add = false;
            if(intval($item->SysUsers['active']) == 1){
                $need_add = true;
                if($forSummary == true){
                    $result[] = [
                        'name' => $item->SysUsers['name'] . ' ' . $item->SysUsers['lname'],
                        'short_uid' => $item->SysUsers['short_uid'],
                        'user_id' => $item->SysUsers['id'],
                        'active' => $item->SysUsers['active'],
                        'email' => $item->SysUsers['email'],
                        'level' => $level,
                    ];
                }else{
                    $result[] = [
                        'id' => $item->SysUsers['id'],
                        'uid' => $item->SysUsers['uid'],
                        'name' => $item->SysUsers['name'],
                        'mname' => '',
                        'lname' => $item->SysUsers['lname'],
                        'active' => $item->SysUsers['active'],
                        'level' => $level,
                        'isChecked' => false
                    ];
                }
            }
            $result = array_merge($result, $this->__child_invitees($level + ($need_add == true ? 1 : 0) , $item->user_id, $forSummary));
        }
        return $result;
    }

    public function get_invitees_meeting(){
        $this->loadModel('SpaLiveV1.DataNetworkMeeting');
        $this->loadModel('SpaLiveV1.DataNetworkInvitees');
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $meeting_id = get('id', 0);
        if($meeting_id <= 0){
            $this->message('Invalid meeting id.');
            return;
        }

        $owner = $this->DataNetworkMeeting->find()->select(['SysUsers.uid', 'SysUsers.name', 'SysUsers.mname', 'SysUsers.lname'])
        ->join(['SysUsers' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'SysUsers.id = DataNetworkMeeting.createdby']])
        ->where(['DataNetworkMeeting.id' => $meeting_id])->first();

        $invitees = $this->DataNetworkInvitees->find()->select(['SysUsers.uid', 'SysUsers.name', 'SysUsers.mname', 'SysUsers.lname'])
        ->join(['SysUsers' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'SysUsers.id = DataNetworkInvitees.user_id']])
        ->where(['DataNetworkInvitees.meeting_id' => $meeting_id])->toArray();

        $result = [];
        foreach($invitees as $item){
            $result[] = [
                'uid' => $item->SysUsers['uid'],
                'name' => $item->SysUsers['name'],
                'mname' => $item->SysUsers['mname'],
                'lname' => $item->SysUsers['lname'],
            ];
        }

        $item_owner = [
            'uid' => $owner->SysUsers['uid'],
            'full_name' => $owner->SysUsers['name'] . ( !empty($owner->SysUsers['mname']) ? ' ' . $owner->SysUsers['mname'] : '')
                . (!empty($owner->SysUsers['lname']) ? ' ' . $owner->SysUsers['lname'] : '')
        ];

        $this->set('invitees', $result);
        $this->set('owner', $item_owner);
        $this->success();
    }

    public function cancel_meeting(){
        $this->loadModel('SpaLiveV1.DataNetworkMeeting');
        
        $token = get('token', '');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }


        $meeting_id = get('id', 0);
        if($meeting_id <= 0){
            $this->message('Invalid meeting.');
            return;
        }

        $meetingData = $this->DataNetworkMeeting->find()->where(['DataNetworkMeeting.id' => $meeting_id])->first();
        if(empty($meetingData)){
            $this->message('Invalid meeting.');
            return;
        }

        $zoom_token = $this->renewZoomToken();

        $str_url = "https://api.zoom.us/v2/meetings/" . $meetingData->zoom_meeting_id;
        $curl = curl_init();
        curl_setopt_array($curl, array(
          CURLOPT_URL => $str_url,
          CURLOPT_RETURNTRANSFER => true,
          CURLOPT_ENCODING => "",
          CURLOPT_MAXREDIRS => 10,
          CURLOPT_TIMEOUT => 30,
          CURLOPT_HTTP_VERSION => CURL_HTTP_VERSION_1_1,
          CURLOPT_CUSTOMREQUEST => "DELETE",
          CURLOPT_HTTPHEADER => array(
            "authorization: Bearer " . $zoom_token,
            "content-type: application/json"
          ),
        ));

        $response = curl_exec($curl);
        $err = curl_error($curl);

        if(!isset($err) || empty($err)){
            $meetingData->deleted = 1;
            $this->DataNetworkMeeting->save($meetingData);

            $skd_date = $meetingData->scheduled_date->i18nFormat('l dS \o\f F Y h:i:s A');
            $html_content = 'Hi,
                <br><br>
                The meeting scheduled on '.$skd_date.' was cancelled.';

            $str_qry_inv = "
            SELECT User.email FROM data_network_invitees DNI 
            INNER JOIN sys_users User ON User.id = DNI.user_id WHERE DNI.meeting_id = {$meeting_id}
            ";
            $invitees = $this->DataNetworkMeeting->getConnection()->execute($str_qry_inv)->fetchAll('assoc');
            
            foreach($invitees as $item){
                $data=array(
                    'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                    'to'      => $item['email'],
                    'subject' => 'Network meeting cancelled',
                    'html'    => $html_content,
                );

                $mailgunKey = $this->getMailgunKey();

                $curl = curl_init();
                curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
                curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
                curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
                curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
                curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
                curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
                curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
                curl_setopt($curl, CURLOPT_POST, true); 
                curl_setopt($curl, CURLOPT_POSTFIELDS, $data);

                $result = curl_exec($curl);
                curl_close($curl);
            }

            $this->success();
        }
    }

    public function refund_payment_global(){
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        
        $uid = get('uid', '');
        $id = get('id', 0);
        $total = get('total', 0);
        
        $this->loadModel('SpaLiveV1.DataPayment');

        
        $ent_payment = $this->DataPayment->find()->where([
            'DataPayment.id' => $id,
            'DataPayment.uid' => $uid,
            // 'DataPayment.refund_id' => 0,
            'DataPayment.is_visible' => 1,
        ])->first();

        // pr($ent_payment);
        // exit;

        if (!empty($ent_payment)) {
            $total_refund = get('total_refund', 0);
            if ($total_refund <= 0 || $total_refund > $ent_payment->total) {
                $this->message('Invalid refund mount.');
                return false;
            }

            $total_refund = $total_refund * 100;
        } else {
            $this->message("You can't refund this payment.");
            return false;
        }
        

        $ent_payment_refunds = $this->DataPayment->find()->where([
            'DataPayment.uid' => $ent_payment->uid,
            'DataPayment.intent' => $ent_payment->intent,
            'OR' => [
                ['DataPayment.type' => 'REFUND'],
                ['DataPayment.type' => 'REFUND PRODUCT'],
            ],
            'DataPayment.is_visible' => 1,
        ]);

        if (!empty($ent_payment_refunds)) {
            // pr($ent_payment_refunds->toArray());
            // exit;
            $total_refunded = 0;
            foreach ($ent_payment_refunds as $key => $ref) {
                $total_refunded += $ref->total;
            }

            $max_refund = ($ent_payment->total - $total_refunded);

            if ($max_refund <= 0) {
                $this->message('This payment has no more money to refund.');
                return false;
            }
        }

        $error = "";
        try {
            $re = \Stripe\Refund::create([
                'amount' => $total_refund,
                'payment_intent' => $ent_payment->intent,
            ]);

            // pr($this->set('re', $re));
            // return;
            if ($re) {
                $arr_payment_refund = [
                    'id_from'           => 0,
                    'id_to'             => $ent_payment->id_from,
                    'uid'               => $ent_payment->uid,
                    'type'              => 'REFUND',
                    'intent'            => $ent_payment->intent,
                    'payment'           => '',
                    'receipt'           => $ent_payment->receipt,
                    'discount_credits'  => 0,
                    'promo_discount'    => '',
                    'promo_code'        => '',
                    'subtotal'          => $total_refund,
                    'total'             => $total_refund,
                    'prod'              => 1,
                    'is_visible'        => 1,
                    'comission_payed'   => 1,
                    'comission_generated'   => 0,
                    'prepaid'           => 0,
                    'created'           => date('Y-m-d H:i:s'),
                    'createdby'         => defined('USER_ID') ? USER_ID : 0,
                    'state'            => $ent_payment->state,
                ];

                $c_entity = $this->DataPayment->newEntity($arr_payment_refund);

                if(!$c_entity->hasErrors()) {
                    $ent_refund = $this->DataPayment->save($c_entity);

                    if ($ent_refund->total == $ent_payment->total || $ent_refund->total == ($ent_payment->total - 5000)){
                        $this->DataPayment->updateAll(['refund_id' => $ent_refund->id], ['id' => $ent_payment->id]); 
                    }
                    
                    //Deactivate the course for the injectors who want to get a refund for the training classes
                    if($ent_payment->type =='ADVANCED COURSE' ){//|| $ent_payment->type =='BASIC COURSE'){
                        //advanced course
                        $this->loadModel('SpaLiveV1.DataTrainings');
                        $advanced_course = $this->DataTrainings->find()->
                        join([
                            'Training' => ['table' => 'cat_trainings', 'type' => 'LEFT', 'conditions' => 'Training.id = DataTrainings.training_id'],
                        ])->
                        where([
                            'DataTrainings.user_id' => $ent_payment->id_from,
                            'DataTrainings.deleted' => 0,
                            'Training.level' => 'LEVEL 2'
                        ])->first();
                        if(!empty($advanced_course)){
                            // update table DataTrainings deleted  = 0
                            if ($ent_refund->total == $ent_payment->total || $ent_refund->total == ($ent_payment->total - 5000)){
                                $this->DataTrainings->updateAll(['deleted' => 1], ['id' => $advanced_course->id]);
                            }
                            
                        }

                        //has basic course
                        $this->loadModel('SpaLiveV1.DataTrainings');
                        $basic_course = $this->DataTrainings->find()->
                        join([
                            'Training' => ['table' => 'cat_trainings', 'type' => 'LEFT', 'conditions' => 'Training.id = DataTrainings.training_id'],
                        ])->
                        where([
                            'DataTrainings.user_id' => $ent_payment->id_from,
                            'DataTrainings.deleted' => 0,
                            'Training.level' => 'LEVEL 1'
                        ])->first();
                        $this->loadModel('SpaLiveV1.SysUsers');
                        if(empty($basic_course)){               
                            //not course founded, need buy the basic course
                            $this->SysUsers->updateAll(['steps' => 'BASICCOURSE'], ['id' => $ent_payment->id_from]); 
                        }else{
                            if($basic_course->attended ==1){
                                $this->validate_step();
                            }else{
                                $this->SysUsers->updateAll(['steps' => 'MATERIALS'], ['id' => $ent_payment->id_from]); 
                            }
                        }

                    } else if($ent_payment->type =='BASIC COURSE' ){//|| $ent_payment->type ==''){
                        //advanced course
                        $this->loadModel('SpaLiveV1.DataTrainings');
                        $advanced_course = $this->DataTrainings->find()->
                        join([
                            'Training' => ['table' => 'cat_trainings', 'type' => 'LEFT', 'conditions' => 'Training.id = DataTrainings.training_id'],
                        ])->
                        where([
                            'DataTrainings.user_id' => $ent_payment->id_from,
                            'DataTrainings.deleted' => 0,
                            'Training.level' => 'LEVEL 1'
                        ])->first();
                        if(!empty($advanced_course)){
                            // update table DataTrainings deleted  = 0
                            if ($ent_refund->total == $ent_payment->total || $ent_refund->total == ($ent_payment->total - 5000)){
                                $this->DataTrainings->updateAll(['deleted' => 1], ['id' => $advanced_course->id]);
                            }
                            
                        }

                        //has advanced course
                        $this->loadModel('SpaLiveV1.DataTrainings');
                        $basic_course = $this->DataTrainings->find()->
                        join([
                            'Training' => ['table' => 'cat_trainings', 'type' => 'LEFT', 'conditions' => 'Training.id = DataTrainings.training_id'],
                        ])->
                        where([
                            'DataTrainings.user_id' => $ent_payment->id_from,
                            'DataTrainings.deleted' => 0,
                            'Training.level' => 'LEVEL 2'
                        ])->first();
                        $this->loadModel('SpaLiveV1.SysUsers');
                        if(empty($basic_course)){               
                            //not course founded, need buy the basic course
                            $this->SysUsers->updateAll(['steps' => 'BASICCOURSE'], ['id' => $ent_payment->id_from]); 
                        }else{
                            if($basic_course->attended ==1){
                                $this->validate_step();
                            }else{
                                $this->SysUsers->updateAll(['steps' => 'MATERIALS'], ['id' => $ent_payment->id_from]); 
                            }
                        }

                    } else {

                        $this->loadModel('SpaLiveV1.DataTrainings');

                        $other_course = $this->DataTrainings->find()->
                            join([
                                'Training' => ['table' => 'cat_trainings', 'type' => 'LEFT', 'conditions' => 'Training.id = DataTrainings.training_id'],
                            ])->
                            where([
                                'DataTrainings.user_id' => $ent_payment->id_from,
                                'DataTrainings.deleted' => 0,
                                'Training.level' => $ent_payment->type
                            ])->first();
                            if(!empty($other_course)){
                                // update table DataTrainings deleted  = 0
                                if ($ent_refund->total == $ent_payment->total || $ent_refund->total == ($ent_payment->total - 5000)){
                                    $this->DataTrainings->updateAll(['deleted' => 1], ['id' => $other_course->id]);
                                }
                                
                        }

                    }


                    // $ent_payment->refund_id = $ent_refund->id;
                    $this->success();
                    $this->message('Payment refunded successfully.');
                } else {
                    $this->message('The was an error trying to refund the payment.');
                    return false;
                }
            }

        } catch(Stripe_CardError $e) {
            $error = $e->getMessage();
        } catch (Stripe_InvalidRequestError $e) {
            // Invalid parameters were supplied to Stripe's API
            $error = $e->getMessage();
        } catch (Stripe_AuthenticationError $e) {
            // Authentication with Stripe's API failed
            $error = $e->getMessage();
        } catch (Stripe_ApiConnectionError $e) {
            // Network communication with Stripe failed
            $error = $e->getMessage();
        } catch (Stripe_Error $e) {
            // Display a very generic error to the user, and maybe send
            // yourself an email
            $error = $e->getMessage();
        } catch (Exception $e) {
            // Something else happened, completely unrelated to Stripe
            $error = $e->getMessage();
        } catch(\Stripe\Exception\CardException $e) {
            // Since it's a decline, \Stripe\Exception\CardException will be caught
            $error = $e->getMessage();
        } catch (\Stripe\Exception\RateLimitException $e) {
            // Too many requests made to the API too quickly
            $error = $e->getMessage();
        } catch (\Stripe\Exception\InvalidRequestException $e) {
            // Invalid parameters were supplied to Stripe's API
            $error = $e->getMessage();
        } catch (\Stripe\Exception\AuthenticationException $e) {
            // Authentication with Stripe's API failed
            // (maybe you changed API keys recently)
            $error = $e->getMessage();
        } catch (\Stripe\Exception\ApiErrorException $e) {
            // Display a very generic error to the user, and maybe send
            // yourself an email
            $error = $e->getMessage();
        }

        if ($error) {
            $this->message($error);
            return false;
        }
    }

    public function refund_product(){
        $this->loadModel('SpaLiveV1.DataPurchases');
        $this->loadModel('SpaLiveV1.DataPurchasesDetail');
        $this->loadModel('SpaLiveV1.SysUsers');

        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        
        $uid = get('uid','');
        $amount = get('amount', 0);

        $purchase = $this->DataPurchases->find()->where(['DataPurchases.uid' => $uid])->first();
        if(empty($purchase)){
            $this->message('Invalid purchase.');
            return;
        }


        if(!empty($purchase)){
            
            $error = "";
            try {
                if($amount > 0){
                    $re = \Stripe\Refund::create([
                        'amount' => $amount,
                        'payment_intent' => $purchase->payment,
                    ]);

                    if ($re) {
                        $this->success();
                    }
                }else{
                    $this->message('Insufficient quantity.');
                }   
            } catch(Stripe_CardError $e) {
                $error = $e->getMessage();
            } catch (Stripe_InvalidRequestError $e) {
                // Invalid parameters were supplied to Stripe's API
                $error = $e->getMessage();
            } catch (Stripe_AuthenticationError $e) {
                // Authentication with Stripe's API failed
                $error = $e->getMessage();
            } catch (Stripe_ApiConnectionError $e) {
                // Network communication with Stripe failed
                $error = $e->getMessage();
            } catch (Stripe_Error $e) {
                // Display a very generic error to the user, and maybe send
                // yourself an email
                $error = $e->getMessage();
            } catch (Exception $e) {
                // Something else happened, completely unrelated to Stripe
                $error = $e->getMessage();
            } catch(\Stripe\Exception\CardException $e) {
                // Since it's a decline, \Stripe\Exception\CardException will be caught
                $error = $e->getMessage();
            } catch (\Stripe\Exception\RateLimitException $e) {
                // Too many requests made to the API too quickly
                $error = $e->getMessage();
            } catch (\Stripe\Exception\InvalidRequestException $e) {
                // Invalid parameters were supplied to Stripe's API
                $error = $e->getMessage();
            } catch (\Stripe\Exception\AuthenticationException $e) {
                // Authentication with Stripe's API failed
                // (maybe you changed API keys recently)
                $error = $e->getMessage();
            } catch (\Stripe\Exception\ApiErrorException $e) {
              // Display a very generic error to the user, and maybe send
              // yourself an email
              $error = $e->getMessage();
            }
            if(!empty($error)) $this->message($error);
        }
    }

