        $currentDayCreated = strtotime(date('Y-m-01'));

        $dates = [];
        $year = 0;
        $i = 0;
        $yearIndex = -1;

        while( $lastDayMonth < $currentDayCreated ) {
            if ($year != date('Y', $currentDayCreated)) {
                $year = date('Y', $currentDayCreated);

                $dates[] = [
                    'year'  => $year,
                    'data'  => []
                ];

                $yearIndex++;
            }

            $dates[$yearIndex]['data'][] = [
                'year'      => $year,
                'month'     => date('m', $currentDayCreated),
                'month_txt' => date('F', $currentDayCreated),
                'yearMonth' => date('Y-m', $currentDayCreated),
                'url'       => $this->URL_API . '?action=monthly_statement&token=' . $token . '&yearMonth=' . date('Y-m', $currentDayCreated)
            ];

            $i++;
            $currentDayCreated = strtotime('-1 month', $currentDayCreated);
        }

        if(USER_TYPE == 'injector' || USER_TYPE == 'gfe+ci'){
            $this->summarySubscriptions();
            $Subscription = new SubscriptionController();
            $allowHoldTrial = $Subscription->allow_hold_trial(USER_ID);
            $this->set('allow_hold_trial', $allowHoldTrial);
        }

        if ($return_value) return ['account' => $data, 'user' => $user];
        else {
            $this->set('data', $data);
            $this->set('statement_date_blocks', $dates);
            $this->set('show_button_more', count($data['incomes']) < 20 ? false : true);
            $this->success();
        }
    }    

    public function more_incomes(){
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataPayment');
        $accountUsr = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();

        $id_income = get('id_income','');

        if(empty($id_income)){
            $this->message('Empty income.');
            return;
        }

        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));

        $account = $stripe->accounts->retrieve($accountUsr->stripe_account,[]);

        $last_obj = $stripe->transfers->retrieve(
            $id_income,
            []
        );

        if(Count($last_obj) == 0){
            $this->message('Invalid income.');
            return;
        }

        $arr_transfers = [];
        $arr_stripe_conditions = ['destination' => $accountUsr->stripe_account, 'limit' => 20, 'starting_after' => $last_obj];

        $transfers = $stripe->transfers->all($arr_stripe_conditions);

        if(Count($transfers) < 0){
            $this->message('No more incomes.');
            $this->success(true);
            return;
        }

        $where_income = [
            'OR' => [
                ['DataPayment.type' => 'CI COMMISSION'],
                ['DataPayment.type' => 'GFE COMMISSION'],
                /* ['DataPayment.type' => 'TIP COMMISSION'], */
            ],
            'DataPayment.id_to' => USER_ID,
        ];

        $data = [];

        foreach($transfers->data as $item){
            if(!empty($item['transfer_group'])) $where_income['DataPayment.uid'] = $item['transfer_group'];
            $desc = $item['description'];
            if(empty($desc)) continue;
            $payBay = $this->DataPayment->find()->select(['DataPayment.id', 'pay_by' => "CONCAT_WS(' ', UsrPay.name, UsrPay.lname)", 'UsrPay.uid','DataPayment.id_from', 'DataPayment.type', 'DataPayment.uid'])->join([
                'UsrPay' => ['table' => 'sys_users', 'type' => 'LEFT', 'conditions' => 'UsrPay.id = DataPayment.id_from'],
            ])->where($where_income)->first();

            if ($payBay) {
                $rr_type = $payBay->type;
                $tm_arr = [
                    "invoice"  => intval(env('INVOICE_START', 1500) + $payBay["id"]),
                    "amount" => $item["amount"],
                    "amount_reversed" => $item["amount_reversed"],
                    "created" => date( 'Y-m-d H:i:s', $item["created"]),
                    "currency" => $item["currency"],
                    "description" => ($payBay->id_from == 0 && strpos($item["description"], 'CI COMMISSION') !== false ? 'CI commision' : 
                        ($payBay->id_from > 0 && strpos($item["description"], 'CI COMMISSION') !== false ? 'Network commission' : $item["description"])),
                    "transfer_group" => $item["transfer_group"],
                    "status" => 'Paid',
                    "origin_by" => ((!empty($payBay) && !empty($payBay->pay_by)) ? $payBay->pay_by : ($payBay->id_from == 0 ? ($rr_type == 'GFE' || $rr_type == 'TREATMENT' ? 'Zachary Cannon, MD' : 'MySpaLive') : '')),
                    "id_from"   => $payBay->id_from,
                    "id" => $item['id']
                ];
                
                if ($rr_type == 'GFE COMMISSION' || $rr_type == 'CI COMMISSION'){
                    $tgp_uid = $payBay->uid;
                    $usr_uid = $user['uid'];
                    $tm_arr['spalive_receipt'] = "{$this->URL_API}?action=rcpt&uid={$usr_uid}&trgp={$tgp_uid}";
                }

                $data['incomes'][] = $tm_arr;
            }
        }

        $this->set('data', $data);
        $this->success();
    }

