    public function send_panel_notification(){
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $user_uid = get('user_uid', '');
        $type = get('type','');
        $body = get('body',''); 

        $this->loadModel('SpaLiveV1.SysUsers');
        $ent_user = $this->SysUsers->find()->where(['SysUsers.deleted' => 0,'SysUsers.uid' => $user_uid])->first();
        
        if (!empty($ent_user)){
            $users_array = array( $ent_user->id );
            if($type == 'NOTIFICATION'){
                $this->notify_devices($body,$users_array,true,false);
            }else if('SMS'){
                $this->notify_devices($body,$users_array,false,false, true, array(), '', array(), true, true);
            }

        }

    }

    public function verify_schedule_disponibility() {
