        $str_total_query = "SELECT 
            (SELECT COUNT(U.id) FROM sys_users U WHERE login_status = 'CHANGEPASSWORD' AND deleted = 0 AND active = 1 AND type = 'patient' {$U}) as total_no_app_patient,
            (SELECT COUNT(U.id) FROM sys_users U WHERE login_status = 'READY' AND deleted = 0 AND active = 1 AND createdby = 0 AND type = 'patient' {$U}) as uninvited_patient,
