            (SELECT COUNT(U.id) FROM sys_users U WHERE login_status = 'PAYMENT' AND deleted = 0 AND active = 1 AND type = 'injector' {$U}) as total_ci_pending_payment,
            (SELECT COUNT(U.id) FROM sys_users U WHERE deleted = 0 AND active = 1 AND type = 'examiner' {$U}) as total_examiner,
            (SELECT COUNT(U.id) FROM sys_users U WHERE login_status = 'READY' AND deleted = 0 AND active = 1 AND type = 'examiner' {$U}) as ready_examiner,
