    public function report_training_attended(){
        $t_id = get('id',0);
        if ($t_id == 0) return;
         $now = date('Y-m-d H:i:s');

        $this->loadModel('SpaLiveV1.DataTrainings');

        $fields = ['DataTrainings.id','User.name','User.lname','User.email','User.uid','User.phone', 'DataTrainings.attended', 'CatTrainings.title', 'CatTrainings.scheduled'];
        $fields['show_certificate'] = "(IF('{$now}' > CatTrainings.scheduled,1,0))";

        $ent_trainings = $this->DataTrainings->find()->select($fields)
        ->join([
            'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataTrainings.user_id'],
            'CatTrainings' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainings.id = DataTrainings.training_id']
        ])->where(['User.deleted' => 0, 'User.active' => 1,'User.login_status IN' => array('READY', 'APPROVE', 'W9'),'DataTrainings.training_id' => $t_id,'DataTrainings.deleted' => 0])->order(['User.name' => 'ASC'])->all();

        
        if(!empty($ent_trainings)){
            $result = array();
            foreach($ent_trainings as $row) {
                $result[] = array(
                    'id' => $row->id,
                    'show_certificate' => intval($row->show_certificate),
                    'user_uid' => $row['User']['uid'],
                    'name' => $row['User']['name'] . ' ' . $row['User']['lname'] . ' (' . $row['User']['email'] . ')',
                    'phone' => $row['User']['phone'],
                    'attended' => $row->attended,
                    'title' => $row['CatTrainings']['title'],
                    'scheduled' => $row['CatTrainings']['scheduled']
                );
            }
        } 
        $title = '';
        $html = '';
        $html2 = '';
        $count = 0;
        if(!empty($result)){
            $title = $result[0]['title'];
