    public function download_last_report() {
        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
        }

        $this->loadModel('SpaLiveV1.SysReport');

        $_where = ['SysReport.deleted' => 0];

        $ent_report = $this->SysReport->find()
            ->where($_where)
            ->order(['SysReport.report_to' => 'DESC'])
            ->first();
        
        if (empty($ent_report)) {
            $this->success(false);
            $this->message("There's not generated reports.");
        } else {
            $filepath = TMP . 'reports' . DS . $ent_report->name;
            $size = filesize($filepath);
            
            // $this->set('filepath', $filepath);
            // $this->set('test', $ent_report->name);return;

            // header("Content-Type: application/pdf");
            // header("Content-Disposition: attachment; filename={$ent_report->name}");
            // header("Content-Length: {$size}");
            // echo file_get_contents($filepath)
            
            // $this->set('file', file_get_contents($filepath));
            $this->set('size', filesize($filepath));
            $this->set('name', $ent_report->name);
            $this->set('filepath', $filepath);
            $this->success(true);

            // exit;
        }
    }

    public function send_general_report() {
        
        $this->loadModel('SpaLiveV1.SysReport');

        $_where = ['SysReport.deleted' => 0];

        $ent_report = $this->SysReport->find()
            ->where($_where)
            ->order(['SysReport.report_to' => 'DESC'])
            ->first();
        
        if (empty($ent_report)) {
            $this->success(false);
            $this->message("There's not generated reports.");
        } else {
            $filepath = TMP . 'reports' . DS . $ent_report->name;

            $data = array(
                'from'    => 'MySpaLive <noreply@mg.myspalive.com>',
                'to'      => 'ashlan@myspalive.com,cassandra@myspalive.com',
                // 'to'      => 'jorge.alejandro.puente@gmail.com',
                // 'to'      => 'khanzab@gmail.com',
                'subject' => 'General report MySpaLive',
                'html'    => 'This is the general report from ' . $ent_report->report_from->i18nFormat('MM/dd/yyyy') . ' to ' . $ent_report->report_to->i18nFormat('MM/dd/yyyy') . '<br><br> This was generated ' . $ent_report->created->i18nFormat('MM/dd/yyyy hh:mm a'),
                'attachment[1]' => curl_file_create($filepath, 'application/pdf', $ent_report->name),
            );

            $mailgunKey = $this->getMailgunKey();
    
    
            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_HTTPHEADER, array('Content-Type: multipart/form-data'));
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);
    
            $result = curl_exec($curl);
            curl_close($curl);
            
            
            $this->success(true);
        }
    }

    public function monthly_statement() {
        $type = get('type', 'pdf');
        $token = get('token', 'pdf');
        $userType = get('userType', 'pdf');
        $userUid = get('userUid', 'pdf');
        $yearMonth = trim(get('yearMonth', ''));
        $fullDate = $yearMonth . '-01';

        if (empty($yearMonth)) {$this->message('Invalid date.');return;}

        $firstDay = date('Y-m-01', strtotime($fullDate));
        $lastDay =  date('Y-m-t', strtotime($fullDate));

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }


        // $user['user_id'] = 1;
        $arr_data = ($user['user_id'] == 1 ? $this->check_account_spalivemd(true, $user, $firstDay, $lastDay) : $this->check_account(true, $user, $firstDay, $lastDay));



        // pr('$arr_data');
        // pr($arr_data);
        // exit;
        $arr_account = $arr_data['account'];
        $user = $arr_data['user'];

        foreach($arr_account['incomes'] as $key => $income) {
            $arr_account['incomes'][$key]['type'] = 'income';
            $arr_account['incomes'][$key]['amount'] = '$' . number_format(($income['amount'] / 100), 2);
        }

        foreach($arr_account['expenses'] as $key => $expense) {
            $arr_account['expenses'][$key]['type'] = 'expense';
            $arr_account['expenses'][$key]['total'] = '$' . number_format(($expense['total'] / 100), 2);
            $arr_account['expenses'][$key]['subtotal'] = '$' . number_format(($expense['subtotal'] / 100), 2);
        }

        $arr_balance = array_merge($arr_account['incomes'], $arr_account['expenses']);

        usort($arr_balance, function($a, $b) {
            return strtotime($a["created"]) - strtotime($b["created"]);
        });

        if ($type == 'pdf') $this->monthly_statement_pdf($arr_balance, $firstDay, $lastDay, $user);
        elseif ($type == 'xlsx') $this->monthly_statement_xlsx($arr_balance, $firstDay, $lastDay, $user);
    }

    private function monthly_statement_pdf($arr_balance, $firstDay, $lastDay, $user) {
        $html2pdf = new HTML2PDF('F','A4','en', true, 'UTF-8', array(10,10,10,10));

        $fullname = trim(trim($user['name'] . ' ' . $user['mname']) . ' ' . $user['lname']);
        $str_balance = '';

        // pr($arr_balance);
        // exit;

        foreach($arr_balance as $key => $balance) {
            $str_balance .= "
                <tr style=\"border-spacing: 0;\">
                    <td style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef;\">" . date('F d', strtotime($balance['created'])) . "</td>
                    <td style=\"padding: 2mm; width: 72mm; border-bottom: 1px solid #e4e6ef;\">" . $balance['invoice'] . ' - ' . ($balance['type'] == 'expense' ? $balance['detail'] : $balance['description']) . "</td>
                    <td style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef; text-align: right;\">" . ($balance['type'] == 'expense' ? ('- ' . $balance['total']) : '') . "</td>
                    <td style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef; text-align: right;\">" . ($balance['type'] == 'income' ? $balance['amount'] : '') . "</td>
                </tr>";
        }

        if ($str_balance == '') {
            $str_balance .= "
                <tr style=\"border-spacing: 0;\">
                    <td colspan=\"4\" style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef;\"><i>No transactions.</i></td>
                </tr>";
        }

        // $url_root = $this->URL_ROOT . "api";
        
        $html2pdf->writeHTML("
            <page style=\"width: 190mm; height: 277mm; position:relative; color: #373a48;\">
                    <img src=\"" . $this->URL_API . "img/logo.png\" style=\"width:50mm;\">

                    <table style=\"margin-top: 10mm;\">
                        <tr>
                            <td style=\"width: 110mm;\">
                                <h1 style=\"font-size: 22px; margin: 0mm 0 0;\">MySpaLive Monthly Statement</h1>
                            </td>
                            <td style=\"width: 75mm; text-align: right;\">
                                <p style=\"margin: 0; font-size: 15px;\">" . $fullname . "</p>
                                <p style=\"margin: 1mm 0 0; font-size: 13px;\"><i>" . $user['email'] . "</i></p>

                                <p style=\"margin: 5mm 0 0; font-size: 15px;\"><b>For " . date('F d', strtotime($firstDay)) . " to " . date('F d Y', strtotime($lastDay)) . "</b></p>
                            </td>
                        </tr>
                    </table>

                    <table style=\"margin-top: 10mm; width: 185mm; border-spacing: 0; border-collapse: collapse; color: #525560;\">
                        <tr>
                            <td colspan=\"4\" style=\"border-bottom: 1px solid #373a48; padding: 2mm;\">
                                <p style=\"margin: 0; font-weight: bold; font-size: 15px;\">Transaction's summary</p>
                            </td>
                        </tr>
                        <tr style=\"font-weight: bold;  border-spacing: 0;\">
                            <td style=\"padding: 2mm; width: 28mm; border-bottom: 1px solid #373a48;\">Date</td>
                            <td style=\"padding: 2mm; width: 72mm; border-bottom: 1px solid #373a48;\">Invoice - Description</td>
                            <td style=\"padding: 2mm; width: 28mm; border-bottom: 1px solid #373a48; text-align: right;\">Expenses</td>
                            <td style=\"padding: 2mm; width: 28mm; border-bottom: 1px solid #373a48; text-align: right;\">Income</td>
                        </tr>

                        " . $str_balance . "
                    </table>

                <!-- <page_footer>
                    <div style=\"text-align: center; font-size: 15px;\">
                        [[page_cu]]/[[page_nb]]
                    </div>
                </page_footer> -->
            </page>");

        $html2pdf->Output('monthly_statement.pdf', 'I');
    }

