    private function check_account_spalivemd($return_value = false, $user = [], $firstDay = '2022-01-01', $lastDay = '2022-01-31'){
        $this->loadModel("SpaLiveV1.SysUsers");
        $this->loadModel("SpaLiveV1.DataPayment");
        $token = get('token',"");
        
        $labelDetail = [
            'GFE' => "Certificate request",
            'TREATMENT' => "Treatment services",
            'PURCHASE' => "Product purchase",
        ];

        $data = [
            'bank' => "",
            'amount_transfers' => 0,
            'disabled_reason' => "",
            'incomes' => [],
            'expenses' => [],
        ];
        $fields = ['DataPayment.id', 'DataPayment.type','DataPayment.total','DataPayment.subtotal','DataPayment.receipt','DataPayment.created','DataPayment.id_to','DataPayment.uid',
            "provider_by" => "
            (IF(
                DataPayment.type = 'GFE', 
                IFNULL( (SELECT CONCAT_WS(' ', Ug.name, Ug.lname) FROM data_consultation Cons INNER JOIN sys_users Ug ON Ug.id = Cons.assistance_id WHERE Cons.uid = DataPayment.service_uid), '' ) , 
                IFNULL( (SELECT CONCAT_WS(' ', Ug.name, Ug.lname) FROM data_treatment Treat INNER JOIN sys_users Ug ON Ug.id = Treat.assistance_id WHERE Treat.uid = DataPayment.uid), '' )
            ))", 'UsrPay.uid'
        ];

        $payBay = $this->DataPayment->find()->select(['DataPayment.id', 'pay_by' => "CONCAT_WS(' ', UsrPay.name, UsrPay.lname)", 'UsrPay.uid', 'UsrPay.name', 'UsrPay.mname', 'UsrPay.lname', 'DataPayment.id_from', 'DataPayment.type', 'DataPayment.uid', 'DataPayment.created', 'DataPayment.total'])
        ->join([
            'UsrPay' => ['table' => 'sys_users', 'type' => 'LEFT', 'conditions' => 'UsrPay.id = DataPayment.id_from'],
        ])->where([
            'DataPayment.is_visible' => 1,
            'DataPayment.payment <>' => '',
            'DataPayment.id_to' => 0,
            'DATE(DataPayment.created) >=' => $firstDay,
            'DATE(DataPayment.created) <=' => $lastDay
        ])->toArray();

        // pr($payBay);
        // exit;

        foreach($payBay as $item){
            $data['amount_transfers'] += $item['total'];
            $desc = $item['description'];

            // pr($payBay);
            // pr('--------------------');
            // exit;
                $tm_arr = [
    
                    "invoice"  => intval(env('INVOICE_START', 1500) + $item["id"]),
                    "amount" => $item["total"],
                    "created" => date( 'Y-m-d H:i:s', strtotime($item["created"]->i18nFormat('Y-MM-dd HH:mm:ss'))),
                    "currency" => 'USD',
                    "description" => ($item->id_from == 0 && strpos($item["type"], 'CI COMMISSION') !== false ? 'CI commision' : 
                        ($item->id_from > 0 && strpos($item["type"], 'CI COMMISSION') !== false ? 'Network commission' : $item["type"])),
                    "transfer_group" => $item["transfer_group"],
                    "status" => 'Paid',
                    "origin_by" => trim(trim($item->UsrPay['name'] . ' ' . $item->UsrPay['mname']) . ' ' . $item->UsrPay['name']),
                    "id_from"   => $item->id_from
                ];
                // pr($tm_arr);
                // pr('--------------------');
                $rr_type = $item->type;
    
                $data['incomes'][] = $tm_arr;
        }
        // pr($data);
        // exit;
        // exit;

        $fields['provider'] = "CONCAT_WS(' ', UsrPay.name, UsrPay.lname)";
        // $fields[] = 'DataPurchases.status';
        $payments = $this->DataPayment->find()->select($fields)->join([
            'UsrPay' => ['table' => 'sys_users', 'type' => 'LEFT', 'conditions' => 'UsrPay.id = DataPayment.id_to'],
            // 'DataPurchases' => ['table' => 'data_purchases', 'type' => 'INNER', 'conditions' => 'DataPurchases.uid = DataPayment.uid'],
        ])->where([
            'DataPayment.payment <>' => '',
            'DataPayment.is_visible' => 1,
            'DataPayment.id_to <>' => 0,
            'OR' => [
                ['DataPayment.type' => 'CI COMMISSION'],
                ['DataPayment.type' => 'GFE COMMISSION'],
            ],
            'DATE(DataPayment.created) >=' => $firstDay,
            'DATE(DataPayment.created) <=' => $lastDay
        ]);

    // pr('$payments');
    // pr(debug($payments));
    // exit;
        // $labelDetail = [
        //     'GFE' => "Certificate request",
        //     'GFE COMISSION' => "Certificate request",
        //     'TREATMENT' => "Treatment services",
        //     'PURCHASE' => "Product purchase",
        // ];

        foreach($payments as $item){
            $rr_type = $item["type"];
            $tm_arr = [
                "invoice"  => intval(env('INVOICE_START', 1500) + $item["id"]),
                "detail"   => $rr_type,
                "total"    => $item["total"],
                "id_to"    => $item["id_to"],
                "created"  => $item["created"]->i18nFormat('Y-MM-dd HH:mm:ss'),
                "subtotal" => $item["subtotal"],
                "receipt"  => $item["receipt"],
                "status"   => 'Paid',//$item->DataPurchases['status'],
                "provider" => ((!empty($item) && !empty($item->provider)) ? $item->provider : ($item->id_to == 0 ? 'SpaLiveMD' : '')),
                // "transfer_group" => $item["uid"],
            ];

            $data['expenses'][] = $tm_arr;
        }

        if ($return_value) return ['account' => $data, 'user' => $user];
        else {
            $this->set('data', $data);
            $this->success();
        }
    }

    public function generate_xlsx($arr_data = [], $download = false){

        $tableStyle = [
            'font'          => ['name' => 'Arial','size' => 13],
            'alignment'     => ['vertical' => Alignment::VERTICAL_CENTER],
            'borders' => [
                'outline' => [
                    'borderStyle' => Border::BORDER_MEDIUM,
                    'color' => ['rgb' => '333440'],
                ],
            ],
            // 'horizontal' => Alignment::HORIZONTAL_CENTER, 
        ];

        // $arr_data = [
        //     'config' => [
        //         'doc_title'          => 'SpaLiveMD Statement',
        //         'first_column'       => 'B',
        //         'init_row'           => 2,
        //         'use_logo'          => true,
        //     ],
        //     'header' => [
        //         [
        //             'txt'           => 'SpaLiveMD Monthly Statement',
        //             'mergeColumns'  => 6,
        //             'offset'        => 0,
        //             'style'         => [
        //                 'font'      => array('name' => 'Arial','bold' => true,'size' => 22),
        //                 'alignment' => array('vertical' => Alignment::VERTICAL_CENTER)
        //             ]
        //         ],
        //         [
        //             'txt'           => 'From July 1 to July 31 2021',
        //             'mergeColumns'  => 5,
        //             'offset'        => 0,
        //             'style'         => [
        //                 'font'      => array('name' => 'Arial','bold' => true,'size' => 17),
        //                 'alignment' => array('vertical' => Alignment::VERTICAL_CENTER)
        //             ]
        //         ],
        //         [
        //             'txt'           => 'Jorge Alejandro Puente Garza',
        //             'mergeColumns'  => 5,
        //             'offset'        => 1,
        //             'style'         => [
        //                 'font'      => array('name' => 'Arial','bold' => true,'size' => 15),
        //                 'alignment' => array('vertical' => Alignment::VERTICAL_CENTER)
        //             ]
        //         ],
        //         [
        //             'txt'           => 'jorge.alejandro.puente@gmail.com',
        //             'mergeColumns'  => 5,
        //             'offset'        => 0,
        //             'style'         => [
        //                 'font'      => array('name' => 'Arial', 'italic' => true,'size' => 15),
        //                 'alignment' => array('vertical' => Alignment::VERTICAL_CENTER)
        //             ]
        //         ]
        //     ],
        //     'data' => [
        //         [
        //             'DATE'  => 'July 1',
        //             'TRANSACTION'  => 'lorem Ipsum 2',
        //             'DETAILS'  => 'maiores dolorum maxime nam consequuntur 3',
        //             'CORRECTION'  => 'July 4',
        //         ],
        //         [
        //             'DATE'  => 'July 2',
        //             'TRANSACTION'  => 'lorem Ipsum 2',
        //             'DETAILS'  => 'maiores dolorum repellat maxime nam consequuntur 3  dolorum repellat maxi  dolorum repellat maxi',
        //             'CORRECTION'  => 'July 4',
        //         ]
        //     ]
        // ];

        $spreadsheet = new Spreadsheet();
        $sheet = $spreadsheet->getActiveSheet();

        $config = $arr_data['config'];
        $header = isset($arr_data['header']) ? $arr_data['header'] : [];
        $data = isset($arr_data['data']) ? $arr_data['data'] : [];

        $firstColumn = isset($config['first_column']) ? $config['first_column'] : 'A';
        $firstColumnKey = array_search($firstColumn, $this->arr_columns);

        $initRow = isset($config['init_row']) ? $config['init_row'] : 2;
        $rowIndex = $initRow;

        // LOGO
        if (isset($config['use_logo']) && $config['use_logo']) {
            $drawing = new Drawing();
            $drawing->setName('SpaLiveMD');
            $drawing->setDescription('SpaLiveMD Logo');
            $drawing->setPath(WWW_ROOT . 'img/logo.png');
            $drawing->setHeight(75);
            $drawing->setCoordinates($this->arr_columns[$firstColumnKey] . $rowIndex);
            // $drawing->setOffsetX(10);
            $drawing->setWorksheet($spreadsheet->getActiveSheet());

            $rowIndex = $rowIndex + 4;
        }

        // HEADER
        foreach($header as $i => $head) {
            if (isset($head['offset']) && $head['offset'] > 0) $rowIndex = $rowIndex + $head['offset'];

            $tmpCell = $this->arr_columns[$firstColumnKey] . $rowIndex;
            $sheet->getCell($tmpCell)->setValue($head['txt']);
            $sheet->getStyle($tmpCell)->applyFromArray($head['style']);
            
            if (isset($head['mergeColumns']) && $head['mergeColumns'] > 1) {
                $mergeColHead = $firstColumnKey + ($head['mergeColumns'] - 1);

                $mergeColumns = $tmpCell . ':' . $this->arr_columns[$mergeColHead] . $rowIndex;
                $sheet->mergeCells($mergeColumns);
                $sheet->getStyle($mergeColumns)->getAlignment()->setWrapText(true);
            } 

            $rowIndex++;
        }

        $headerTableStyle = $tableStyle;
        // COLUMN TITLES
        if (count($data) > 0) {
            $rowIndex++;
            $rowIndex++;

            $auxColumnKey = $firstColumnKey;

            $headerTableStyle['font']['bold'] = true;

            foreach ($data[0] as $k => $val) {
                $tmpCell = $this->arr_columns[$auxColumnKey] . $rowIndex;

                $sheet->getCell($tmpCell)->setValue($k);
                $sheet->getStyle($tmpCell)->applyFromArray($headerTableStyle);

                $sheet->getColumnDimension($this->arr_columns[$auxColumnKey])->setAutoSize(true);
                $sheet->getStyle($tmpCell)->getAlignment()->setWrapText(true);

                $auxColumnKey++;
            }

            $rowIndex++;
        }

        // DATA
        foreach ($data as $k => $dataRow) {
            $auxColumnKey = $firstColumnKey;
            // pr($dataRow);

            foreach ($dataRow as $k2 => $d) {
                $tmpCell = $this->arr_columns[$auxColumnKey] . $rowIndex;
    
                $sheet->getCell($tmpCell)->setValue($d);
                $sheet->getStyle($tmpCell)->applyFromArray($tableStyle);
    
                $sheet->getColumnDimension($this->arr_columns[$auxColumnKey])->setAutoSize(true);
                $sheet->getStyle($tmpCell)->getAlignment()->setWrapText(true);
                
                $auxColumnKey++;
            }

            $rowIndex++;
        }
        // exit;

        $writer = \PhpOffice\PhpSpreadsheet\IOFactory::createWriter($spreadsheet, "Xlsx");

        if ($download) {
            header("Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
            // header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
            header('Content-Disposition: attachment; filename="'. (isset($config['doc_title']) && $config['doc_title'] ? $config['doc_title'] . '.xlsx' : 'report.xlsx').'"');
            $writer->save('php://output');
        } else $writer->save(TMP . 'reports' . DS . (isset($config['doc_title']) && $config['doc_title'] ? $config['doc_title'] : 'report') . ".xlsx");

        exit;
    }

    public function barrido_pacientes(){
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataPatientClinic');

        $users = $this->SysUsers->find()->select(['SysUsers.id', 'SysUsers.createdby'])
        ->where(['SysUsers.id <> SysUsers.createdby', 'SysUsers.type' => 'patient', 'SysUsers.createdby <>' => 0])->toArray();

        foreach ($users as $item) {
            $arrSave = [
                'uid' => $this->DataPatientClinic->new_uid(),
                'injector_id' => $item->createdby,
                'user_id' => $item->id
            ];
            try{
                $entItem = $this->DataPatientClinic->newEntity($arrSave);
                if(!$entItem->hasErrors()){
                    $this->DataPatientClinic->save($entItem);
                }
            }
            catch (\PDOException $e){}
        }
        $this->success();
    }

    public function add_patient(){
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataPatientClinic');

        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $user_id = $this->SysUsers->uid_to_id(get('user_uid', ''));
        if($user_id <= 0){
            $this->message('Invalid patient.');
            return;
        }

        $patient = $this->SysUsers->find()->select(['SysUsers.type', 'SysUsers.name', 'SysUsers.lname', 'SysUsers.email', 'SysUsers.short_uid', 'SysUsers.uid', 'SysUsers.steps'])->where(['SysUsers.id' => $user_id])->first();
        if($patient->type == 'examiner'){
            $this->message('Invalid user.');
            return;
        }

        $arrLinkPat = [
            'uid' => $this->DataPatientClinic->new_uid(),
            'injector_id' => USER_ID, 
            'user_id' => $user_id,
        ];
        try{
            $entLink = $this->DataPatientClinic->newEntity($arrLinkPat);
            if(!$entLink->hasErrors()){
                $this->DataPatientClinic->save($entLink);
                $this->set('patient', array('name' => $patient->steps == 'REGISTER' ? $patient->email : $patient->name . ' ' . $patient->lname, 
                                            'short_uid' => $patient->short_uid, 
                                            'uid' => $patient->uid, 
                                            'register_pending' => $patient->steps == 'REGISTER' ? true : false));
                $this->success(); 
            }else{
                $this->message('Error adding patient.');
            }
        }catch (\PDOException $e){
            $this->message('is already your patient.');
        }
    }

    public function get_instructions(){
        $this->loadModel('SpaLiveV1.CatStripeInstructions');
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

