    public function download_tray_file() {
        $panel = get('l3n4p', '');
        $tray_uid = get('tray_uid', '');

        if(empty($panel) || (!empty($panel) && $panel != '6092482f7ce858.91169218')){

            $token = get('token',"");

            if(!empty($token)){
                $user = $this->AppToken->validateToken($token, true);
                if($user === false){
                    $this->message('Invalid token.');
                    $this->set('session', false);
                    return;
                }
                $this->set('session', true);
            } else {
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
        }

        // 
        $this->loadModel('SpaLiveV1.FileTray');

        $ent_tray = $this->FileTray->find()
            ->where([
                'FileTray.uid'  => $tray_uid,
                'FileTray.deleted'  => 0
            ])->first();

        // pr($ent_tray);
        // exit;
    
        if (!empty($ent_tray)) {
            $filepath = TMP . 'reports' . DS . $ent_tray->filename;

            switch ($ent_tray->mimetype) {
                case 'PDF':
                    header("Content-type:application/pdf");
                    break;

                case 'XLSX':
                    header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
                    break;
                
                default:
                    $this->message('Invalid mimetype');
                    return;
                    break;
            }

            header("Content-Disposition:attachment;filename=" . $ent_tray->filename);
            header('Content-Length: ' . filesize($filepath));
    
            readfile($filepath);
            exit;

        } else $this->message('Invalid tray uid.');
    }

