    public function get_can_block_schedule(){
        $this->loadModel('SpaLiveV1.DataTreatment');
        $this->loadModel('SpaLiveV1.DataScheduleModel');
        $this->loadModel('SpaLiveV1.DataUserUnavailable');

        $token = get('token',"");

        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $treatment_item = $this->DataTreatment->find()->select(['DataTreatment.assistance_id', 'DataTreatment.schedule_date'])->where(['DataTreatment.uid' => get('uid', '')])->first();

        if(empty($treatment_item)){
            $this->message('Invalid treatment.');
            return;
        }

        $day = $treatment_item->schedule_date->i18nFormat('yyyy-MM-dd');
        $time = strtotime($treatment_item->schedule_date->i18nFormat('yyyy-MM-dd HH:mm'));
        $dayName = $treatment_item->schedule_date->i18nFormat('EEEE');

        $ent_sch_model = $this->DataScheduleModel->find()->where(['DataScheduleModel.deleted' => 0, 'DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.days LIKE' => $dayName, 'DataScheduleModel.model' => 'injector'])->first();
        if(empty($ent_sch_model)){
            $ent_sch_model = $this->DataScheduleModel->find()->where(['DataScheduleModel.deleted' => 0, 'DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.days LIKE' => '%,%'])->first();
        }

        $hour_start = strtotime($treatment_item->schedule_date->i18nFormat('yyyy-MM-dd') . ' ' . $ent_sch_model->time_start . ":00");
        $hour_end = strtotime($treatment_item->schedule_date->i18nFormat('yyyy-MM-dd') . ' ' . $ent_sch_model->time_end . ":00");


        $skd_to_block_minus = [
            ['label' => date("g:i a", $time - (180 * 60)),'save' => date("H:i", $time - (180 * 60)), 'time' => $time - (180 * 60)],
            ['label' => date("g:i a", $time - (150 * 60)),'save' => date("H:i", $time - (150 * 60)), 'time' => $time - (150 * 60)],
            ['label' => date("g:i a", $time - (120 * 60)),'save' => date("H:i", $time - (120 * 60)), 'time' => $time - (120 * 60)],
            ['label' => date("g:i a", $time - (90 * 60)),'save' => date("H:i", $time - (90 * 60)), 'time' => $time - (90 * 60)],
            ['label' => date("g:i a", $time - (60 * 60)),'save' => date("H:i", $time - (60 * 60)), 'time' => $time - (60 * 60)],
            ['label' => date("g:i a", $time - (30 * 60)),'save' => date("H:i", $time - (30 * 60)), 'time' => $time - (30 * 60)],
        ];
        $skd_to_block_plus = [
            ['label' => date("g:i a", $time + (30 * 60)),'save' => date("H:i", $time + (30 * 60)), 'time' => $time + (30 * 60)],
            ['label' => date("g:i a", $time + (60 * 60)),'save' => date("H:i", $time + (60 * 60)), 'time' => $time + (60 * 60)],
            ['label' => date("g:i a", $time + (90 * 60)),'save' => date("H:i", $time + (90 * 60)), 'time' => $time + (90 * 60)],
            ['label' => date("g:i a", $time + (120 * 60)),'save' => date("H:i", $time + (120 * 60)), 'time' => $time + (120 * 60)],
            ['label' => date("g:i a", $time + (150 * 60)),'save' => date("H:i", $time + (150 * 60)), 'time' => $time + (150 * 60)],
            ['label' => date("g:i a", $time + (180 * 60)),'save' => date("H:i", $time + (180 * 60)), 'time' => $time + (180 * 60)],
        ];

        foreach ($skd_to_block_minus as $key => $value) {
            if($value['time'] < $hour_start ){
                unset($skd_to_block_minus[$key]);
            }    
        }
        
        foreach ($skd_to_block_plus  as $key => $value) {
            if($value['time'] > $hour_end){
                unset($skd_to_block_plus[$key]);
            }    
        }

        
        $skd_unav = $this->DataUserUnavailable->find()->select(['DataUserUnavailable.day_unavailable', 'DataUserUnavailable.time_unavailable'])
        ->where(['DataUserUnavailable.injector_id' => $treatment_item->assistance_id, 'DataUserUnavailable.day_unavailable' => $day])->toArray();

        // pr($skd_to_block_minus);
        // pr($skd_unav);exit;

        foreach($skd_unav as $item){
            $_time = $item->time_unavailable->i18nFormat('HH:mm');

            foreach ($skd_to_block_minus as $key => $value) {
                if($value['save'] == $_time){
                    unset($skd_to_block_minus[$key]);
                    break;
                }    
            }
            
            foreach ($skd_to_block_plus  as $key => $value) {
                if($value['save'] == $_time){
                    unset($skd_to_block_plus[$key]);
                    break;
                }    
            }
        }


        $this->set('before_skd', array_values($skd_to_block_minus));
        $this->set('after_skd', array_values($skd_to_block_plus)); 
        $this->success();
    }

    public function confirm_treatment(){
        $this->loadModel('SpaLiveV1. ');
        $this->loadModel('SpaLiveV1.DataTreatment');
        $this->loadModel('SpaLiveV1.DataUserUnavailable');
        $this->loadModel('SpaLiveV1.DataPatientClinic');

        $token = get('token',"");
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $treatment = $this->DataTreatment->find()->where(['DataTreatment.uid' => get('uid', '')])->first();
        if(empty($treatment)){
            $this->message('Invalid treatment.');
            return;
        }

        $hours = explode('||', get('hours', ''));
        // if(empty($hours)){
        //     $this->message('Invalid hours.');
        //     return;
        // }

        
        $errors = false;

        foreach($hours as $item){
            if (empty($item)) continue;
            $arrSave = [
                'uid' => $this->DataUserUnavailable->new_uid(),
                'injector_id' => USER_ID,
                'time_unavailable' => $item.':00',
                'day_unavailable' => $treatment->schedule_date->i18nFormat('yyyy-MM-dd'),
                'treatment_id' => $treatment->id,
            ];

            $ent = $this->DataUserUnavailable->newEntity($arrSave);
            if(!$ent->hasErrors()){
                $this->DataUserUnavailable->save($ent);
            }else{
                $errors = true;
            }
        }

        if(!$errors){
            $this->DataTreatment->updateAll(
                ['status' => 'CONFIRM'],
                ['id' => $treatment->id]
            );


            $ent_datapatient = $this->DataPatientClinic->find()->select(['SysUsers.uid','SysUsers.short_uid','SysUsers.name','SysUsers.lname'])
            ->join(['SysUsers' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'DataPatientClinic.user_id = SysUsers.id'],])
            ->where(['SysUsers.deleted' => 0, 'DataPatientClinic.injector_id' => USER_ID,'DataPatientClinic.deleted' => 0,'DataPatientClinic.user_id' => $treatment->patient_id])->first();

            if (empty($ent_datapatient)) {
                $arrLinkPat = [
                    'uid' => $this->DataPatientClinic->new_uid(),
                    'injector_id' => USER_ID, 
                    'user_id' => $treatment->patient_id,
                ];
                try{
                    $entLink = $this->DataPatientClinic->newEntity($arrLinkPat);
                    if(!$entLink->hasErrors()){
                        $this->DataPatientClinic->save($entLink);
                        $this->success(); 
                    }
                }catch (\PDOException $e){
                    $this->message('is already your patient.');
                }
            }


            $this->success();
        }
    }
    
    public function get_transfer_id($str_account = '', $str_trans_group = '', $retJson = true, $payment = ''){
        $account = !empty($str_account) ? $str_account : get('ac_strp', '');
        $transferGroup = !empty($str_trans_group) ? $str_trans_group : get('trans_gp', '');
        $payment = !empty($payment) ? $payment : get('payment', '');
        $transfer = '';
        $stripe = new \Stripe\StripeClient(Configure::read('App.stripe_secret_key'));
        $transfers =$stripe->transfers->all(['limit' => 20, 'transfer_group' => $transferGroup]);
        
        foreach ($transfers->data as $key => $trans) {
            if(!empty($payment)){
                if($trans->destination == $account && $payment == $trans->source_transaction){
                    $transfer = $trans->id;
                    break;
                }
            }else if($trans->destination == $account){
                $transfer = $trans->id;
                break;
            }
        }
        
        if($retJson){
            $this->success();
            $this->set('data', $transfer);
        }else{
            return $transfer;
        }

    }    

