    public function report_unit_sales() {



        $panel = get('l3n4p', '');
        $tray_uid = get('tray_uid', '');

        if(empty($panel) || (!empty($panel) && $panel != '6092482f7ce858.91169218')){
            return;
        }

        
        $type = get('type', 'MTD');
        $format = get('format', 'pdf');
        $token = get('token', 'pdf');
        
        $firstDay = date('Y-m-01');
        $lastDay =  date('Y-m-t');
        if ($type == 'YTD') {
            $firstDay = date('Y-01-01');
        }
        $state = get('state', '');  $this->log(__LINE__ . ' ' . json_encode($state));
        if(is_string($state) && $state !== ''){
            //$str = explode(',', $state);
            $_where = ' AND DP.state IN ('. $state  .')';
	        
		}else if($state !== ''){
            $_where = ' AND DP.state IN ('.  $state .')';		
		}

        
        $this->loadModel('SpaLiveV1.DataPurchases');

        $str_query_find = "
                    SELECT CP.id prod_id, CP.sku, CP.sold_as, CP.`name`, SUM(DPD.qty - DPD.refunded) AS total FROM data_purchases DP
                    JOIN data_purchases_detail DPD ON DPD.purchase_id = DP.id
                    JOIN data_payment DPA ON DPA.uid = DP.uid 
                    JOIN cat_products CP ON CP.id = DPD.product_id
                    JOIN sys_users SU ON SU.id = DP.user_id
                    WHERE 
                        DP.payment <> '' AND 
                        SU.is_test = 0 AND 
                        DPA.is_visible = 1 AND 
                        DPA.payment <> '' AND
                        DPA.id_to = 0 AND
                        DP.deleted = 0 AND
                        DPA.promo_code <> 'DSCT99SPA' AND
                        SU.name NOT LIKE '%test%' AND
                        SU.is_test = 0 AND
                        DPA.receipt <> '' AND
                        CP.id != 44	AND
                        DP.created BETWEEN '{$firstDay}' AND '{$lastDay}' {$_where}
                    GROUP 
                        BY CP.id
                    ORDER 
                        BY CP.name ASC
                ";
                $this->log(__LINE__ . ' ' . ($str_query_find));
        $ent_query = $this->DataPurchases->getConnection()->execute($str_query_find)->fetchAll('assoc');

        if ($format == 'pdf') $this->report_unit_sales_pdf($ent_query, $firstDay, $lastDay);
        elseif ($format == 'xlsx') $this->report_unit_sales_xlsx($arr_balance, $firstDay, $lastDay, $user);
    }

    private function report_unit_sales_pdf($arr_data, $firstDay, $lastDay) {
        $html2pdf = new HTML2PDF('F','A4','en', true, 'UTF-8', array(10,10,10,10));

        $str_balance = '';

        // pr($arr_balance);
        // exit;

        foreach($arr_data as $key => $balance) {
            $extra_detail = '';
            if ($balance['prod_id'] == 59) $extra_detail = ' (' . $balance['total']*5 . ' vials)';
            $str_balance .= "
                <tr style=\"border-spacing: 0;\">
                    <td style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef;\">" . $balance['sku'] . "</td>
                    <td style=\"padding: 2mm; width: 50mm; border-bottom: 1px solid #e4e6ef;\">" . $balance['name'] . "</td>
                    <td style=\"padding: 2mm; width: 50mm; border-bottom: 1px solid #e4e6ef;\">" . $balance['sold_as'] . "</td>
                    <td style=\"padding: 2mm; width: 28mm; border-bottom: 1px solid #e4e6ef; text-align: right;\">" . number_format(intval($balance['total']),0,'.',',') . $extra_detail . "</td>
                </tr>";
        }

        if ($str_balance == '') {
            $str_balance .= "
                <tr style=\"border-spacing: 0;\">
                    <td colspan=\"4\" style=\"padding: 2mm; border-bottom: 1px solid #e4e6ef;\"><i>No transactions.</i></td>
