    public function send_giftcard (){
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.CatProducts');
        $this->loadModel('SpaLiveV1.DataGiftCards');
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $card_id = get('card_id','');
        if(empty($card_id)){
            $this->message('Card empty.');
            return;
        }

        $ent_card = $this->CatProducts->find()
        ->where([
            'CatProducts.id' => $card_id,
            'CatProducts.deleted' => 0,
            'CatProducts.category' => 'GIFT CARDS',
        ])->first();

        if(empty($ent_card)){
            $this->message('Card invalid.');
            return;
        }

        $email_patient = get('email_patient', '');
        if(empty($email_patient)){
            $this->message('Email patient empty.');
            return;
        }
        
        $patient_id = 0;
        $patient_email = $email_patient;
        $ent_user = $this->SysUsers->find()
        ->select([
            'SysUsers.id',
            'SysUsers.email'
        ])->where([
            'SysUsers.email' => $email_patient,
        ])->first();
        if(!empty($ent_user)){
            $patient_id = $ent_user->id;
            $patient_email = $ent_user->email;
        }
        
        $code = $this->sendGiftCards(USER_NAME. ' '.USER_LNAME, $patient_email, $ent_card->item_description, $ent_card->file_id, $ent_card->name);
        
        $array_vals = array(
            'Gift Card 50' => 5000,
            'Gift Card 75' => 7500,
            'Gift Card 100' => 10000,
            'Gift Card 200' => 20000,
            'Gift Card 600' => 60000,

        );
        $array_save = array(
            'uid' => Text::uuid(),
            'code' => $code,
            'deleted' => 0,
            'created' => date('Y-m-d H:i:s'),
            'expiration' => date('Y-m-d H:i:s', strtotime('+6 months')),
            'user_id' => USER_ID,
            'receipt_id' => $patient_id,
            'card_id' => $ent_card->id,
            // 'discount' => isset($array_vals[$ent_card->item_description]) ? $array_vals[$ent_card->item_description] : 0
            'discount' => isset($ent_card->unit_price) ? $ent_card->unit_price : 0
        );

        $this->message('Email sent successfully.');

        $ent_gift = $this->DataGiftCards->newEntity($array_save);
        if(!$ent_gift->hasErrors()){
            $this->DataGiftCards->save($ent_gift);
            $this->success();
        }
    }

    public function preview_provider_profile(){
        $this->loadModel('DataDirectorClinic');
        $this->loadModel('SpaLiveV1.DataTreatmentReview');
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $this->loadModel("SpaLiveV1.SysUsers");

        $_usr_uid = get('uid', '');
        if(!empty($_usr_uid)){
            $_where = ["SysUsers.uid" => $_usr_uid];
        }else{
            $this->message('Uid must be provided.');
            $this->set('success', false);
            return;
        }

        $first_day = date('Y-m-01');
        $last_day = date('Y-m-t');
        $most_reviewed = $this->DataTreatmentReview->injectorMostReviewed();
        $fields = ['SysUsers.id', 'SysUsers.uid','SysUsers.name', 'SysUsers.lname', 'SysUsers.mname','SysUsers.bname','SysUsers.city','SysUsers.dob','SysUsers.gender','SysUsers.short_uid','SysUsers.score','SysUsers.photo_id','SysUsers.ein','SysUsers.email','SysUsers.phone','SysUsers.state','SysUsers.street','SysUsers.zip','SysUsers.type','SysUsers.score','State.name','SysUsers.photo_id','SysUsers.score','SysUsers.description',
            'SysUsers.enable_notifications', 'SysUsers.suite', 
            'is_ci_of_month' => "(SELECT COUNT(InjM.id) FROM data_injector_month InjM WHERE InjM.injector_id = SysUsers.id AND InjM.deleted = 0 AND InjM.date_injector BETWEEN '{$first_day}' AND '{$last_day}')",
            'cpr_uploaded' => "(SELECT COUNT(DUCL.id) FROM data_user_cpr_licence DUCL WHERE DUCL.user_id = SysUsers.id LIMIT 1)"
        ];
        $fields['likes'] = "(SELECT Count(DTR.id) FROM data_treatment_reviews DTR WHERE DTR.injector_id = SysUsers.id AND DTR.like = 'LIKE')";
        $find = $this->SysUsers->find()->select($fields)
        ->join([
            'State' => ['table' => 'cat_states', 'type' => 'INNER', 'conditions' => 'State.id = SysUsers.state']
        ])->where($_where)->first();

        if(empty($find)){
            $this->message('Can´t find user');
            return;
        }else{
            $this->loadModel("SpaLiveV1.CatStates");
            $state = $this->CatStates->find()->select(['CatStates.require_ci_license'])->where(['CatStates.id' => $user['user_state']])->first();
            if ($state) {
                $this->set('require_ci_license', $state->require_ci_license == 1 ? true : false);
            }
            if($find->type == 'clinic'){
                $director = $this->DataDirectorClinic->find()->where(['DataDirectorClinic.clinic_id' => $find->id])->first();
                $dirVals = [
                    'director_uid' => "",
                    'director_name' => "",
                    'director_phone' => "",
                    'director_license' => "",
                ];
                if(!empty($director)){
                    $dirVals['director_uid'] = $director->uid;
                    $dirVals['director_name'] = $director->director_name;
                    $dirVals['director_phone'] = $director->director_number;
                    $dirVals['director_license'] = $director->director_license;
                }

                $this->set('director', $dirVals);
            }

            $find['enable_notifications'] = (isset($find['enable_notifications']) && ($find['enable_notifications'] === true || $find['enable_notifications'] == 1)) ? 1 : 0;
            $ver = get('version', '');
            $key = get('key', '');
            $ver = str_replace('version ', '', $ver);

            if($find['type'] != 'injector' && $find['type'] != 'gfe+ci'){
                $this->message('The Uid provided is not from an injector');
                $this->set('success', false);
                return;
            }
            
            //unset($find['id']);
            unset($find['active']);
            //unset($find['user_id']);
            unset($find['deleted']);
            unset($find['created']);
            unset($find['password']);
            unset($find['modified']);
            unset($find['modifiedby']);
            $state = $find['state'];
            $find['state_txt'] = $find['State']['name'];
            $find['state'] = $state;
            unset($find['State']);
            $find['most_reviewed'] = 0;
            $find['is_ci_of_month'] = 0;
            $find['cpr_uploaded'] = ($find['cpr_uploaded'] > 0 ? 1 : 0);
            $find['gender'] = $find['gender'] == 'Other' ? ' ' : $find['gender'];
            $this->loadModel('SpaLiveV1.SysLicence');
            $this->loadModel('SpaLiveV1.DataWN');
            $licenseFields = ['SysLicence.id','SysLicence.type', 'SysLicence.number','state.name'];
            
            $licenceItem = $this->SysLicence->find()->select($licenseFields)
            ->join([
                'state' => ['table' => 'cat_states', 'type' => 'INNER', 'conditions' => 'state.id = SysLicence.state'],
                ])
                ->where(['SysLicence.user_id' => $find['id'], 'SysLicence.deleted' => 0])->group(['SysLicence.number'])->all();
            
            $this->loadModel('SpaLiveV1.DataTrainings');
            $trainingsFields = ['DataTrainings.id','DataTrainings.training_id', 'training_data.title', 'training_data.scheduled', 'training_data.level'];
            $trainingsInstance = $this->DataTrainings->find()->select($trainingsFields)
                ->join([
                    'training_data' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'training_data.id = DataTrainings.training_id'],
                ])
                ->where(['DataTrainings.user_id' => $find['id'], 'DataTrainings.deleted' => 0])->order(['training_data.level' => 'ASC'])->all();
            
            $str_query = "
                SELECT 
                    (SELECT GROUP_CONCAT(CONCAT_WS('|',CT.name,ROUND(DTP.price / 100,2))) FROM data_treatments_prices DTP JOIN cat_treatments_ci CT ON CT.id = DTP.treatment_id WHERE DC.id = DTP.user_id AND DTP.deleted = 0 AND CT.deleted = 0) as treatments
                FROM sys_users as DC
                WHERE (DC.type = 'injector' OR DC.type = 'gfe+ci') AND DC.deleted = 0 AND DC.is_test = 0 AND DC.id = ".$find['id']."
            ";
            
            $arr_find = $this->SysUsers->getConnection()->execute($str_query)->fetchAll('assoc');
            if(empty($arr_find))
                $arr_find = "";
            else 
                $arr_find = $arr_find[0];

            unset($find['user_id']);
            if (!isset($find['dob'])) $find['dob'] = '';
            $this->set('data', $find);
            $this->set('licenses', $licenceItem);
            $this->set('trainings', $trainingsInstance);
            $this->set('treatments', $arr_find['treatments']);

            $this->success();

        }
    }

    public function bulk_notification_trainers() {

        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        
        $type = get('type','');
        $body = get('body','');
        $is_sms = get('is_sms',0);
        $is_email = get('is_email',0);
        $training_id = get('training_id',0);
        $now = date('Y-m-d H:i:s');
        $this->loadModel('SpaLiveV1.SysUsers');
        $this->loadModel('SpaLiveV1.DataModelPatient');
        $this->loadModel('SpaLiveV1.DataParticipantTrainers');
        $users_array = array();
        $ent_user = array();
        $email_string = "";
        $email_array = array();

        $ent_user = $this->SysUsers->find()->join([
            'DataParticipantTrainers' => ['table' => 'data_participant_trainers', 'type' => 'INNER', 'conditions' => 'DataParticipantTrainers.user_id = SysUsers.id'],
            'CatTrainings' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainings.id = DataParticipantTrainers.training_id'],
            ])
        ->where(['CatTrainings.id' => $training_id, 'DataParticipantTrainers.deleted ' => 0, 'SysUsers.deleted' => 0])->all();
        
        foreach ($ent_user as $row) {
            $users_array[] = $row['id'];
        }

        if ($is_email == 1) {

            if(empty($email_string)){
                $str_str_users = implode(",",$users_array);
            
                $str_query = "
                    SELECT 
                        GROUP_CONCAT(SU.email) emails
                    FROM sys_users SU
                    WHERE SU.deleted = 0 AND SU.id > 1 AND SU.enable_notifications = 1 AND (SU.login_status = \"READY\" OR SU.login_status = \"CHANGEPASSWORD\" OR SU.login_status = \"PAYMENT\") AND FIND_IN_SET(SU.id,'{$str_str_users}')";
    
    
                $ent_query = $this->SysUsers->getConnection()->execute($str_query)->fetchAll('assoc');
                
                if (!empty($ent_query)) {
                    $email_string = $ent_query[0]['emails'];
                }
            }

            $data = array(
                'from'    => 'MySpaLive <info@mg.myspalive.com>',
                'to'    => 'MySpaLive <info@mg.myspalive.com>',
                'bcc'      => $email_string,
                'subject' => "New message from MySpaLive",
                'html'    => $this->getEmailFormat($body),
            );

            $mailgunKey = $this->getMailgunKey();


            $curl = curl_init();
            curl_setopt($curl, CURLOPT_URL, 'https://api.mailgun.net/v3/mg.myspalive.com/messages');
            curl_setopt($curl, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
            curl_setopt($curl, CURLOPT_USERPWD, 'api:' . $mailgunKey);
            curl_setopt($curl, CURLOPT_RETURNTRANSFER, 1);
            curl_setopt($curl, CURLOPT_CONNECTTIMEOUT, 10);
            curl_setopt($curl, CURLOPT_SSL_VERIFYPEER, 0);
            curl_setopt($curl, CURLOPT_SSL_VERIFYHOST, 0);
            curl_setopt($curl, CURLOPT_POST, true); 
            curl_setopt($curl, CURLOPT_POSTFIELDS, $data);

            $result = curl_exec($curl);
            curl_close($curl);

            $this->loadModel('SpaLiveV1.CatTrainings');

            $ent_training = $this->CatTrainings->find()->where(['CatTrainings.id' => $training_id, 'CatTrainings.deleted ' => 0])->first();
            if(!empty($ent_training)){
                $ent_training->email_sent_date = date("Y-m-d H:i:s");
                $this->CatTrainings->save($ent_training);
            }

        } else if ($is_sms == 1) {
            $this->notify_devices($body,$users_array,false,false,false,array(),'',array(),true);
            $this->loadModel('SpaLiveV1.CatTrainings');
            $ent_training = $this->CatTrainings->find()->where(['CatTrainings.id' => $training_id, 'CatTrainings.deleted ' => 0])->first();
            if(!empty($ent_training)){
                $ent_training->sms_sent_date = date("Y-m-d H:i:s");
                $this->CatTrainings->save($ent_training);
            }
        }
    }

