    public function get_step_validate(){
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        $this->loadModel("SpaLiveV1.SysUsers");        

        $ent_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
        
        if($ent_user->spa_work == 1){
            $this->SysUsers->updateAll(
                ['steps' => 'HOME'], 
                ['id' =>  USER_ID]
            );
            $this->set('step', $ent_user->steps);
            $this->success();
            return;
        }

        if($ent_user->steps == 'CODEVERIFICATION' || $ent_user->steps == 'WAITINGSCHOOLAPPROVAL' || $ent_user->steps == 'STATENOTAVAILABLE' || $ent_user->steps == 'TRACERS' || $ent_user->steps == 'DENIED'){
            $this->set('step', $ent_user->steps);
            $this->success();
            return;
        }
        
        $this->loadModel("SpaLiveV1.DataSubscriptions"); 
        $this->loadModel("SpaLiveV1.DataTrainings"); 
        $this->loadModel("SpaLiveV1.CatStates"); 
        $now = date('Y-m-d H:i:s');
        $nowDay = date('Y-m-d');

        $ent_state = $this->CatStates->find()->where(['CatStates.id' => $user['user_state'], 'CatStates.deleted' => 0])->first();
        if ($ent_state->enabled == 0) {
            $this->SysUsers->updateAll(
                ['steps' => 'STATENOTAVAILABLE'], 
                ['id' =>  USER_ID]
            );
            $this->set('step', 'STATENOTAVAILABLE');
            $this->success();
            return;
        }

        
        $this->loadModel("SpaLiveV1.DataPayment");
        
        $ent_payments = $this->DataPayment->find()->where(['DataPayment.id_from' => USER_ID, 'DataPayment.type IN' => array('BASIC COURSE', 'CI REGISTER'), 'DataPayment.payment <>' => ''])->first();

        if(!empty($ent_payments)){
            $user_training = $this->DataTrainings->find()->select(['CatTrainigs.scheduled', 'CatTrainigs.created', 'DataTrainings.attended'])->join([
                'CatTrainigs' => ['table' => 'cat_trainings', 'type' => 'INNER', 'conditions' => 'CatTrainigs.id = DataTrainings.training_id'],
                ])->where(['CatTrainigs.level' => 'LEVEL 1','DataTrainings.user_id' => USER_ID,'DataTrainings.deleted' => 0])->first();
            if(empty($user_training)){
                $this->SysUsers->updateAll(
                    ['steps' => 'SELECTBASICCOURSE'], 
                    ['id' =>  USER_ID]
                );
                $this->success();
                $this->set('step', 'SELECTBASICCOURSE');
                return;
            }else{

                $this->loadModel("SpaLiveV1.DataCertificates");
                
                 $entCertificate = $this->DataCertificates->find()
                    ->join([
                        'DataConsultation' => ['table' => 'data_consultation', 'type' => 'INNER', 'conditions' => 'DataConsultation.id = DataCertificates.consultation_id'],
                         'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataConsultation.patient_id']
                    ])
                    ->where(['DataConsultation.patient_id' => USER_ID,'DataConsultation.deleted' => 0, 'DataCertificates.deleted' => 0])->first();


                if(date('Y-m-d', strtotime($user_training['CatTrainigs']['scheduled'])) > "2023-02-03" && date('Y-m-d', strtotime($user_training['CatTrainigs']['scheduled'])) >= $nowDay && empty($entCertificate)){
                    $this->SysUsers->updateAll(
                        ['steps' => 'MATERIALS'], 
                        ['id' =>  USER_ID]
                    );
                    $this->success();
                    $this->set('step', 'MATERIALS');
                    return;
                }

                $this->loadModel("SpaLiveV1.DataCertificates");
                
                $entCertificate = $this->DataCertificates->find()
                    ->join([
                        'DataConsultation' => ['table' => 'data_consultation', 'type' => 'INNER', 'conditions' => 'DataConsultation.id = DataCertificates.consultation_id'],
                            'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataConsultation.patient_id']
                    ])
                    ->where(['DataConsultation.patient_id' => USER_ID,'DataConsultation.deleted' => 0, 'DataCertificates.deleted' => 0])->first();

                
                $c_date = strtotime('2023-02-27');
                $isBeforeChange = $c_date > strtotime($user_training['CatTrainigs']['created']);
                $this->set('is_before', $isBeforeChange);
                if(date('Y-m-d', strtotime($user_training['CatTrainigs']['scheduled'])) > "2023-02-03" && date('Y-m-d', strtotime($user_training['CatTrainigs']['scheduled'])) >= $nowDay && empty($entCertificate)){
                    $this->SysUsers->updateAll(
                        ['steps' => 'MATERIALS'], 
                        ['id' =>  USER_ID]
                    );
                    $this->success();
                    $this->set('step', 'MATERIALS');
                    return;
                }
                
                if($isBeforeChange) {

                    if (date('Y-m-d', strtotime($user_training['CatTrainigs']['scheduled'])) == $nowDay && !empty($entCertificate) && $ent_user->steps == 'MATERIALS') {
                         $this->SysUsers->updateAll(
                            ['steps' => 'MATERIALS'], 
                            ['id' =>  USER_ID]
                        );
                        $this->success();
                        $this->set('step', 'MATERIALS');
                        return;
                    }
    
                    if(date('Y-m-d 08:00:00', strtotime($user_training['CatTrainigs']['scheduled'])) > $now){
                        $this->SysUsers->updateAll(
                            ['steps' => 'MATERIALS'], 
                            ['id' =>  USER_ID]
                        );
                        $this->success();
                        $this->set('step', 'MATERIALS');
                        return;
                    }
                }
                // CHECK IF THE USER HAS ATTENDED THE TRAINING          
                else if($user_training->attended != 1) {
                    $this->SysUsers->updateAll(
                        ['steps' => 'MATERIALS'], 
                        ['id' =>  USER_ID]
                    );
                    $this->success();
                    $this->set('step', 'MATERIALS');
                    return;
                }

                $this->set('is_after', $c_date < $user_training['CatTrainigs']['created']);
            }
        } else {
            $this->SysUsers->updateAll(
                ['steps' => 'BASICCOURSE'], 
                ['id' =>  USER_ID]
            );
            $this->success();
            $this->set('step', 'BASICCOURSE');
            return;
        }

