                            <b>$location</b>
                        </td>
                    </tr>                          
                </tbody>    
            </table>
        </div>
        <div style=\"padding: -1px 0px 0px 0px; width: 100%\">
           <table width=\"100%\">                
                <tbody>
                    <tr>
                        <td style=\"text-align: left; width: 33%;\">
                            Date <br>
                            <b>$training_date</b>
                        </td>
                        <td style=\"text-align: left; width: 33%;\">
                            Time <br>
