    public function PutSubscriptionOnHold(){
        $this->loadModel('SpaLiveV1.DataSubscriptions');
        $this->loadModel('SpaLiveV1.DataSubscriptionPayments');
        $this->loadModel('SpaLiveV1.DataSubscriptionCancelled');
        $this->loadModel('SpaLiveV1.DataAgreements');
        
        $token = get('token', '');
        
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }

        $subscription_id = get('subscription_id', 0);

        $entSubs = $this->DataSubscriptions->find()->where(['DataSubscriptions.id' => $subscription_id])->first();
        $entSubsHold = $this->DataSubscriptions->find()->where(['DataSubscriptions.user_id' => $entSubs->user_id, 'DataSubscriptions.already_on_hold' => 1])->all();
        
        if(!empty($entSubs)){
            
            if(count($entSubsHold) > 0){
                $this->message('The user has already had a subscription on hold before.');
                return;
            }

            $entSubs->already_on_hold = 1;
            $entSubs->status = 'HOLD';

            if(!$entSubs->hasErrors()){
                if($this->DataSubscriptions->save($entSubs)){
                    $this->set('data', $entSubs);
                    $this->success();
                }else $this->add_errors('Error updating item');
            }else $this->add_errors('Error updating item');
        }
    }

