    public function get_w9_bulk_patients() {
        set_time_limit(0);
        ini_set('memory_limit','-1');

        $type = get('type', '');
        $date_from = get('date_from', '');
        $date_to = get('date_to', '');
        $arr_types = ['patient'];

        if (!$date_from|| !$date_to) {
            $this->messages('You must specify a valid range of dates.');
            return;
        }

        if (!in_array($type, $arr_types)) {
            $this->messages('Invalid type ' . $type);
            return;
        }

        $this->loadModel('SpaLiveV1.FileTray');

        $tray_uid = $this->FileTray->new_uid();
        $this->FileTray->new_entity([
            'uid'           => $tray_uid,
            'filename'      => 'W9BulkPatients-' . date('U') . '.pdf',
            // 'filename'      => 'W9Bulk-' . str_replace('-', '', $date_from) . '-' . str_replace('-', '', $date_to),
            'model'         => 'W9BulkPatients',
            'status'        => 'INIT',
            'params'        => json_encode([
                'model'     => 'W9BulkPatients',
                'type'      => $type,
                'date_from' => $date_from,
                'date_to'   => $date_to,
            ]),
            'mimetype'      => 'PDF',
        ]);

        $this->success();
        $this->set('tray_uid', $tray_uid);
        $this->set('command', (env('COMMAND_PATH', '') . ' filetray ' . $tray_uid . ' > /dev/null 2>&1 &'));

        shell_exec(env('COMMAND_PATH', '') . ' filetray ' . $tray_uid . ' > /dev/null 2>&1 &');
    }
    
