    function remove_emoji($string)
    {
        // Match Enclosed Alphanumeric Supplement
        $regex_alphanumeric = '/[\x{1F100}-\x{1F1FF}]/u';
        $clear_string = preg_replace($regex_alphanumeric, '', $string);

        // Match Miscellaneous Symbols and Pictographs
        $regex_symbols = '/[\x{1F300}-\x{1F5FF}]/u';
        $clear_string = preg_replace($regex_symbols, '', $clear_string);

        // Match Emoticons
        $regex_emoticons = '/[\x{1F600}-\x{1F64F}]/u';
        $clear_string = preg_replace($regex_emoticons, '', $clear_string);

        // Match Transport And Map Symbols
        $regex_transport = '/[\x{1F680}-\x{1F6FF}]/u';
        $clear_string = preg_replace($regex_transport, '', $clear_string);
        
        // Match Supplemental Symbols and Pictographs
        $regex_supplemental = '/[\x{1F900}-\x{1F9FF}]/u';
        $clear_string = preg_replace($regex_supplemental, '', $clear_string);

        // Match Miscellaneous Symbols
        $regex_misc = '/[\x{2600}-\x{26FF}]/u';
        $clear_string = preg_replace($regex_misc, '', $clear_string);

        // Match Dingbats
        $regex_dingbats = '/[\x{2700}-\x{27BF}]/u';
        $clear_string = preg_replace($regex_dingbats, '', $clear_string);

        return $clear_string;
    }

    private function generate_certificates_two_signs($display = false, $cert_uid = '') {

        
        $cert_count = 0;

        $this->loadModel('SpaLiveV1.DataCertificates');
        $fields = ['DataCertificates.uid','User.name','User.lname','DataCertificates.date_start','DataCertificates.date_expiration','DataConsultation.treatments','DataConsultation.patient_id'];

        $fields['treatments'] = '(SELECT GROUP_CONCAT(DISTINCT CT.name) FROM cat_treatments CT WHERE FIND_IN_SET(CT.id,DataConsultation.treatments))';

        $certItem = $this->DataCertificates->find()->select($fields)
        ->join([
            'DataConsultation' => ['table' => 'data_consultation', 'type' => 'INNER', 'conditions' => 'DataConsultation.id = DataCertificates.consultation_id'],
             'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataConsultation.patient_id']
        ])
        ->where(['DataCertificates.uid' => $cert_uid])->first();

        if (!empty($certItem)) {

            $cert_count = 1;

            $data_treatments = $certItem['DataConsultation']['treatments'];

            $arr_tr = explode(",",$data_treatments);

            $str_cert_treaments = $certItem['treatments'];
            if (count($arr_tr) > 4) {
                $arr_tttr = explode(",",$certItem['treatments']);
                $str_cert_treaments = $arr_tttr[0] . ',' . $arr_tttr[1] . ',' . $arr_tttr[2] . ',' . $arr_tttr[3];
            }

            $_treatments = 'TREATMENTS: ' . strtoupper(isset($str_cert_treaments) ? $str_cert_treaments : '');
            $treatments = $_treatments;
            $wi = strlen($treatments);
            $wi2 = 0;
            if (strlen($treatments) > 100) {
                $treatments = wordwrap($treatments, 100, "\n");
                $arr_strings = $arr_tttrr = explode("\n",$treatments);
                $treatments = $arr_tttrr[0];
                $treatments2 = $arr_tttrr[1];
                $wi = strlen($treatments);
                $wi2 = strlen($treatments2);
            }
                  
            //$name = strtoupper($certItem->User['name'] . ' ' . $certItem->User['lname']);
            $name = ucfirst($certItem->User['name']) . ' ' . ucfirst($certItem->User['lname']);
            $dates = $certItem['date_start']->i18nFormat('MM-dd-yyyy');
            $datef = $certItem['date_expiration']->i18nFormat('MM/dd/yyyy');
            
            $type_space = imagettfbbox(425, 0, './font/AlexBrush-Regular.ttf', $name);
            $text_width = abs($type_space[4] - $type_space[0]) + 10;
            
            $im     = imagecreatefromjpeg(TMP . "files/certhd.jpeg");
            $purple = imagecolorallocate($im, 158, 138, 191);
            $gray = imagecolorallocate($im, 30, 30, 30);
            $px   = (imagesx($im) - $text_width) / 2;
            imagettftext($im, 425, 0, (int)$px, 3225, $gray, './font/AlexBrush-Regular.ttf', $name);
            $type_spaceTr = imagettfbbox(100, 0, './font/Garet-Heavy.ttf', $treatments);
            $text_widthTr = abs($type_spaceTr[4] - $type_spaceTr[0]) + 10;
            $pxTr = (imagesx($im) - $text_widthTr) / 2;
            imagettftext($im, 100, 0, (int)$pxTr, 3700, $gray, './font/Garet-Book.ttf', $treatments);
            if (strlen($_treatments) > 100) {
                $pxt     = (imagesx($im) - 25 * $wi2) / 2;
                imagettftext($im, 10, 0, (int)$pxt - 100, 1290, $gray, './font/Garet-Book.ttf', $treatments2);
            }

            // Position of the expiration date
            $exp_date = 'Expiration Date: ' .  $datef;
            $type_spaceEd = imagettfbbox(95, 0, './font/Garet-Book.ttf', $exp_date);
            $text_widthEd = abs($type_spaceEd[4] - $type_spaceEd[0]);
            $pxEd = ((imagesx($im) - $text_widthEd) / 2);
            // imagettftext($im, 21, 0, 800, 963, $gray, './font/Garet-Book.ttf','Expiration Date: ' .  $datef);
            imagettftext($im, 95, 0, (int)$pxEd, 4000, $gray, './font/Garet-Book.ttf',$exp_date);

            imagejpeg($im, TMP .  "files/tmp_Cert.jpeg", 60);
            imagedestroy($im);

            if (count($arr_tr) > 4) {
                $arr_tttrr = explode(",",$certItem['treatments']);
                switch(count($arr_tttrr)) {
                    case 5:
                        $str_cert_treaments = $arr_tttrr[4];
                        break;
                    case 6:
                        $str_cert_treaments = $arr_tttrr[4] . ',' . $arr_tttrr[5]; break;
                    case 7:
                        $str_cert_treaments = $arr_tttrr[4] . ',' . $arr_tttrr[5] . ',' . $arr_tttrr[6]; break;
                    case 8:
                        $str_cert_treaments = $arr_tttrr[4] . ',' . $arr_tttrr[5] . ',' . $arr_tttrr[6] . ',' . $arr_tttrr[7]; break;
                    default:
                        $str_cert_treaments = $arr_tttrr[4];
                }
                
                $cert_count++;
                $name = strtoupper($certItem->User['name'] . ' ' . $certItem->User['lname']);
                $dates = $certItem['date_start']->i18nFormat('MM-dd-yyyy');
                $datef = $certItem['date_expiration']->i18nFormat('MM-dd-yyyy');
                $treatments = 'TREATMENTS: ' . strtoupper($str_cert_treaments);
                $im     = imagecreatefromjpeg(TMP . "files/certhd.jpeg");
                $purple = imagecolorallocate($im, 158, 138, 191);
                $gray = imagecolorallocate($im, 30, 30, 30);
                $px     = (imagesx($im) - 35 * strlen($name)) / 2;
                imagettftext($im, 90, 0, (int)$px - 20, 1100, $gray, './font/Bison-Regular.ttf', $name);
                $pxt     = (imagesx($im) - 25 * strlen($treatments)) / 2;
                imagettftext($im, 70, 0, (int)$pxt - 20, 1200, $gray, './font/Bison-Regular.ttf', $treatments);
                imagettftext($im, 60, 0, 500, 1950, $gray, './font/Bison-Regular.ttf', $dates);
                imagettftext($im, 60, 0, 1900, 1740, $gray, './font/Bison-Regular.ttf', $datef);
                imagejpeg($im, TMP .  "files/tmp_Cert2.jpeg", 60);
                imagedestroy($im);
            }

        }

        $fname = TMP . 'certificates' . DS . $cert_uid . '.pdf';

        // $path = TMP . 'files/tmp_Cert.jpg';
        // $type = pathinfo($path, PATHINFO_EXTENSION);
        // $data = file_get_contents($path);
        // $base64 = 'data:image/' . $type . ';base64,' . base64_encode($data);

        $hhtml = "<page><img src=\"" .TMP .  "files/tmp_Cert.jpeg\" style=\"width:90%; position: absolute; left: 0;\"></page>";
        //$hhtml = "<page><img src='". $base64 ."' style='width:90%; position: absolute; left: 0;'></page>";
        if ($cert_count > 1) {
            $hhtml = "<page><img src=\"" . TMP .  "files/tmp_Cert.jpeg\" style=\"width:90%; position: absolute; left: 0;\"></page><page><img src=\"" . TMP .  "files/tmp_Cert2.jpeg\" style=\"width:100%; position: absolute; left: 0;\"></page>";
            //$hhtml = "<page><img src='". $base64 ."' style='width:90%; position: absolute; left: 0;'></page><page><img src='". $base64 ."' style='width:100%; position: absolute; left: 0;'></page>";
        }
        
        $html2pdf = new HTML2PDF('L','A4','en', true, 'UTF-8', array(30, 10, 0, 0));  
        $html2pdf->WriteHTML($hhtml);
        $html2pdf->Output($fname, $display ? 'FI' : 'F'); //,'D'

        return $cert_count;
    }

    public function get_weightloss_receipt() {
        
        $panel = get('l3n4p', '');
        if((empty($panel) || $panel != '609248af7ce858.91s69218')){
            $this->message('Invalid token.');
            return;
        }
        $uid = get('uid','');
        if (empty($uid)) {
            $this->message('Invalid payment identifier.');
            return;
        }

        //data_payment.type
        $this->loadModel('SpaLiveV1.DataPayment');
        $sp = $this->DataPayment->find()->select(['User.name','User.lname','User.street','User.city','User.zip','User.suite','State.abv',
        'DataPayment.type','DataPayment.total','DataPayment.created','DataPayment.id'])->join([
            'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'DataPayment.id_from = User.id'],
            //'DataSubscription' => ['table' => 'data_subscriptions', 'type' => 'INNER', 'conditions' => 'DataSubscription.id = DataPayment.subscription_id'],
            'State' => ['table' => 'cat_states', 'type' => 'INNER', 'conditions' => 'DataPayment.id_from = User.id'],
        ])->where(['DataPayment.uid' => $uid])->first();
        
        if (empty($sp)) {
            return;
        }
        $this->set('sp',$sp);
        
        $address = $sp['User']['street'].(isset($sp['User']['suite']) && !empty($sp['User']['suite']) ? ', '.$sp['User']['suite'] : '') .', '.$sp['User']['city'].', '.$sp['State']['abv'].' '.$sp['User']['zip'];

        
        $this->rcpt_weightloss($sp['type'],$sp['total'],$address,$sp['User']['name'] . ' ' . $sp['User']['lname'],$sp->id,$sp->created->i18nFormat('MM/dd/yyyy hh:mm a'));
        exit;

    }

