    public function validate_step(){        
        $token = get('token','');
        if(!empty($token)){
            $user = $this->AppToken->validateToken($token, true);
            if($user === false){
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
            $this->set('session', true);
        } else {
            $this->message('Invalid token.');
            $this->set('session', false);
            return;
        }
        $this->loadModel("SpaLiveV1.SysUsers");        

        $ent_user = $this->SysUsers->find()->where(['SysUsers.id' => USER_ID])->first();
        
        if($ent_user->spa_work == 1){
            $this->SysUsers->updateAll(
                ['steps' => 'HOME'], 
                ['id' =>  USER_ID]
            );
            $this->set('step', $ent_user->steps);
            $this->success();
            return;
        }

        if($ent_user->steps == 'CODEVERIFICATION' || $ent_user->steps == 'WAITINGSCHOOLAPPROVAL' || $ent_user->steps == 'STATENOTAVAILABLE' || $ent_user->steps == 'TRACERS' || $ent_user->steps == 'DENIED'){
            $this->set('step', $ent_user->steps);
            $this->success();
            return;
        }
        
        $this->loadModel("SpaLiveV1.DataSubscriptions"); 
        $this->loadModel("SpaLiveV1.DataTrainings"); 
        $this->loadModel("SpaLiveV1.CatStates"); 
        $now = date('Y-m-d H:i:s');
        $nowDay = date('Y-m-d');

        $ent_state = $this->CatStates->find()->where(['CatStates.id' => $user['user_state'], 'CatStates.deleted' => 0])->first();
        if ($ent_state->enabled == 0) {
            $this->SysUsers->updateAll(
                ['steps' => 'STATENOTAVAILABLE'], 
                ['id' =>  USER_ID]
            );
            $this->set('step', 'STATENOTAVAILABLE');
            $this->success();
            return;
        }
            
        $this->loadModel("SpaLiveV1.DataPayment");                        

        $ent_subscriptions = $this->DataSubscriptions->find()->where(['DataSubscriptions.user_id' => USER_ID,'DataSubscriptions.deleted' => 0,'DataSubscriptions.status' => 'ACTIVE', 'DataSubscriptions.subscription_type' => 'SUBSCRIPTIONMSL'])->first();
        if(empty($ent_subscriptions)){
            
            $this->SysUsers->updateAll(
                ['steps' => 'MSLSUBSCRIPTION'], 
                ['id' =>  USER_ID]
            );
            $this->success();
            $this->set('step', 'MSLSUBSCRIPTION');
            return;
            
        }else{
            $ent_subscriptions2 = $this->DataSubscriptions->find()->where(['DataSubscriptions.user_id' => USER_ID,'DataSubscriptions.deleted' => 0,'DataSubscriptions.status' => 'ACTIVE', 'DataSubscriptions.subscription_type' => 'SUBSCRIPTIONMD'])->first();
            if(empty($ent_subscriptions2)){
                $this->SysUsers->updateAll(
                    ['steps' => 'MDSUBSCRIPTION'], 
                    ['id' =>  USER_ID]
                );
                $this->success();
                $this->set('step', 'MDSUBSCRIPTION');
                return;
            }
        }
        // Validate W9
        $this->loadModel('SpaLiveV1.DataWN');

        $w9 = $this->DataWN->find()->where(['DataWN.user_id' => USER_ID])->first();
        if(empty($w9)){
            $this->SysUsers->updateAll(
                ['steps' => 'W9'], 
                ['id' =>  USER_ID]
            );
            $this->set('step', 'W9');
            $this->success();
            return;
        }

        // Validate Settings    
        $array_response = array();
        $arr_pro = array();

        if(USER_TYPE == 'patient'){
            $this->success();
            $this->set('step', $ent_user->steps);
            return;
        }
        $model = USER_TYPE == 'gfe+ci' ? 'injector' : USER_TYPE;

        $array_response['radius'] = $ent_user->radius;

        $this->loadModel('SpaLiveV1.DataScheduleModel');
        $lm_entity = $this->DataScheduleModel->find()->where(['DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.deleted' => 0, 'DataScheduleModel.days LIKE' => '%,%', 'DataScheduleModel.model' => $model])->first();

        if (empty($lm_entity)) {
            $str_days = "";
            $int_start = 9;
            $int_end = 15;
        } else {
            $str_days = $lm_entity->days;
            $int_start = $lm_entity->time_start;
            $int_end = $lm_entity->time_end;
        }

        $array_response['days'] = $str_days;
        $array_response['time_start'] = $int_start;
        $array_response['time_end'] = $int_end;

        $skd_days = $this->DataScheduleModel->find()->select(['DataScheduleModel.id', 'DataScheduleModel.days', 'DataScheduleModel.time_end', 'DataScheduleModel.time_start'])
        ->where(['DataScheduleModel.injector_id' => USER_ID, 'DataScheduleModel.deleted' => 0, 'DataScheduleModel.days NOT LIKE' => '%,%', 'DataScheduleModel.model' => $model])->toArray();

        $array_response['days_settings'] = [];
        if(!empty($skd_days)){
            $array_response['days_settings'] = $skd_days;
        }else if(!empty($lm_entity)){
            $days = explode(',', $lm_entity->days);
            foreach($days as $item){
                if(!empty($item)){
                    $array_response['days_settings'][] = [
                        'days' => $item,
                        'time_start' => $lm_entity->time_start,
                        'time_end' => $lm_entity->time_end
                    ];
                }
            }
        }

        $this->loadModel('SpaLiveV1.DataTreatmentsPrice');
        $p_entity = $this->DataTreatmentsPrice->find()->join([
            'CTCI' => ['table' => 'cat_treatments_ci', 'type' => 'INNER', 'conditions' => 'DataTreatmentsPrice.treatment_id = CTCI.id AND CTCI.deleted = 0']
        ])
        ->where(['DataTreatmentsPrice.user_id' => USER_ID, 'DataTreatmentsPrice.deleted' => 0])->all();

        if (!empty($p_entity)) {
            
            foreach ($p_entity as $row) {
                $arr_pro[] = $row->treatment_id . ',' . $row->price;
            }
        }

        if(count($arr_pro) > 0 && count($array_response['days_settings']) > 0){
            $this->SysUsers->updateAll(
                ['steps' => 'HOME'], 
                ['id' =>  USER_ID]
            );
            $this->success();
            $this->set('step', 'HOME');
            return;
        } else {
            $this->SysUsers->updateAll(
                ['steps' => 'TREATMENTSETTINGS'], 
                ['id' =>  USER_ID]
            );
            $this->success();
            $this->set('step', 'TREATMENTSETTINGS');
            return;
        }
        
    }

    public function get_training_cert_os($return_path = false) {
        $this->loadModel('SpaLiveV1.CatTrainigs');
        $this->loadModel('SpaLiveV1.DataCourses');

        $panel = get('l3n4p', '');
        $ftmpname="";
        if(empty($panel) || (!empty($panel) && $panel != '6092482f7ce858.91169218')){

            $token = get('token',"");

            if(!empty($token)){
                $user = $this->AppToken->validateToken($token, true);

                if($user === false){
                    $this->message('Invalid token.');
                    $this->set('session', false);
                    return;
                }
                $this->set('session', true);
            } else {
                $this->message('Invalid token.');
                $this->set('session', false);
                return;
            }
        }

        if (isset($user)) {

            $certItem = $this->DataCourses->find()->select(['User.name','User.mname','User.lname','DataCourses.scheduled','DataCourses.title','DataTrainigs.id'])
            ->join([
                'DataCourses' => ['table' => 'data_trainings', 'type' => 'INNER', 'conditions' => 'DataCourses.id = DataCourses.training_id'],
                'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataCourses.user_id']
            ])->where(['DataCourses.user_id' => USER_ID, 'DataCourses.id' => get('id', 0)])->first();

            if(empty($certItem)){
                $this->message('Course not found.');
                return;
            }

            $name = trim($user['name'].' '.((isset($user['mname']) && !empty($user['mname']) ?$user['mname'] : '' )).' '.$user['lname']);
            $ftmpname= $certItem['DataCourses']['id'];
        } else {

            if (get('cert_id', 0) > 0) {
                $certItem = $this->DataCourses->find()->where(['DataCourses.id' => get('cert_id', 0)])->first();
                $name = '';
            } else {
                
                $certItem = $this->DataCourses->find()->select(['User.name','User.mname','User.lname','CC.title','DataCourses.id','DSR.nameschool'])
                ->join([
                    'CC' => ['table' => 'cat_courses', 'type' => 'INNER', 'conditions' => 'CC.id = DataCourses.course_id'],
                    'DSR' => ['table' => 'data_school_register', 'type' => 'INNER', 'conditions' => 'DSR.id = CC.school_id'],
                    'User' => ['table' => 'sys_users', 'type' => 'INNER', 'conditions' => 'User.id = DataCourses.user_id']
                ])
                ->where(['User.uid' => get('user_uid', ''), 'DataCourses.course_id' => get('id', 0), 'DataCourses.status' => 'DONE'])->first();
                if(empty($certItem)){
                    $this->message('Course not found.');
                    return;
                }
                $name = trim($certItem['User']['name'].' '.((isset($certItem['User']['mname']) && !empty($certItem['User']['mname']) ?$certItem['User']['mname'] : '' )).' '.$certItem['User']['lname']);
                $ftmpname= $certItem['id'];
            }

            if(empty($certItem)){
                $this->message('Course not found.');
                return;
            }

            
        }
        
        //$dates = $certItem['scheduled']->i18nFormat('MM/dd/yyyy');
        
        $type_space = imagettfbbox(125, 0, './font/AlexBrush-Regular.ttf', $name);
        $text_width = abs($type_space[4] - $type_space[0]) + 10;
        
        $im   = imagecreatefrompng(TMP . "files/Certificate_of_Coverage_and_Completion_With_MD.png");
        $gray = imagecolorallocate($im, 30, 30, 30);
        $px   = (imagesx($im) - $text_width) / 2;
        imagettftext($im, 125, 0, (int)$px, 1400, $gray, './font/AlexBrush-Regular.ttf', $name);

        $cert_title = ' '.$certItem['CC']['title'];//.' on '.$dates;
        if (strlen($cert_title) > 39) {
            $tmp_title = wordwrap($cert_title, 39, "\n");
            $arr_strings = $arr_tttrr = explode("\n",$tmp_title);
            $cert_title = $arr_tttrr[0];
            $cert_title2 = $arr_tttrr[1];
            
            $type_spaceTr = imagettfbbox(40, 0, './font/Garet-Book.ttf', $cert_title);
            $text_widthTr = abs($type_spaceTr[4] - $type_spaceTr[0]) + 0;
            //print_r($text_widthTr);exit;//835 = 585
            $pxTr = (450 + ((1105-$text_widthTr)/2));
            imagettftext($im, 40, 0, (int)$pxTr, 1730, $gray, './font/Garet-Book.ttf', $cert_title);

            $type_spaceTr2 = imagettfbbox(40, 0, './font/Garet-Book.ttf', $cert_title2);
            $text_widthTr2 = abs($type_spaceTr2[4] - $type_spaceTr2[0]) + 10;
            //print_r($text_widthTr2);exit;//1106
            $pxTr = (450 + ((1105 - $text_widthTr2)/2)) ;
            imagettftext($im, 40, 0, (int)$pxTr, 1780, $gray, './font/Garet-Book.ttf', $cert_title2);
        } else {//startx =  450 endx = 1500 = 1050 text_widthTr = 1115  
            $type_spaceTr = imagettfbbox(40, 0, './font/Garet-Book.ttf', $cert_title);
            $text_widthTr = abs($type_spaceTr[4] - $type_spaceTr[0]) + 0;            
            $pxTr = (450 +((1105 - $text_widthTr)/2) ) ; //$pxTr = (1545 - $text_widthTr) ; 
            imagettftext($im, 40, 0, (int)$pxTr, 1780, $gray, './font/Garet-Book.ttf', $cert_title);
        }
        $nameschool = ' '.$certItem['DSR']['nameschool'];
