    function detectar_orientacion_imagen($imagen_path) {
        $imagen_info  = getimagesizefromstring($imagen_path);

         

        //$imagen_info = getimagesize($imagen_path);
        $ancho = $imagen_info[0];
        $alto = $imagen_info[1];
        
        
        if ($ancho > $alto) {
            return 'horizontal';
        } elseif ($ancho < $alto) {
            return 'vertical';
        } else {
            return 'cuadrada';
        }
    }

